function t(key) { return (T[APP.lang] && T[APP.lang][key]) || (T.en[key]) || key; }
function applyLangDir() { document.body.dir = APP.lang === 'ar' ? 'rtl' : 'ltr'; document.documentElement.lang = APP.lang; }
function setLang(lang) { APP.lang = lang; localStorage.setItem('rb_lang', lang); applyLangDir(); renderHeader(); checkUrlRouting(); }



function setAccentColor(color, hover) {
  document.documentElement.style.setProperty('--accent', color);
  document.documentElement.style.setProperty('--accent-hover', hover || color);
  localStorage.setItem('rb_accent', color);
  localStorage.setItem('rb_accent_hover', hover || color);
}
function loadAccentColor() {
  const c = localStorage.getItem('rb_accent');
  const h = localStorage.getItem('rb_accent_hover');
  if (c) { document.documentElement.style.setProperty('--accent', c); document.documentElement.style.setProperty('--accent-hover', h || c); }
}

async function exportAppData() {
  const data = { version: 1, exportedAt: Date.now(), settings: APP.settings, folders: APP.folders.filter(f=>!f.system), files: APP.files.map(f => ({id:f.id,name:f.name,size:f.size,mime:f.mime,folderId:f.folderId,uploadedAt:f.uploadedAt,caption:f.caption,tag:f.tag,starred:f.starred,version:f.version,encrypted:f.encrypted})), shares: APP.shares };
  const blob = new Blob([JSON.stringify(data,null,2)], {type:'application/json'});
  const d = new Date().toISOString().slice(0,10);
  const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = `ridgebox-backup-${d}.json`; a.click();
  showToast(t('save'), 'success');
}

async function importAppData(jsonFile) {
  try {
    const text = await jsonFile.text();
    const data = JSON.parse(text);
    if (!data.version || !data.files) { showToast('Invalid backup file', 'error'); return; }
    const fileCount = (data.files||[]).length;
    const folderCount = (data.folders||[]).length;
    const settingCount = Object.keys(data.settings||{}).length;
    const isId = APP.lang === 'id';
    showConfirm(
      isId ? 'Impor Data?' : 'Import Data?',
      isId ? `Ini akan menggabungkan ${fileCount} file, ${folderCount} folder, ${settingCount} pengaturan. Lanjutkan?` : `This will merge ${fileCount} files, ${folderCount} folders, ${settingCount} settings. Continue?`,
      async () => {
        let added = 0;
        for (const f of (data.files||[])) { if (!APP.files.find(ef => ef.id === f.id)) { APP.files.push(f); await saveFile(f); added++; } }
        for (const fo of (data.folders||[])) { if (!APP.folders.find(ef => ef.id === fo.id)) { APP.folders.push(fo); await saveFolder(fo); } }
        if (data.settings) { for (const [k,v] of Object.entries(data.settings)) { APP.settings[k] = v; await saveSetting(k, v); } }
        if (data.shares) { for (const s of data.shares) { if (!APP.shares.find(es => es.id === s.id)) { APP.shares.push(s); await saveShare(s); } } }
        showToast(isId ? `${added} file diimpor` : `${added} files imported`, 'success');
        await refreshUI();
      }
    );
  } catch(e) { showToast('Import failed: ' + e.message, 'error'); }
}

async function setupBiometric() {
  if (!window.PublicKeyCredential) { showToast(APP.lang==='id'?'Browser tidak mendukung WebAuthn':'Browser does not support WebAuthn', 'error'); return; }
  try {
    const avail = await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable();
    if (!avail) { showToast(APP.lang==='id'?'Tidak ada autentikator biometrik':'No biometric authenticator available', 'error'); return; }
    const challenge = new Uint8Array(32); crypto.getRandomValues(challenge);
    const cred = await navigator.credentials.create({ publicKey: { challenge, rp: { name: 'Ridgebox' }, user: { id: new Uint8Array(16), name: 'ridgebox-user', displayName: 'Ridgebox User' }, pubKeyCredParams: [{type:'public-key',alg:-7},{type:'public-key',alg:-257}], authenticatorSelection: { authenticatorAttachment: 'platform', userVerification: 'required' }, timeout: 60000 } });
    localStorage.setItem('rb_biometric_id', btoa(String.fromCharCode(...new Uint8Array(cred.rawId))));
    showToast(APP.lang==='id'?'Biometrik terdaftar':'Biometric registered', 'success');
    openSettings();
  } catch(e) { if (e.name !== 'NotAllowedError') showToast('Error: ' + e.message, 'error'); }
}

async function verifyBiometric() {
  const storedId = localStorage.getItem('rb_biometric_id');
  if (!storedId || !window.PublicKeyCredential) return false;
  try {
    const rawId = Uint8Array.from(atob(storedId), c => c.charCodeAt(0));
    const challenge = new Uint8Array(32); crypto.getRandomValues(challenge);
    await navigator.credentials.get({ publicKey: { challenge, allowCredentials: [{ type: 'public-key', id: rawId }], userVerification: 'required', timeout: 60000 } });
    return true;
  } catch(e) { return false; }
}

function removeBiometric() { localStorage.removeItem('rb_biometric_id'); showToast(APP.lang==='id'?'Biometrik dihapus':'Biometric removed', 'info'); openSettings(); }

async function saveFileDescription(fileId, description) {
  const file = APP.files.find(f => f.id === fileId);
  if (!file) return;
  file.caption = description;
  await saveFile(file);
  const indicator = document.getElementById('desc-saved-indicator');
  if (indicator) { indicator.style.opacity = '1'; setTimeout(() => { indicator.style.opacity = '0'; }, 1500); }
}

function startEditDescription(fileId) {
  const el = document.getElementById('detail-desc-' + fileId);
  if (!el) return;
  const file = APP.files.find(f => f.id === fileId);
  if (!file) return;
  const oldVal = file.caption || '';
  const ta = document.createElement('textarea');
  ta.id = 'detail-desc-' + fileId;
  ta.value = oldVal;
  ta.style.cssText = 'width:100%;min-height:48px;padding:6px 8px;border:1px solid var(--accent);border-radius:6px;background:var(--bg);color:var(--text);font-size:12px;font-family:inherit;resize:vertical';
  ta.placeholder = t('addCaption');
  let saved = false;
  ta.onblur = function() {
    if (saved) return; saved = true;
    saveFileDescription(fileId, ta.value);
    const p = document.createElement('p');
    p.id = 'detail-desc-' + fileId;
    p.style.cssText = 'font-size:12px;color:var(--text-secondary);margin-top:4px;cursor:pointer;display:flex;align-items:center;gap:6px';
    p.innerHTML = ta.value ? `${ta.value} <i class="fas fa-pen" style="font-size:10px;opacity:.5"></i>` : `<span style="font-style:italic;opacity:.6">${t('addCaption')} <i class="fas fa-pen" style="font-size:10px;opacity:.5"></i></span>`;
    p.onclick = () => startEditDescription(fileId);
    ta.replaceWith(p);
  };
  ta.onkeydown = function(e) { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); ta.blur(); } if (e.key === 'Escape') { ta.value = oldVal; ta.blur(); } };
  el.replaceWith(ta);
  ta.focus();
}

// ===== INDEXEDDB (F15) =====
const DB_NAME = 'RidgeboxDB';
const DB_VERSION = 8;
let _db = null;

function openDB() {
    return new Promise((resolve, reject) => {
        if (_db && !_db.closed) return resolve(_db);
        _db = null; // Reset if closed
        const req = indexedDB.open(DB_NAME, DB_VERSION);
        req.onupgradeneeded = (e) => {
            const db = e.target.result;
            if (!db.objectStoreNames.contains('files')) {
                const fs = db.createObjectStore('files', { keyPath: 'id' });
                fs.createIndex('folderId', 'folderId', { unique: false });
                fs.createIndex('name', 'name', { unique: false });
                fs.createIndex('trashed', 'trashed', { unique: false });
                fs.createIndex('starred', 'starred', { unique: false });
            }
            if (!db.objectStoreNames.contains('folders')) db.createObjectStore('folders', { keyPath: 'id' });
            if (!db.objectStoreNames.contains('shares')) db.createObjectStore('shares', { keyPath: 'id' });
            if (!db.objectStoreNames.contains('settings')) db.createObjectStore('settings', { keyPath: 'key' });
            if (!db.objectStoreNames.contains('thumbnails')) db.createObjectStore('thumbnails', { keyPath: 'fileId' });
            if (!db.objectStoreNames.contains('gdrive_accounts')) {
                const ga = db.createObjectStore('gdrive_accounts', { keyPath: 'id' });
                ga.createIndex('email', 'email', { unique: false });
                ga.createIndex('status', 'status', { unique: false });
            }
            if (!db.objectStoreNames.contains('s3_accounts')) {
                const sa = db.createObjectStore('s3_accounts', { keyPath: 'id' });
                sa.createIndex('providerId', 'providerId', { unique: false });
                sa.createIndex('status', 'status', { unique: false });
            }
            if (!db.objectStoreNames.contains('onedrive_accounts')) {
                const oa = db.createObjectStore('onedrive_accounts', { keyPath: 'id' });
                oa.createIndex('email', 'email', { unique: false });
                oa.createIndex('status', 'status', { unique: false });
            }
            if (!db.objectStoreNames.contains('dropbox_accounts')) {
                const da = db.createObjectStore('dropbox_accounts', { keyPath: 'id' });
                da.createIndex('email', 'email', { unique: false });
                da.createIndex('status', 'status', { unique: false });
            }
            if (!db.objectStoreNames.contains('backup_config')) {
                db.createObjectStore('backup_config', { keyPath: 'id' });
            }
            if (!db.objectStoreNames.contains('comments')) {
                const co = db.createObjectStore('comments', { keyPath: 'id' });
                co.createIndex('fileId', 'fileId', { unique: false });
                co.createIndex('createdAt', 'createdAt', { unique: false });
            }
            if (!db.objectStoreNames.contains('sessions')) {
                const ss = db.createObjectStore('sessions', { keyPath: 'id' });
                ss.createIndex('current', 'current', { unique: false });
                ss.createIndex('createdAt', 'createdAt', { unique: false });
            }
            if (!db.objectStoreNames.contains('activity_log')) {
                const al = db.createObjectStore('activity_log', { keyPath: 'id' });
                al.createIndex('type', 'type', { unique: false });
                al.createIndex('timestamp', 'timestamp', { unique: false });
            }
        };
        req.onsuccess = (e) => { _db = e.target.result; resolve(_db); };
        req.onerror = (e) => reject(e.target.error);
    });
}

async function dbGetAll(store) {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(store, 'readonly');
        const req = tx.objectStore(store).getAll();
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
    });
}

async function dbGet(store, key) {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(store, 'readonly');
        const req = tx.objectStore(store).get(key);
        req.onsuccess = () => resolve(req.result);
        req.onerror = () => reject(req.error);
    });
}

async function dbPut(store, data) {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(store, 'readwrite');
        tx.objectStore(store).put(data);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
        tx.onabort = () => reject(tx.error || new Error('Transaction aborted'));
    });
}

async function dbDelete(store, key) {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(store, 'readwrite');
        tx.objectStore(store).delete(key);
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

async function dbClear(store) {
    const db = await openDB();
    return new Promise((resolve, reject) => {
        const tx = db.transaction(store, 'readwrite');
        tx.objectStore(store).clear();
        tx.oncomplete = () => resolve();
        tx.onerror = () => reject(tx.error);
    });
}

async function loadAllData() {
    try {
        APP.files = await dbGetAll('files');
        const customFolders = await dbGetAll('folders');
        APP.folders = [
            { id: 'all', name: t('allFiles'), icon: 'fa-folder', system: true },
            { id: 'recent', name: t('recent'), icon: 'fa-clock', system: true },
            { id: 'favorites', name: t('favorites'), icon: 'fa-star', system: true },
            { id: 'trash', name: t('trash'), icon: 'fa-trash-alt', system: true },
            ...customFolders
        ];
        APP.shares = await dbGetAll('shares');
        const settings = await dbGetAll('settings');
        settings.forEach(s => { APP.settings[s.key] = s.value; });
        APP.gdriveAccounts = await dbGetAll('gdrive_accounts');
        APP.s3Accounts = await dbGetAll('s3_accounts');
        APP.onedriveAccounts = await dbGetAll('onedrive_accounts');
        APP.dropboxAccounts = await dbGetAll('dropbox_accounts');
        // Load OneDrive/Dropbox config from settings
        const odCfg = await dbGet('settings', 'onedrive_config');
        if (odCfg) APP.onedriveConfig = odCfg.value;
        const dbCfg = await dbGet('settings', 'dropbox_config');
        if (dbCfg) APP.dropboxConfig = dbCfg.value;
        // Load backup config
        const bkCfg = await dbGet('settings', 'backup_config');
        if (bkCfg) APP.backupConfig = { ...APP.backupConfig, ...bkCfg.value };
    } catch(e) { console.error('Load data error:', e); }
}

async function saveFile(file) { await dbPut('files', file); }
async function deleteFileDB(id) { await dbDelete('files', id); }
async function saveFolder(folder) { await dbPut('folders', folder); }
async function deleteFolderDB(id) { await dbDelete('folders', id); }
async function saveShare(share) { await dbPut('shares', share); }
async function deleteShareDB(id) { await dbDelete('shares', id); }
async function saveSetting(key, value) { await dbPut('settings', { key, value }); }

// ===== FEATURE 1: AUTO-LOCK (IDLE TIMER) =====
function initAutoLock() {
    if (APP.autoLockTimer) clearTimeout(APP.autoLockTimer);
    if (APP.autoLockCountdown) clearInterval(APP.autoLockCountdown);
    const mins = APP.settings.autoLockMinutes;
    if (!mins || mins <= 0 || !APP.settings.pinLock) { updateAutoLockDisplay(-1); return; }
    let remaining = mins * 60 * 1000;
    function startCountdown() {
        if (APP.autoLockCountdown) clearInterval(APP.autoLockCountdown);
        const startT = Date.now();
        APP.autoLockCountdown = setInterval(() => {
            const elapsed = Date.now() - startT;
            const left = Math.max(0, remaining - elapsed);
            updateAutoLockDisplay(left);
            if (left <= 0) clearInterval(APP.autoLockCountdown);
        }, 1000);
    }
    function resetTimer() {
        if (APP.autoLockTimer) clearTimeout(APP.autoLockTimer);
        if (APP.autoLockCountdown) clearInterval(APP.autoLockCountdown);
        remaining = mins * 60 * 1000;
        APP.autoLockTimer = setTimeout(() => { showLockScreen(); }, remaining);
        startCountdown();
    }
    ['mousemove','keydown','touchstart','scroll','click'].forEach(e => document.removeEventListener(e, resetTimer));
    ['mousemove','keydown','touchstart','scroll','click'].forEach(e => document.addEventListener(e, resetTimer, {passive:true}));
    resetTimer();
}
function updateAutoLockDisplay(ms) {
    const el = document.getElementById('auto-lock-countdown');
    if (!el) return;
    if (ms < 0) { el.style.display='none'; return; }
    el.style.display='flex';
    const sec = Math.ceil(ms/1000);
    const m = Math.floor(sec/60), s = sec%60;
    el.innerHTML = `<i class="fas fa-lock" style="font-size:9px"></i> ${t('autoLockIn')} ${m}:${s.toString().padStart(2,'0')}`;
}

