async function saveFileNote(fileId, noteText) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    file.notes = noteText;
    await saveFile(file);
}

// ===== Feature 7: File Comments/Notes =====
async function getComments(fileId) {
    try {
        const all = await dbGetAll('comments');
        return all.filter(c => c.fileId === fileId).sort((a, b) => a.createdAt - b.createdAt);
    } catch(e) { return []; }
}

async function addComment(fileId, text) {
    const isId = APP.lang === 'id';
    if (!text || !text.trim()) return;
    if (text.length > 500) { showToast(isId ? 'Komentar maksimal 500 karakter' : 'Comment max 500 characters', 'warning'); return; }
    const author = APP.user?.email || (isId ? 'Anda' : 'You');
    const comment = {
        id: genId(),
        fileId: fileId,
        author: author,
        text: text.trim(),
        createdAt: Date.now()
    };
    await dbPut('comments', comment);
    // Re-render comments section
    const container = document.getElementById('comments-container-' + fileId);
    if (container) {
        const comments = await getComments(fileId);
        container.innerHTML = renderCommentsListHTML(fileId, comments);
    }
    updateCommentBadge(fileId);
}

async function deleteComment(fileId, commentId) {
    await dbDelete('comments', commentId);
    const container = document.getElementById('comments-container-' + fileId);
    if (container) {
        const comments = await getComments(fileId);
        container.innerHTML = renderCommentsListHTML(fileId, comments);
    }
    updateCommentBadge(fileId);
}

