async function updateCommentBadge(fileId) {
    try {
        const comments = await getComments(fileId);
        const badge = document.getElementById('detail-comment-badge');
        const countEl = document.getElementById('comment-count-' + fileId);
        if (badge && comments.length > 0) {
            badge.style.display = 'inline';
            badge.textContent = comments.length;
        } else if (badge) {
            badge.style.display = 'none';
        }
        if (countEl) {
            countEl.textContent = comments.length;
            countEl.style.display = comments.length > 0 ? 'inline' : 'none';
        }
        // Also load comments if container exists
        const container = document.getElementById('comments-container-' + fileId);
        if (container && container.querySelector('[style*="animation:spin"]')) {
            container.innerHTML = renderCommentsListHTML(fileId, comments);
        }
    } catch(e) {}
}

function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

// ===== Feature 8: File Integrity Check (SHA-256) =====
async function computeFileHash(arrayBuffer) {
    try {
        const hashBuffer = await crypto.subtle.digest('SHA-256', arrayBuffer);
        const hashArray = Array.from(new Uint8Array(hashBuffer));
        return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
    } catch(e) {
        console.warn('SHA-256 computation failed:', e);
        return null;
    }
}

function renderFileHashSection(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return '';
    const isId = APP.lang === 'id';
    const hash = file.fileHash || null;
    const verified = file._integrityVerified || false;
    const hashDisplay = hash ? hash.substring(0, 16) + '...' : (isId ? 'Belum dihitung' : 'Not computed');
    const largeFileWarning = file.size > 50 * 1024 * 1024 ? `<div style="font-size:11px;color:#f59e0b;margin-top:4px"><i class="fas fa-exclamation-triangle" style="margin-right:3px"></i>${isId ? 'File besar, verifikasi mungkin memakan waktu' : 'Large file, verification may take time'}</div>` : '';
    return `<div style="margin-top:16px;padding:12px;background:var(--bg-secondary);border-radius:10px">
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">
            <i class="fas fa-shield-halved" style="font-size:12px;color:${verified ? '#10b981' : 'var(--accent)'}"></i>
            <span style="font-size:13px;font-weight:600">${isId ? 'Integritas File' : 'File Integrity'}</span>
            ${verified ? '<span style="font-size:10px;color:#10b981;font-weight:600"><i class="fas fa-check-circle" style="margin-right:2px"></i>' + (isId ? 'Terverifikasi' : 'Verified') + '</span>' : ''}
        </div>
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px">
            <span style="font-size:11px;color:var(--text-secondary);font-family:'JetBrains Mono',monospace;flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${hash || ''}">SHA-256: ${hashDisplay}</span>
            ${hash ? `<button onclick="copyToClipboard('${hash}')" style="background:none;border:none;cursor:pointer;color:var(--accent);font-size:12px;padding:2px 6px;border-radius:4px;transition:background .15s" onmouseover="this.style.background='rgba(59,130,246,.1)'" onmouseout="this.style.background='none'" title="${isId ? 'Salin hash' : 'Copy hash'}" aria-label="Copy hash"><i class="fas fa-copy"></i></button>` : ''}
        </div>
        ${largeFileWarning}
        <button class="btn btn-secondary btn-sm" style="margin-top:6px;width:100%" onclick="verifyFileIntegrity('${fileId}')"><i class="fas fa-shield-halved"></i> ${isId ? 'Verifikasi Integritas' : 'Verify Integrity'}</button>
    </div>`;
}

async function verifyFileIntegrity(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    const isId = APP.lang === 'id';
    
    if (!file.fileHash) {
        showToast(isId ? 'Hash file belum tersedia. Hash dihitung saat upload.' : 'File hash not available. Hash is computed on upload.', 'warning');
        return;
    }
    
    showToast(isId ? 'Memverifikasi integritas file...' : 'Verifying file integrity...', 'info', 5000);
    
    try {
        let url;
        if (file.storageProvider === 'gdrive' && file.driveFileId) {
            const account = APP.gdriveAccounts.find(a => a.id === file.providerAccountId && a.status === 'connected') || APP.gdriveAccounts.find(a => a.status === 'connected');
            if (account) {
                const accessToken = await APP.storageProviders.gdrive.getAccessToken(account.id);
                url = `/api/gdrive/download?accessToken=${encodeURIComponent(accessToken)}&fileId=${encodeURIComponent(file.driveFileId)}`;
            }
        } else if (file.storageProvider === 's3' && file.driveFileId) {
            const account = APP.s3Accounts.find(a => a.id === file.providerAccountId);
            if (account) {
                const provider = account.type === 's3' ? APP.storageProviders.s3 : APP.storageProviders.token;
                if (provider) {
                    const dlResult = await provider.download(account.id, file.driveFileId);
                    if (typeof dlResult === 'string') url = dlResult;
                }
            }
        }
        if (!url) {
            url = APP.settings.proxyMode !== false
                ? `/api/download?path=${encodeURIComponent(file.filePath)}&bot_index=${file.botIndex}`
                : `https://api.telegram.org/file/bot${APP.bots[0]?.token}/${file.filePath}`;
        }
        
        const resp = await fetch(url);
        if (!resp.ok) throw new Error('Download failed');
        const blob = await resp.blob();
        const arrayBuffer = await blob.arrayBuffer();
        
        // If encrypted, decrypt first
        let dataToHash = arrayBuffer;
        if (file.encrypted) {
            try {
                const encData = new Uint8Array(arrayBuffer);
                const decData = await decryptData(encData, 'ridgebox_' + file.chatId);
                dataToHash = decData.buffer;
            } catch(e) {
                console.warn('Decrypt failed for integrity check, hashing raw data');
            }
        }
        
        const currentHash = await computeFileHash(dataToHash);
        
        if (currentHash === file.fileHash) {
            file._integrityVerified = true;
            showToast(isId ? 'Integritas file terverifikasi ✓' : 'File integrity verified ✓', 'success');
            // Re-render detail panel
            openDetailPanel(fileId);
        } else {
            file._integrityVerified = false;
            showToast(isId ? '⚠ Pemeriksaan integritas file gagal! File mungkin rusak' : '⚠ File integrity check failed! File may be corrupted', 'error', 6000);
        }
    } catch(e) {
        showToast(isId ? 'Gagal memverifikasi: ' : 'Verification failed: ' + e.message, 'error');
    }
}

function copyToClipboard(text) {
    navigator.clipboard.writeText(text).then(() => {
        showToast(APP.lang === 'id' ? 'Disalin ke clipboard' : 'Copied to clipboard', 'success');
    }).catch(() => {
        // Fallback
        const ta = document.createElement('textarea');
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        ta.remove();
        showToast(APP.lang === 'id' ? 'Disalin ke clipboard' : 'Copied to clipboard', 'success');
    });
}
function renderNotesSection(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    const note = file?.notes || '';
    return `<div style="margin-top:16px;padding:12px;background:var(--bg-secondary);border-radius:10px">
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">
            <i class="fas fa-sticky-note" style="font-size:12px;color:var(--accent)"></i>
            <span style="font-size:13px;font-weight:600">${t('notes')}</span>
        </div>
        <textarea id="file-note-input" aria-label="Notes" style="width:100%;min-height:60px;padding:8px;border:1px solid var(--border);border-radius:8px;background:var(--bg);color:var(--text);font-size:12px;resize:vertical;font-family:inherit" placeholder="${t('addNotes')}" onblur="saveFileNote('${fileId}',this.value)" onkeydown="if(event.ctrlKey&&event.key==='Enter'){this.blur()}">${note}</textarea>
    </div>`;
}

// ===== FEATURE 3: BULK RENAME =====
function openBulkRenameModal() {
    if (APP.selectedFiles.size === 0) return;
    const isId = APP.lang === 'id';
    const ids = [...APP.selectedFiles];
    const files = ids.map(id => APP.files.find(f => f.id === id)).filter(Boolean);
    const previewFiles = files.slice(0, 3);
    openModal(`<div style="padding:24px">
        <h3 style="font-size:18px;font-weight:600;margin-bottom:16px"><i class="fas fa-i-cursor" style="color:var(--accent)"></i> ${t('bulkRename')}</h3>
        <p style="font-size:12px;color:var(--text-secondary);margin-bottom:12px">${files.length} ${isId?'file dipilih':'files selected'}</p>
        <div style="margin-bottom:12px">
            <label style="font-size:13px;font-weight:500;display:block;margin-bottom:4px">${t('prefix')}</label>
            <input type="text" id="rename-prefix" class="input" aria-label="Prefix" style="width:100%" oninput="updateBulkRenamePreview()">
        </div>
        <div style="margin-bottom:12px">
            <label style="font-size:13px;font-weight:500;display:block;margin-bottom:4px">${t('suffix')}</label>
            <input type="text" id="rename-suffix" class="input" aria-label="Suffix" style="width:100%" oninput="updateBulkRenamePreview()">
        </div>
        <div style="margin-bottom:12px">
            <label style="font-size:13px;font-weight:500;display:block;margin-bottom:4px">${t('pattern')} ({name}, {index}, {date})</label>
            <input type="text" id="rename-pattern" class="input" aria-label="Pattern" style="width:100%" placeholder="{name}" oninput="updateBulkRenamePreview()">
        </div>
        <div style="margin-bottom:16px;padding:10px;background:var(--bg-secondary);border-radius:8px">
            <div style="font-size:12px;font-weight:600;margin-bottom:6px">${t('preview')}</div>
            <div id="bulk-rename-preview" style="font-size:11px;color:var(--text-secondary)"></div>
        </div>
        <div style="display:flex;gap:8px;justify-content:flex-end">
            <button class="btn btn-secondary" onclick="closeModal()">${t('cancel')}</button>
            <button class="btn btn-primary" onclick="applyBulkRename()">${isId?'Terapkan':'Apply'}</button>
        </div>
    </div>`);
    updateBulkRenamePreview();
}
function applyBulkRenamePattern(name, pattern, prefix, suffix, index) {
    const ext = name.includes('.') ? '.' + name.split('.').pop() : '';
    const baseName = name.includes('.') ? name.slice(0, name.lastIndexOf('.')) : name;
    let result = pattern || '{name}';
    result = result.replace('{name}', baseName).replace('{index}', String(index + 1).padStart(2, '0')).replace('{date}', new Date().toISOString().slice(0, 10));
    result = (prefix || '') + result + (suffix || '');
    if (ext) result += ext;
    return result;
}
function updateBulkRenamePreview() {
    const prefix = document.getElementById('rename-prefix')?.value || '';
    const suffix = document.getElementById('rename-suffix')?.value || '';
    const pattern = document.getElementById('rename-pattern')?.value || '';
    const ids = [...APP.selectedFiles];
    const files = ids.map(id => APP.files.find(f => f.id === id)).filter(Boolean);
    const preview = files.slice(0, 3);
    const el = document.getElementById('bulk-rename-preview');
    if (!el) return;
    el.innerHTML = preview.map((f, i) => {
        const newName = applyBulkRenamePattern(f.name, pattern, prefix, suffix, i);
        return `<div style="margin-bottom:4px">${f.name} → <strong style="color:var(--accent)">${newName}</strong></div>`;
    }).join('') + (files.length > 3 ? `<div>... +${files.length - 3} ${APP.lang==='id'?'lainnya':'more'}</div>` : '');
}
async function applyBulkRename() {
    const prefix = document.getElementById('rename-prefix')?.value || '';
    const suffix = document.getElementById('rename-suffix')?.value || '';
    const pattern = document.getElementById('rename-pattern')?.value || '';
    const ids = [...APP.selectedFiles];
    await bulkRename(ids, pattern, prefix, suffix);
}
async function bulkRename(fileIds, pattern, prefix, suffix) {
    let count = 0;
    for (let i = 0; i < fileIds.length; i++) {
        const file = APP.files.find(f => f.id === fileIds[i]);
        if (!file) continue;
        file.name = applyBulkRenamePattern(file.name, pattern, prefix, suffix, i);
        await saveFile(file);
        count++;
    }
    closeModal();
    showToast(`${count} ${APP.lang==='id'?'file diganti nama':'files renamed'}`, 'success');
    renderFileList();
}

// ===== FEATURE 4: RESUME UPLOAD (CHUNKED UPLOAD) =====
async function executeChunkedUpload(file, folderParam) {
    const CHUNK = 5 * 1024 * 1024;
    const totalChunks = Math.ceil(file.size / CHUNK);
    const uploadId = genId();
    const progress = { id: uploadId, fileName: file.name, totalChunks, uploadedChunks: 0, size: file.size, folderParam: folderParam || APP.currentFolder, startedAt: Date.now() };
    await saveSetting('pendingUpload_' + uploadId, progress);
    try {
        for (let i = 0; i < totalChunks; i++) {
            const start = i * CHUNK;
            const end = Math.min(start + CHUNK, file.size);
            const chunk = file.slice(start, end);
            const bot = APP.bots[0];
            if (!bot) throw new Error('No bot');
            const formData = new FormData();
            formData.append('document', chunk, `${file.name}.part${i}`);
            formData.append('bot_index', bot.index);
            formData.append('chat_id', bot.chatId);
            const resp = await fetch('/api/upload', { method: 'POST', body: formData });
            const result = await resp.json();
            if (!result.ok && !(result.result && result.result.message_id)) throw new Error('Chunk upload failed');
            progress.uploadedChunks = i + 1;
            await saveSetting('pendingUpload_' + uploadId, progress);
            const pct = Math.round(((i + 1) / totalChunks) * 100);
            updateUploadPreviewProgress(file.name, pct);
        }
        await saveSetting('pendingUpload_' + uploadId, null);
        await dbDelete('settings', 'pendingUpload_' + uploadId);
    } catch (e) {
        showToast(t('retryingUpload'), 'warning');
        throw e;
    }
}
async function checkPendingUploads() {
    try {
        const allSettings = await dbGetAll('settings');
        const pending = allSettings.filter(s => s.key && s.key.startsWith('pendingUpload_') && s.value);
        if (pending.length === 0) return;
        showToast(`${t('resumeUpload')} ${pending.length} ${APP.lang==='id'?'unggahan':'upload(s)'}`, 'info', 6000);
    } catch(e) {}
}

