// ===== FEATURE 6: THUMBNAIL CACHE =====
async function getThumbnail(fileId, fileUrl) {
    try {
        const cached = await dbGet('thumbnails', fileId);
        if (cached && cached.dataUrl && (Date.now() - cached.cachedAt < 7 * 86400000)) return cached.dataUrl;
    } catch(e) {}
    if (!fileUrl) return null;
    try {
        const dataUrl = await new Promise((resolve, reject) => {
            const img = new Image();
            img.crossOrigin = 'anonymous';
            img.onload = () => {
                const c = document.createElement('canvas');
                c.width = 64; c.height = 64;
                const ctx = c.getContext('2d');
                const ratio = Math.min(64/img.width, 64/img.height);
                const w = img.width * ratio, h = img.height * ratio;
                ctx.drawImage(img, (64-w)/2, (64-h)/2, w, h);
                resolve(c.toDataURL('image/jpeg', 0.7));
            };
            img.onerror = () => reject('img err');
            img.src = fileUrl;
        });
        await dbPut('thumbnails', { fileId, dataUrl, cachedAt: Date.now() });
        return dataUrl;
    } catch(e) { return null; }
}
async function clearOldThumbnails() {
    try {
        const all = await dbGetAll('thumbnails');
        const cutoff = Date.now() - 7 * 86400000;
        for (const t of all) {
            if (t.cachedAt < cutoff) await dbDelete('thumbnails', t.fileId);
        }
    } catch(e) {}
}
async function loadThumbnailsForVisibleFiles(files) {
    // Use IntersectionObserver for lazy loading image thumbnails
    const lazyElements = document.querySelectorAll('[data-lazy-thumb]');
    if (lazyElements.length === 0) return;

    if (window._thumbObserver) window._thumbObserver.disconnect();

    window._thumbObserver = new IntersectionObserver((entries) => {
        entries.forEach(async (entry) => {
            if (!entry.isIntersecting) return;
            const el = entry.target;
            const thumbUrl = el.getAttribute('data-lazy-thumb');
            const fileId = el.getAttribute('data-file-id');
            if (!thumbUrl || el._thumbLoaded) return;
            el._thumbLoaded = true;
            window._thumbObserver.unobserve(el);

            // Try cached thumbnail first
            try {
                const cached = await dbGet('thumbnails', fileId);
                if (cached && cached.dataUrl && (Date.now() - cached.cachedAt < 7 * 86400000)) {
                    applyThumbToElement(el, cached.dataUrl);
                    return;
                }
            } catch(e) {}

            // Load the image directly as background (for grid cards)
            const img = el.querySelector('img.file-thumb-placeholder-img');
            if (img) {
                img.src = thumbUrl;
            } else {
                // For list thumbnails, set background-image
                const thumbDiv = el.querySelector('img') || el;
                if (thumbDiv.tagName === 'IMG') {
                    thumbDiv.src = thumbUrl;
                } else {
                    el.style.backgroundImage = `url(${thumbUrl})`;
                    el.style.backgroundSize = 'cover';
                    el.style.backgroundPosition = 'center';
                }
            }
        });
    }, { rootMargin: '200px', threshold: 0.01 });

    lazyElements.forEach(el => window._thumbObserver.observe(el));
}

function applyThumbToElement(el, dataUrl) {
    const img = el.querySelector('img.file-thumb-placeholder-img');
    if (img) {
        img.src = dataUrl;
    } else {
        const thumbImg = el.querySelector('img');
        if (thumbImg) {
            thumbImg.src = dataUrl;
        }
    }
}

