// ===== FILE CLICK HANDLER (F91 shift+click) =====
function handleFileClick(e, fileId, index) {
    if (APP.batchMode || e.shiftKey) {
        e.preventDefault();
        if (e.shiftKey && APP.lastSelectedIndex >= 0) {
            // F91: Range select
            const files = getFilteredFiles();
            const start = Math.min(APP.lastSelectedIndex, index);
            const end = Math.max(APP.lastSelectedIndex, index);
            for (let i = start; i <= end; i++) {
                if (files[i]) APP.selectedFiles.add(files[i].id);
            }
        } else {
            if (APP.selectedFiles.has(fileId)) APP.selectedFiles.delete(fileId);
            else APP.selectedFiles.add(fileId);
        }
        APP.lastSelectedIndex = index;
        renderFileList();
    } else if (e.detail === 2) {
        // Double click → preview
        openPreview(fileId);
    } else {
        // Single click → detail panel
        haptic('tap');
        openDetailPanel(fileId);
    }
}

// ===== DRAG & DROP (F46, F86, Feature 3: Enhanced) =====
let draggedFileId = null;
let draggedFileIds = []; // Multi-file drag support
function handleDragStart(e, fileId) {
    draggedFileId = fileId;
    // If files are selected and the dragged file is among them, drag all selected
    if (APP.selectedFiles.has(fileId) && APP.selectedFiles.size > 1) {
        draggedFileIds = [...APP.selectedFiles];
    } else {
        draggedFileIds = [fileId];
    }
    e.dataTransfer.effectAllowed = 'move';
    e.dataTransfer.setData('text/plain', draggedFileIds.join(','));
    // Create ghost drag image with file count
    const ghostEl = document.createElement('div');
    ghostEl.style.cssText = 'position:absolute;top:-9999px;left:-9999px;display:flex;align-items:center;gap:8px;padding:8px 14px;background:var(--accent);color:#fff;border-radius:8px;font-size:13px;font-weight:600;font-family:Space Grotesk,sans-serif;white-space:nowrap;box-shadow:0 4px 12px rgba(59,130,246,.4)';
    ghostEl.innerHTML = `<i class="fas fa-file" style="font-size:12px"></i> ${draggedFileIds.length} ${APP.lang==='id'?'file':'file(s)'}`;
    document.body.appendChild(ghostEl);
    e.dataTransfer.setDragImage(ghostEl, 20, 20);
    setTimeout(() => ghostEl.remove(), 0);
}
function handleFolderDrop(e, folderId) {
    e.preventDefault();
    e.stopPropagation();
    // Remove highlight from all folder drop targets
    document.querySelectorAll('.sidebar-folder-drop-target').forEach(el => {
        el.classList.remove('sidebar-drop-highlight');
        el.style.background = '';
    });
    const idsToMove = draggedFileIds.length > 0 ? draggedFileIds : (draggedFileId ? [draggedFileId] : []);
    if (idsToMove.length === 0) return;
    // Don't move to trash via drag (use dedicated actions)
    const isId = APP.lang === 'id';
    let movedCount = 0;
    idsToMove.forEach(async (fid) => {
        const file = APP.files.find(f => f.id === fid);
        if (!file) return;
        // If dropping on "trash" folder, move to trash instead
        if (folderId === 'trash') {
            if (!file.trashed) {
                file.trashed = true;
                file.trashedAt = Date.now();
                await saveFile(file);
                APP.files = APP.files.filter(f => f.id !== fid);
                movedCount++;
            }
        } else {
            await moveFileToFolderSilent(fid, folderId);
            movedCount++;
        }
    });
    if (movedCount > 0) {
        const folder = APP.folders.find(f => f.id === folderId);
        const folderName = folder ? folder.name : (folderId === 'trash' ? (isId ? 'Sampah' : 'Trash') : '');
        showToast(`${movedCount} ${isId?'file dipindahkan ke':'file(s) moved to'} ${folderName}`, 'success');
        setTimeout(() => refreshUI(), 100);
    }
    draggedFileId = null;
    draggedFileIds = [];
}
// Silent move (no toast — used by handleFolderDrop which shows its own toast)
async function moveFileToFolderSilent(fileId, folderId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    file.folderId = folderId === 'all' || folderId === 'favorites' || folderId === 'recent' ? null : folderId;
    await saveFile(file);
}
function handleDragReorder(e, index) {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
}
function handleDropReorder(e, targetId) {
    e.preventDefault();
    if (!draggedFileId || draggedFileId === targetId) return;
    const targetIdx = APP.files.findIndex(f => f.id === targetId);
    if (targetIdx >= 0) {
        APP.customOrder[draggedFileId] = targetIdx;
        localStorage.setItem('rb_custom_order', JSON.stringify(APP.customOrder));
    }
    draggedFileId = null;
    renderFileList();
}
function setupDragDrop() {
    const zone = document.getElementById('drop-zone');
    const container = document.getElementById('file-list-container');
    if (!container) return;
    ['dragenter', 'dragover'].forEach(ev => {
        container.addEventListener(ev, (e) => {
            e.preventDefault();
            if (zone) zone.style.display = 'block';
            if (zone) zone.classList.add('drag-over');
        });
    });
    ['dragleave', 'drop'].forEach(ev => {
        container.addEventListener(ev, (e) => {
            if (e.target === container || !container.contains(e.relatedTarget)) {
                if (zone) zone.style.display = 'none';
                if (zone) zone.classList.remove('drag-over');
            }
        });
    });
    container.addEventListener('drop', (e) => {
        e.preventDefault();
        if (e.dataTransfer.files.length > 0) {
            handleFileSelect(e.dataTransfer.files);
        }
    });
    // Sidebar folder drop targets — highlight on drag over
    setupSidebarDragTargets();
}

// Setup drag over/out handlers for sidebar folder targets
function setupSidebarDragTargets() {
    const targets = document.querySelectorAll('.sidebar-folder-drop-target');
    targets.forEach(el => {
        el.addEventListener('dragover', (e) => {
            e.preventDefault();
            e.dataTransfer.dropEffect = 'move';
            el.classList.add('drag-over');
        });
        el.addEventListener('dragleave', (e) => {
            el.classList.remove('drag-over');
        });
        el.addEventListener('drop', (e) => {
            el.classList.remove('drag-over');
        });
    });
}


// ===== UPLOAD (F3, F10, F11, F76, F79, F81, F89, F93, F103) =====
function triggerUpload() {
    haptic('tap');
    const inp = document.getElementById('file-upload-input');
    if (inp) inp.click();
}

function triggerUploadWithDriveSelect() {
    const inp = document.getElementById('file-upload-input');
    if (!inp) return;
    // Override the onchange to open drive select modal instead
    const originalOnchange = inp.onchange;
    inp.onchange = function() {
        if (this.files && this.files.length > 0) {
            openDriveSelectModal(this.files[0]);
        }
        inp.onchange = originalOnchange;
    };
    inp.click();
}

async function handleFileSelect(fileList) {
    if (!fileList || fileList.length === 0) return;
    showUploadPreview(fileList);
    for (const file of fileList) {
        await executeUpload(file);
    }
    const inp = document.getElementById('file-upload-input');
    if (inp) inp.value = '';
}

async function executeUpload(file, folderParam) {
    // Storage quota check (F16)
    const quota = checkStorageQuota(file.size);
    if (!quota.allowed) {
        showQuotaExceededModal(quota);
        return;
    }

    // Smart Storage Allocation: Use best available drive across all providers
    const bestDrive = selectBestDrive(file.size);
    if (bestDrive) {
        if (bestDrive.type === 'gdrive') {
            const gdriveResult = await executeUploadToGDrive(file, folderParam);
            if (gdriveResult) {
                renderFileList();
                return;
            }
        } else if (bestDrive.type === 's3' || bestDrive.type === 'token') {
            const account = bestDrive.account;
            const provider = account.type === 's3' ? APP.storageProviders.s3 : APP.storageProviders.token;
            if (provider) {
                try {
                    await executeUploadToS3Drive(account.id, file);
                    return;
                } catch(e) {
                    // Fall through to Telegram
                    console.warn('S3 upload failed, falling back to Telegram:', e);
                }
            }
        }
    }

    // Fallback: Try Google Drive if still connected (for backward compat)
    if (!bestDrive && APP.gdriveAccounts.filter(a => a.status === 'connected').length > 0) {
        const gdriveResult = await executeUploadToGDrive(file, folderParam);
        if (gdriveResult) {
            renderFileList();
            return;
        }
    }

    const bot = APP.bots[0];
    if (!bot) { showToast(t('uploadError') + ': No bot configured', 'error'); return; }

    // Feature 4: Chunked upload for large files (>10MB)
    if (file.size > 10 * 1024 * 1024) {
        APP.activeUploads++;
        updateGlobalProgress();
        try {
            await executeChunkedUpload(file, folderParam);
            APP.activeUploads--;
            updateGlobalProgress();
            showToast(`${file.name} ${t('uploaded')}`, 'success');
            haptic('uploadComplete');
            sendNotification('Ridgebox', `${file.name} uploaded`);
            logActivity('upload', `${APP.lang==='id'?'Mengunggah':'Uploaded'} ${file.name}`);
            triggerWebhook('file.uploaded', { fileId: file.name, fileName: file.name, fileSize: file.size, fileType: getFileType(file.name, file.type) });
            checkStorageWarning();
        } catch(e) {
            APP.activeUploads--;
            updateGlobalProgress();
            showToast(t('uploadError') + ': ' + e.message, 'error');
            haptic('error');
        }
        return;
    }

    APP.activeUploads++;
    updateGlobalProgress();

    try {
        let fileData = file;
        let fileName = file.name;
        let fileSize = file.size;
        let mimeType = file.type || 'application/octet-stream';
        let isEncrypted = false;

        // Feature 8: Compute SHA-256 hash of original file BEFORE encryption
        let fileHash = null;
        try {
            const originalBuffer = await file.arrayBuffer();
            fileHash = await computeFileHash(originalBuffer);
        } catch(e) { console.warn('SHA-256 hash computation failed:', e); }

        // F11: Encrypt if enabled
        if (APP.settings.encryption) {
            const buffer = await file.arrayBuffer();
            const encData = await encryptData(buffer, 'ridgebox_' + bot.chatId);
            fileData = new Blob([encData], { type: 'application/octet-stream' });
            fileName += '.enc';
            isEncrypted = true;
        }

        // F81: Check for versioning (same name in same folder)
        const folderId = folderParam || APP.currentFolder;
        const existing = APP.files.filter(f => f.name === file.name && f.folderId === folderId && !f.trashed);
        const version = existing.length + 1;

        // F76: Proxy mode vs direct
        let result;
        if (APP.settings.proxyMode !== false) {
            // Upload via server proxy
            const formData = new FormData();
            formData.append('document', fileData, fileName);
            formData.append('bot_index', bot.index);
            if (folderParam) formData.append('chat_id', bot.chatId);

            const resp = await fetch('/api/upload', { method: 'POST', body: formData });
            result = await resp.json();
        } else {
            // Direct upload to Telegram
            const formData = new FormData();
            formData.append('chat_id', bot.chatId);
            formData.append('document', fileData, fileName);
            const resp = await fetch(`https://api.telegram.org/bot${bot.token}/sendDocument`, { method: 'POST', body: formData });
            result = await resp.json();
        }

        if (result.ok || (result.result && result.result.message_id)) {
            const msg = result.result;
            const doc = msg.document || msg.photo?.[msg.photo.length - 1] || msg.video || msg.audio || msg.animation;
            const fileId = doc?.file_id || genId();
            // Telegram sendDocument doesn't return file_path — must call getFile API separately
            let filePath = '';
            try {
                const fileResp = await fetch('/api/file-info', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ file_id: fileId, bot_index: bot.index || '0' })
                });
                const fileData = await fileResp.json();
                if (fileData.ok && fileData.result && fileData.result.file_path) {
                    filePath = fileData.result.file_path;
                }
            } catch(e) { console.warn('getFile failed:', e); }

            // F103: Auto-tag by file type
            const fileType = getFileType(fileName, mimeType);
            const autoTag = getAutoTagColor(fileType);

            const meta = {
                id: genId(),
                name: file.name,
                size: fileSize,
                mime: mimeType,
                fileId: fileId,
                filePath: filePath,
                messageId: msg.message_id || null,
                botIndex: bot.index || '0',
                chatId: bot.chatId,
                folderId: folderId === 'all' || folderId === 'recent' || folderId === 'favorites' || folderId === 'trash' ? null : folderId,
                uploadedAt: Date.now(),
                pinned: false,
                starred: false,
                trashed: false,
                encrypted: isEncrypted,
                version: version,
                tag: autoTag,
                caption: '',
                shareCount: 0,
                fileHash: fileHash
            };

            await saveFile(meta);
            APP.files.push(meta);
            // F25: AI Auto-categorize after upload
            if (APP.settings.aiAutoCategorize !== false) {
                aiCategorizeFile(meta);
            }
            // F118: Apply automation rules after upload
            if (APP.automationRules && APP.automationRules.length > 0) {
                applyAutomationRules(meta);
            }
            // F120: Push notification
            pushNotification('upload', t('notifUploadComplete'), file.name);
            showToast(t('uploaded'), 'success');
            haptic('uploadComplete');
            sendNotification('Ridgebox', `${file.name} ${t('uploaded').toLowerCase()}`);
            logActivity('upload', `${APP.lang==='id'?'Mengunggah':'Uploaded'} ${file.name}`);
            triggerWebhook('file.uploaded', { fileId: meta.id, fileName: meta.name, fileSize: meta.size, fileType: fileType, folderId: meta.folderId });
            checkStorageWarning();
            updateUploadPreviewProgress(file.name, 100);
            setTimeout(clearUploadPreview, 2000);
            // Minimize smart upload zone after first upload
            const suz = document.getElementById('smart-upload-zone');
            if (suz && !suz.classList.contains('minimized')) suz.classList.add('minimized');
            renderFileList();
            const _glowC = document.getElementById('file-list-container');
            if (_glowC) { _glowC.classList.add('success-glow'); setTimeout(() => _glowC.classList.remove('success-glow'), 1000); }
            const sidebar = document.getElementById('sidebar-panel');
            if (sidebar) sidebar.innerHTML = renderSidebarHTML();
            setTimeout(() => setupSidebarDragTargets(), 50);
        } else {
            showToast(t('uploadError') + ': ' + (result.description || 'Unknown error'), 'error');
        }
    } catch (err) {
        showToast(t('uploadError') + ': ' + err.message, 'error');
    } finally {
        APP.activeUploads--;
        updateGlobalProgress();
    }
}

function updateGlobalProgress() { // F93
    const bar = document.getElementById('global-progress-bar');
    if (!bar) return;
    if (APP.activeUploads === 0) {
        bar.style.width = '0';
    } else {
        bar.style.width = Math.min(90, APP.activeUploads * 30) + '%';
        setTimeout(() => { if (APP.activeUploads === 0) bar.style.width = '0'; }, 1000);
    }
}

// ===== URL UPLOAD (F10) =====
function openUrlUpload() {
    openModal(`
        <div style="padding:24px">
            <h3 style="font-size:18px;font-weight:600;margin-bottom:16px"><i class="fas fa-link" style="color:var(--accent)"></i> ${t('uploadFromUrl')}</h3>
            <input type="url" id="url-upload-input" class="input" aria-label="File URL" placeholder="https://example.com/file.pdf" style="margin-bottom:8px">
            <input type="text" id="url-upload-name" class="input" aria-label="File name" placeholder="${APP.lang==='id'?'Nama file (opsional)':'Filename (optional)'}" style="margin-bottom:16px">
            <div style="display:flex;gap:8px;justify-content:flex-end">
                <button class="btn btn-secondary" onclick="closeModal()">${t('cancel')}</button>
                <button class="btn btn-primary" onclick="executeUrlUpload()"><i class="fas fa-upload"></i> ${t('upload')}</button>
            </div>
        </div>`);
}

async function executeUrlUpload() {
    const url = document.getElementById('url-upload-input')?.value;
    const name = document.getElementById('url-upload-name')?.value;
    if (!url) { showToast('URL required', 'warning'); return; }
    // Storage quota check (F16) — URL uploads have unknown size, check if at quota limit
    const quotaCheck = checkStorageQuota(0);
    if (quotaCheck.percentage >= 100) {
        showQuotaExceededModal(quotaCheck);
        return;
    }
    try {
        const resp = await fetch('/api/url-upload', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ url, filename: name, bot_index: APP.bots[0]?.index || '0' })
        });
        const result = await resp.json();
        if (result.ok || result.result) {
            const doc = result.result?.document || result.result?.photo?.[0];
            const fileId = doc?.file_id || genId();
            // Fetch file_path via getFile API
            let filePath = '';
            try {
                const fileResp = await fetch('/api/file-info', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ file_id: fileId, bot_index: APP.bots[0]?.index || '0' })
                });
                const fileData = await fileResp.json();
                if (fileData.ok && fileData.result && fileData.result.file_path) {
                    filePath = fileData.result.file_path;
                }
            } catch(e) { console.warn('getFile failed:', e); }
            const meta = {
                id: genId(),
                name: name || url.split('/').pop() || 'download',
                size: 0,
                mime: 'application/octet-stream',
                fileId: fileId,
                filePath: filePath,
                botIndex: APP.bots[0]?.index || '0',
                chatId: APP.bots[0]?.chatId || '',
                folderId: APP.currentFolder === 'all' ? null : APP.currentFolder,
                uploadedAt: Date.now(),
                pinned: false, starred: false, trashed: false, encrypted: false,
                version: 1, tag: getAutoTagColor('other'), caption: '', shareCount: 0
            };
            await saveFile(meta);
            APP.files.push(meta);
            // F25: AI Auto-categorize
            if (APP.settings.aiAutoCategorize !== false) aiCategorizeFile(meta);
            showToast(t('uploaded'), 'success');
            haptic('uploadComplete');
            renderFileList();
            const _glowC2 = document.getElementById('file-list-container');
            if (_glowC2) { _glowC2.classList.add('success-glow'); setTimeout(() => _glowC2.classList.remove('success-glow'), 1000); }
            closeModal();
        } else {
            showToast(t('uploadError') + ': ' + (result.description || result.error || 'Failed'), 'error');
        }
    } catch (err) {
        showToast(t('uploadError') + ': ' + err.message, 'error');
    }
}

// ===== CAMERA UPLOAD (F89) =====
function openCameraUpload() {
    openModal(`
        <div style="padding:24px">
            <h3 style="font-size:18px;font-weight:600;margin-bottom:16px"><i class="fas fa-camera" style="color:var(--accent)"></i> ${t('cameraCapture')}</h3>
            <video id="camera-preview" autoplay playsinline style="width:100%;border-radius:8px;background:#000;margin-bottom:12px"></video>
            <canvas id="camera-canvas" style="display:none"></canvas>
            <div style="display:flex;gap:8px;justify-content:center;margin-bottom:12px">
                <button class="btn btn-primary" onclick="capturePhoto()"><i class="fas fa-camera"></i> ${t('takePhoto')}</button>
                <button class="btn btn-secondary" id="record-btn" onclick="toggleRecording()"><i class="fas fa-video"></i> ${t('startRecording')}</button>
            </div>
            <div style="display:flex;gap:8px;justify-content:flex-end">
                <button class="btn btn-secondary" onclick="closeCamera();closeModal()">${t('close')}</button>
            </div>
        </div>`);
    startCamera();
}

let cameraStream = null;
let mediaRecorder = null;
let recordingChunks = [];

async function startCamera() {
    try {
        cameraStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: true });
        const video = document.getElementById('camera-preview');
        if (video) video.srcObject = cameraStream;
    } catch (err) {
        showToast('Camera error: ' + err.message, 'error');
    }
}

function closeCamera() {
    if (cameraStream) { cameraStream.getTracks().forEach(t => t.stop()); cameraStream = null; }
    if (mediaRecorder && mediaRecorder.state !== 'inactive') { mediaRecorder.stop(); }
}

function capturePhoto() {
    const video = document.getElementById('camera-preview');
    const canvas = document.getElementById('camera-canvas');
    if (!video || !canvas) return;
    // Storage quota check for camera capture (estimate ~2MB for a photo)
    const quotaCheck = checkStorageQuota(2 * 1024 * 1024);
    if (!quotaCheck.allowed) { showQuotaExceededModal(quotaCheck); return; }
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    canvas.getContext('2d').drawImage(video, 0, 0);
    canvas.toBlob(async (blob) => {
        const file = new File([blob], `photo_${Date.now()}.jpg`, { type: 'image/jpeg' });
        await executeUpload(file);
        closeCamera();
        closeModal();
    }, 'image/jpeg');
}

function toggleRecording() {
    const btn = document.getElementById('record-btn');
    if (!mediaRecorder || mediaRecorder.state === 'inactive') {
        // Storage quota check for recording (estimate ~10MB for a short video)
        const quotaCheck = checkStorageQuota(10 * 1024 * 1024);
        if (!quotaCheck.allowed) { showQuotaExceededModal(quotaCheck); return; }
        recordingChunks = [];
        const video = document.getElementById('camera-preview');
        const stream = video?.srcObject;
        if (!stream) return;
        mediaRecorder = new MediaRecorder(stream);
        mediaRecorder.ondataavailable = (e) => { if (e.data.size > 0) recordingChunks.push(e.data); };
        mediaRecorder.onstop = async () => {
            const blob = new Blob(recordingChunks, { type: 'video/webm' });
            const file = new File([blob], `video_${Date.now()}.webm`, { type: 'video/webm' });
            await executeUpload(file);
            closeCamera();
            closeModal();
        };
        mediaRecorder.start();
        if (btn) btn.innerHTML = `<i class="fas fa-stop"></i> ${t('stopRecording')}`;
    } else {
        mediaRecorder.stop();
        if (btn) btn.innerHTML = `<i class="fas fa-video"></i> ${t('startRecording')}`;
    }
}

// ===== FILE OPERATIONS =====
async function moveToTrash(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) { console.warn('moveToTrash: file not found', fileId); return; }
    const fileName = file.name; // Save name before removing
    logActivity('delete', `${APP.lang==='id'?'Menghapus':'Deleted'} ${fileName}`);
    // Immediately remove from DOM for instant visual feedback
    removeFileElement(fileId);
    // Set trashed flags
    file.trashed = true;
    file.trashedAt = Date.now();
    // Save to IndexedDB with trashed flag
    try {
        await saveFile(file);
        console.log('moveToTrash: saved', fileId, 'trashed=', file.trashed);
    } catch(e) { console.error('moveToTrash save error:', e); }
    // CRITICAL: Remove from APP.files IMMEDIATELY so it disappears from all non-trash views
    // The trash view will read directly from IndexedDB
    APP.files = APP.files.filter(f => f.id !== fileId);
    APP.selectedFiles.delete(fileId);
    closeDetailPanel();
    closeContextMenu();
    showUndoToast(t('movedToTrash'), async () => { await restoreFile(fileId); });
    await refreshUI();
}

async function restoreFile(fileId) {
    haptic('toggle');
    // File might not be in APP.files anymore (removed when trashed)
    // So we need to get it from IndexedDB
    let file = APP.files.find(f => f.id === fileId);
    if (!file) {
        try {
            file = await dbGet('files', fileId);
        } catch(e) { console.error('restoreFile: cannot find file:', e); }
    }
    if (!file) { console.warn('restoreFile: file not found anywhere', fileId); return; }
    file.trashed = false;
    file.trashedAt = null;
    try { await saveFile(file); } catch(e) { console.error('restoreFile save error:', e); }
    // Add back to APP.files so it appears in non-trash views
    if (!APP.files.find(f => f.id === fileId)) {
        APP.files.push(file);
    } else {
        const idx = APP.files.findIndex(f => f.id === fileId);
        if (idx !== -1) { APP.files[idx].trashed = false; APP.files[idx].trashedAt = null; }
    }
    closeDetailPanel();
    closeContextMenu();
    showToast(t('restored'), 'success');
    await refreshUI();
}

async function deletePermanently(fileId) {
    haptic('delete');
    showConfirm(
        t('deletePermanently'),
        APP.lang === 'id' ? 'Tidak bisa dikembalikan.' : 'Cannot be undone.',
        async () => {
            // Immediately remove from DOM for instant visual feedback
            removeFileElement(fileId);
            const file = APP.files.find(f => f.id === fileId);
            // Delete from storage provider (Telegram or Google Drive)
            if (file) {
                if (file.storageProvider === 'gdrive' && file.driveFileId) {
                    // Delete from Google Drive
                    try {
                        const account = APP.gdriveAccounts.find(a => a.id === file.providerAccountId && a.status === 'connected') || APP.gdriveAccounts.find(a => a.status === 'connected');
                        if (account) {
                            const accessToken = await APP.storageProviders.gdrive.getAccessToken(account.id);
                            if (accessToken) {
                                await fetch('/api/gdrive/proxy', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ accessToken, method: 'DELETE', path: `/drive/v3/files/${file.driveFileId}` }) });
                                // Update quota estimate
                                if (account.quota) { account.quota.usage = Math.max(0, (parseInt(account.quota.usage) || 0) - (file.size || 0)); await dbPut('gdrive_accounts', account); }
                            }
                        }
                    } catch(e) { console.warn('GDrive delete failed:', e); }
                } else if (file.messageId && file.chatId) {
                    // Delete from Telegram server
                    try {
                        const bot = APP.bots[file.botIndex || 0] || APP.bots[0];
                        if (bot && bot.masked) {
                            await fetch(`/api/proxy?method=deleteMessage&chat_id=${encodeURIComponent(file.chatId)}&message_id=${file.messageId}&bot_index=${file.botIndex || '0'}`);
                        } else if (bot) {
                            await fetch(`https://api.telegram.org/bot${bot.token}/deleteMessage?chat_id=${encodeURIComponent(file.chatId)}&message_id=${file.messageId}`);
                        }
                    } catch(e) { console.warn('Telegram delete failed:', e); }
                }
            }
            await deleteFileDB(fileId);
            // Remove from memory immediately
            APP.files = APP.files.filter(f => f.id !== fileId);
            APP.selectedFiles.delete(fileId);
            closeDetailPanel();
            closeContextMenu();
            if (file) triggerWebhook('file.deleted', { fileId, fileName: file.name, fileSize: file.size });
            showToast(t('deletedForever'), 'info');
            await refreshUI();
        },
        true
    );
}

