async function deleteCustomFolder(folderId) {
    showConfirm(
        APP.lang === 'id' ? 'Hapus Folder?' : 'Delete Folder?',
        APP.lang === 'id' ? 'File tidak akan dihapus.' : 'Files won\'t be deleted.',
        async () => {
            await deleteFolderDB(folderId);
            APP.folders = APP.folders.filter(f => f.id !== folderId);
            if (APP.currentFolder === folderId) selectFolder('all');
            const sidebar = document.getElementById('sidebar-panel');
            if (sidebar) sidebar.innerHTML = renderSidebarHTML();
            setTimeout(() => setupSidebarDragTargets(), 50);
        },
        false
    );
}

// ===== FOLDER OPTIONS (Self-Destruct) =====
function openFolderOptions(folderId) {
    const isId = APP.lang === 'id';
    const folder = APP.folders.find(f => f.id === folderId);
    if (!folder) return;
    const isSD = !!APP.selfDestructFolders[folderId];
    // fakeFolders removed
    openModal(`<div style="padding:20px;max-width:400px">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">
            <h3 style="font-size:18px;font-weight:600"><i class="fas fa-folder" style="color:#f59e0b;margin-right:8px"></i>${folder.name}</h3>
            <button class="btn btn-ghost btn-sm" onclick="closeModal()"><i class="fas fa-times"></i></button>
        </div>
        <div style="display:flex;flex-direction:column;gap:8px">
            <div style="display:flex;align-items:center;gap:10px;padding:12px;border:1px solid var(--border);border-radius:10px;cursor:pointer;transition:all .15s" onclick="closeModal();openSelfDestructSetup('${folderId}')" onmouseover="this.style.borderColor='#ef4444';this.style.background='rgba(239,68,68,.05)'" onmouseout="this.style.borderColor='var(--border)';this.style.background=''">
                <div style="width:40px;height:40px;border-radius:10px;background:#ef444415;display:flex;align-items:center;justify-content:center"><i class="fas fa-bomb" style="color:#ef4444;font-size:16px"></i></div>
                <div style="flex:1"><div style="font-size:13px;font-weight:600">${isId?'Auto-Hapus Folder':'Self-Destruct'}</div><div style="font-size:11px;color:var(--text-secondary)">${isSD?(isId?'Aktif — hapus file setelah':'Active — delete files after')+' '+APP.selfDestructFolders[folderId].interval+' '+(isId?'hari':'days'):(isId?'Hapus otomatis file lama':'Auto-delete old files')}</div></div>
                ${isSD?'<i class="fas fa-check-circle" style="color:#ef4444"></i>':''}
            </div>

            <div style="border-top:1px solid var(--border);margin:4px 0"></div>
            <div style="display:flex;align-items:center;gap:10px;padding:12px;border:1px solid rgba(239,68,68,.2);border-radius:10px;cursor:pointer;transition:all .15s" onclick="closeModal();deleteCustomFolder('${folderId}')" onmouseover="this.style.background='rgba(239,68,68,.05)'" onmouseout="this.style.background=''">
                <div style="width:40px;height:40px;border-radius:10px;background:rgba(239,68,68,.08);display:flex;align-items:center;justify-content:center"><i class="fas fa-trash" style="color:#ef4444;font-size:16px"></i></div>
                <div style="flex:1"><div style="font-size:13px;font-weight:600;color:#ef4444">${isId?'Hapus Folder':'Delete Folder'}</div><div style="font-size:11px;color:var(--text-secondary)">${isId?'File tidak akan dihapus':'Files won\'t be deleted'}</div></div>
            </div>
        </div>
    </div>`);
}

async function emptyTrash() {
    showConfirm(
        t('emptyTrashConfirm'),
        t('emptyTrashWarning'),
        async () => {
            // Get trashed files from IndexedDB (they're not in APP.files anymore)
            let trashFiles;
            try {
                const allDbFiles = await dbGetAll('files');
                trashFiles = allDbFiles.filter(f => f.trashed);
            } catch(e) { trashFiles = []; }
            for (const f of trashFiles) {
                if (f.messageId && f.chatId) {
                    try {
                        const bot = APP.bots[f.botIndex || 0] || APP.bots[0];
                        if (bot && bot.masked) {
                            await fetch(`/api/proxy?method=deleteMessage&chat_id=${encodeURIComponent(f.chatId)}&message_id=${f.messageId}&bot_index=${f.botIndex || '0'}`);
                        } else if (bot) {
                            await fetch(`https://api.telegram.org/bot${bot.token}/deleteMessage?chat_id=${encodeURIComponent(f.chatId)}&message_id=${f.messageId}`);
                        }
                    } catch(e) { console.warn('Telegram delete failed:', e); }
                }
                await deleteFileDB(f.id);
            }
            // Also remove any trashed files still in APP.files (shouldn't be, but safety)
            APP.files = APP.files.filter(f => !f.trashed);
            closeDetailPanel();
            closeContextMenu();
            showToast(t('emptyTrash'), 'info');
            await refreshUI();
        },
        true
    );
}

// ===== DOWNLOAD =====
// Helper: Save blob to device storage (Downloads folder on phone)
// Direct download — navigates browser to API URL with Content-Disposition: attachment
// This forces the browser to save the file directly to phone storage (like MediaFire)
// instead of opening/previewing it in the browser
function directDownload(url, fileName) {
    const a = document.createElement('a');
    a.href = url;
    a.download = fileName || '';
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { a.remove(); }, 1000);
}

async function saveToDevice(blob, fileName) {
    // Method 1: File System Access API (Chrome/Edge desktop) — saves directly to Downloads
    if (window.showSaveFilePicker) {
        try {
            const handle = await window.showSaveFilePicker({
                suggestedName: fileName,
                types: blob.type ? [{ description: 'File', accept: { [blob.type]: ['.' + fileName.split('.').pop()] } }] : []
            });
            const writable = await handle.createWritable();
            await writable.write(blob);
            await writable.close();
            return true;
        } catch (e) {
            if (e.name === 'AbortError') return false;
            console.warn('showSaveFilePicker failed, falling back:', e);
        }
    }
    // Method 2: Navigator msSaveBlob (IE/Edge legacy)
    if (navigator.msSaveBlob) {
        try {
            navigator.msSaveBlob(blob, fileName);
            return true;
        } catch(e) { console.warn('msSaveBlob failed:', e); }
    }
    // Method 3: <a download> with blob URL
    const a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = fileName;
    a.style.display = 'none';
    document.body.appendChild(a);
    a.click();
    setTimeout(() => { URL.revokeObjectURL(a.href); a.remove(); }, 5000);
    return true;
}

async function downloadFile(fileId) {
    haptic('tap');
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    // Track last accessed time
    updateLastAccessed(fileId);
    const isId = APP.lang === 'id';
    logActivity('download', (isId?'Mengunduh':'Downloaded') + ' ' + file.name);
    try {
        // Google Drive files — download via GDrive provider
        if (file.storageProvider === 'gdrive' && file.driveFileId) {
            const account = APP.gdriveAccounts.find(a => a.id === file.providerAccountId);
            if (!account || account.status !== 'connected') {
                // Try to find any connected account
                const anyAccount = APP.gdriveAccounts.find(a => a.status === 'connected');
                if (!anyAccount) { showToast(isId ? 'Akun Google Drive tidak tersedia. Hubungkan ulang.' : 'Google Drive account unavailable. Please reconnect.', 'warning'); return; }
            }
            const activeAccount = APP.gdriveAccounts.find(a => a.id === file.providerAccountId && a.status === 'connected') || APP.gdriveAccounts.find(a => a.status === 'connected');
            const accessToken = await APP.storageProviders.gdrive.getAccessToken(activeAccount.id);
            if (!accessToken) { showToast(isId ? 'Gagal memperoleh token akses' : 'Failed to obtain access token', 'error'); return; }
            const dlUrl = `/api/gdrive/download?accessToken=${encodeURIComponent(accessToken)}&fileId=${encodeURIComponent(file.driveFileId)}`;
            directDownload(dlUrl, file.name);
            showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
            logActivity('download', `${isId?'Mengunduh':'Downloaded'} ${file.name} (Google Drive)`);
            return;
        }

        // S3 / Token provider files — download via provider
        if (file.storageProvider === 's3' && file.driveFileId) {
            const account = APP.s3Accounts.find(a => a.id === file.providerAccountId);
            if (!account || account.status !== 'connected') {
                showToast(isId ? 'Akun penyimpanan tidak tersedia. Hubungkan ulang.' : 'Storage account unavailable. Please reconnect.', 'warning');
                return;
            }
            try {
                const provider = account.type === 's3' ? APP.storageProviders.s3 : APP.storageProviders.token;
                if (!provider) throw new Error('Provider not found');
                const dlResult = await provider.download(account.id, file.driveFileId);
                // dlResult can be a URL string or a blob URL
                if (typeof dlResult === 'string') {
                    if (dlResult.startsWith('/api/')) {
                        directDownload(dlResult, file.name);
                    } else if (dlResult.startsWith('blob:')) {
                        const resp = await fetch(dlResult);
                        const blob = await resp.blob();
                        await saveToDevice(blob, file.name);
                        URL.revokeObjectURL(dlResult);
                    } else {
                        // External URL (e.g. OneDrive download URL)
                        directDownload(dlResult, file.name);
                    }
                }
                showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
                logActivity('download', `${isId?'Mengunduh':'Downloaded'} ${file.name} (S3/Cloud)`);
            } catch(e) {
                showToast(isId ? 'Gagal mengunduh: ' : 'Download failed: ' + e.message, 'error');
            }
            return;
        }

        // Resolve filePath if missing
        if (!file.filePath && file.fileId) {
            try {
                const fileResp = await fetch('/api/file-info', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ file_id: file.fileId, bot_index: file.botIndex || '0' })
                });
                const fileData = await fileResp.json();
                if (fileData.ok && fileData.result && fileData.result.file_path) {
                    file.filePath = fileData.result.file_path;
                    await saveFile(file);
                }
            } catch(e) { console.warn('getFile resolve failed:', e); }
        }

        // If file is encrypted, we must fetch+blob+decrypt first
        if (file.encrypted) {
            let url;
            if (APP.settings.proxyMode !== false) {
                url = '/api/download?path=' + encodeURIComponent(file.filePath) + '&bot_index=' + file.botIndex + '&name=' + encodeURIComponent(file.name);
            } else {
                url = 'https://api.telegram.org/file/bot' + (APP.bots[0]?.token||'') + '/' + file.filePath;
            }
            const resp = await fetch(url);
            if (!resp.ok) throw new Error('Download failed');
            let blob = await resp.blob();
            try {
                const encData = new Uint8Array(await blob.arrayBuffer());
                const decData = await decryptData(encData, 'ridgebox_' + file.chatId);
                blob = new Blob([decData]);
            } catch(e) { console.warn('Decrypt failed, returning raw file'); }
            await saveToDevice(blob, file.name);
            showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
            return;
        }

        // Non-encrypted: Direct download — browser navigates to API URL which has
        // Content-Disposition: attachment → file saves directly to phone Downloads folder
        // This is the MediaFire-style experience: click → save, no preview
        // Always use proxy API for downloads — the Content-Disposition: attachment header
        // forces the browser to save the file. Telegram direct URLs don't have this header
        // and would open the file in the browser instead.
        const dlUrl = '/api/download?path=' + encodeURIComponent(file.filePath) + '&bot_index=' + file.botIndex + '&name=' + encodeURIComponent(file.name);
        directDownload(dlUrl, file.name);
        showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
        logActivity('download', `${APP.lang==='id'?'Mengunduh':'Downloaded'} ${file.name}`);
    } catch (err) {
        showToast('Download error: ' + err.message, 'error');
    }
}

// ===== BULK OPERATIONS (F9, F83) =====
async function bulkDelete() {
    const fileCount = APP.selectedFiles.size;
    showConfirm(
        APP.lang === 'id' ? `Hapus ${fileCount} File?` : `Delete ${fileCount} Files?`,
        APP.lang === 'id' ? 'File akan dipindahkan ke sampah.' : 'Files will be moved to trash.',
        async () => {
            const trashedIds = new Set();
            for (const id of APP.selectedFiles) {
                const file = APP.files.find(f => f.id === id);
                if (file) {
                    file.trashed = true;
                    file.trashedAt = Date.now();
                    await saveFile(file);
                    trashedIds.add(id);
                }
            }
            // Remove trashed files from APP.files
            APP.files = APP.files.filter(f => !trashedIds.has(f.id));
            APP.selectedFiles.clear();
            APP.batchMode = false;
            closeDetailPanel();
            closeContextMenu();
            showUndoToast(t('movedToTrash'), async () => {
                // Undo: restore all files that were just trashed
                for (const id of trashedIds) {
                    await restoreFile(id);
                }
                showToast(APP.lang === 'id' ? 'File dipulihkan' : 'Files restored', 'success');
            });
            await refreshUI();
        },
        true
    );
}

async function bulkDownloadZip() { // F83 + Feature 6: Enhanced with progress modal
    const isId = APP.lang === 'id';
    // Lazy-load JSZip on demand
    if (typeof JSZip === 'undefined') {
        showToast(isId ? 'Memuat pustaka ZIP...' : 'Loading ZIP library...', 'info', 3000);
        try { await window.LazyLibs.load('jszip'); } catch(e) {
            showToast(isId ? 'Gagal memuat pustaka ZIP' : 'Failed to load ZIP library', 'error');
            return;
        }
    }
    const ids = [...APP.selectedFiles];
    const files = ids.map(id => APP.files.find(f => f.id === id)).filter(Boolean);
    if (files.length === 0) { showToast(isId ? 'Tidak ada file dipilih' : 'No files selected', 'warning'); return; }
    
    showToast(isId ? `Mengunduh ${files.length} file sebagai ZIP...` : `Downloading ${files.length} files as ZIP...`, 'info', 5000);
    
    const zip = new JSZip();
    let count = 0;
    
    // Feature 6: Show progress modal
    openModal(`<div style="padding:24px">
        <h3 style="font-size:18px;font-weight:600;margin-bottom:16px"><i class="fas fa-file-archive" style="color:var(--accent)"></i> ${isId ? 'Unduh sebagai ZIP' : 'Download as ZIP'}</h3>
        <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${files.length} ${isId ? 'file' : 'files'}</p>
        <div style="background:var(--bg-secondary);border-radius:8px;height:8px;overflow:hidden;margin-bottom:8px">
            <div id="zip-progress-bar" style="height:100%;width:0%;background:linear-gradient(90deg,var(--accent),#8b5cf6);border-radius:8px;transition:width .3s ease"></div>
        </div>
        <p id="zip-progress-text" style="font-size:12px;color:var(--text-secondary)">${isId ? 'Memulai...' : 'Starting...'}</p>
    </div>`);
    
    for (let i = 0; i < files.length; i++) {
        const file = files[i];
        const progressBar = document.getElementById('zip-progress-bar');
        const progressText = document.getElementById('zip-progress-text');
        if (progressText) progressText.textContent = isId ? `Mengunduh file ${i + 1} dari ${files.length}: ${file.name}` : `Downloading file ${i + 1} of ${files.length}: ${file.name}`;
        if (progressBar) progressBar.style.width = ((i / files.length) * 100) + '%';
        
        try {
            let url;
            if (file.storageProvider === 'gdrive' && file.driveFileId) {
                const account = APP.gdriveAccounts.find(a => a.id === file.providerAccountId && a.status === 'connected') || APP.gdriveAccounts.find(a => a.status === 'connected');
                if (account) {
                    const accessToken = await APP.storageProviders.gdrive.getAccessToken(account.id);
                    url = `/api/gdrive/download?accessToken=${encodeURIComponent(accessToken)}&fileId=${encodeURIComponent(file.driveFileId)}`;
                }
            } else if (file.storageProvider === 's3' && file.driveFileId) {
                const account = APP.s3Accounts.find(a => a.id === file.providerAccountId);
                if (account) {
                    const provider = account.type === 's3' ? APP.storageProviders.s3 : APP.storageProviders.token;
                    if (provider) {
                        const dlResult = await provider.download(account.id, file.driveFileId);
                        if (typeof dlResult === 'string' && (dlResult.startsWith('blob:') || dlResult.startsWith('/api/') || dlResult.startsWith('http'))) {
                            url = dlResult;
                        }
                    }
                }
            }
            if (!url) {
                url = APP.settings.proxyMode !== false
                    ? `/api/download?path=${encodeURIComponent(file.filePath)}&bot_index=${file.botIndex}&name=${encodeURIComponent(file.name)}`
                    : `https://api.telegram.org/file/bot${APP.bots[0]?.token}/${file.filePath}`;
            }
            const resp = await fetch(url);
            if (resp.ok) {
                const blob = await resp.blob();
                // Handle duplicate filenames
                let fileName = file.name;
                let counter = 1;
                while (zip.file(fileName)) {
                    const ext = fileName.includes('.') ? '.' + fileName.split('.').pop() : '';
                    const base = fileName.includes('.') ? fileName.slice(0, fileName.lastIndexOf('.')) : fileName;
                    fileName = base + ` (${counter})` + ext;
                    counter++;
                }
                zip.file(fileName, blob);
                count++;
            }
        } catch(e) { console.warn('Skip file', file.name, e); }
    }
    
    const progressBar = document.getElementById('zip-progress-bar');
    const progressText = document.getElementById('zip-progress-text');
    if (progressBar) progressBar.style.width = '100%';
    if (progressText) progressText.textContent = isId ? 'Menghasilkan ZIP...' : 'Generating ZIP...';
    
    if (count > 0) {
        const content = await zip.generateAsync({ type: 'blob' });
        const dateStr = new Date().toISOString().slice(0, 10);
        await saveToDevice(content, `RidgeBox_${dateStr}.zip`);
        closeModal();
        showToast(`${count} ${isId ? 'file diunduh sebagai ZIP' : 'files downloaded as ZIP'} <i class="fas fa-check-circle" style="font-size:11px"></i>`, 'success');
    } else {
        closeModal();
        showToast(isId ? 'Tidak ada file yang berhasil diunduh' : 'No files could be downloaded', 'error');
    }
    APP.selectedFiles.clear();
    renderFileList();
}


// ===== SHARE (F5, F78, F88, F102) =====
function openShareModal(fileId) {
    haptic('tap');
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    closeContextMenu();
    logActivity('share', `${APP.lang==='id'?'Membagikan':'Shared'} ${file.name}`);
    const existingShares = APP.shares.filter(s => s.fileId === fileId && s.type !== 'gallery');
    // Generate cross-device share URL with encoded file info
    let shareUrl = '';
    if (existingShares.length > 0) {
        const s = existingShares[0];
        const payload = {
            fn: file.name, fs: file.size, fm: file.mime || '',
            fp: file.filePath || '', fi: file.fileId || '', bi: file.botIndex || '0',
            ci: file.chatId || '', pw: s.password || '',
            ex: s.expiry || 0, sd: s.selfDestruct ? 1 : 0,
            pm: s.permission || 'download',
            sid: s.id, enc: file.encrypted ? 1 : 0,
            ca: file.caption || '', al: s.alias || ''
        };
        const encoded = btoa(unescape(encodeURIComponent(JSON.stringify(payload))));
        shareUrl = `${location.origin}${location.pathname}#/s/${encoded}`;
    }
    // Store share URL in a global for safe copy
    window._currentShareUrl = shareUrl;
    window._currentShareFileId = fileId;
    // Compute analytics
    const totalShares = existingShares.length;
    const totalDownloads = existingShares.reduce((sum, s) => sum + (s.downloadCount || 0), 0);
    const totalClicks = existingShares.reduce((sum, s) => sum + (s.clicks || 0), 0);
    const lastAccessed = existingShares.reduce((max, s) => Math.max(max, s.lastAccess || s.lastAccessedAt || 0), 0);
    const activeLinks = existingShares.filter(s => !s.expiry || s.expiry > Date.now()).length;
    const expiredLinks = totalShares - activeLinks;

    // Helper: get expiry badge for a share
    function getExpiryBadge(s) {
        if (!s.expiry || s.expiry === 0) return `<span class="expiry-badge never"><i class="fas fa-infinity" style="font-size:8px"></i> ${t('never')}</span>`;
        const remaining = s.expiry - Date.now();
        if (remaining <= 0) return `<span class="expiry-badge expired"><i class="fas fa-clock" style="font-size:8px"></i> ${t('expired')}</span>`;
        const hrs = Math.floor(remaining / 3600000);
        const mins = Math.floor((remaining % 3600000) / 60000);
        const days = Math.floor(remaining / 86400000);
        let timeStr = '';
        if (days > 0) timeStr = days + 'd ' + Math.floor((remaining % 86400000) / 3600000) + 'h';
        else if (hrs > 0) timeStr = hrs + 'h ' + mins + 'm';
        else timeStr = mins + 'm';
        const badgeClass = remaining < 3600000 ? 'expiring' : 'active';
        return `<span class="expiry-badge ${badgeClass}"><i class="fas fa-clock" style="font-size:8px"></i> ${timeStr}</span>`;
    }

    openModal(`
        <div style="padding:24px">
            <h3 style="font-size:18px;font-weight:600;margin-bottom:4px"><i class="fas fa-share-alt" style="color:var(--accent)"></i> ${t('share')}</h3>
            <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${file.name}</p>
            <!-- Tabs -->
            <div class="share-tab-bar">
                <button class="share-tab-btn active" onclick="switchShareTab('link')"><i class="fas fa-link" style="font-size:11px"></i> ${t('linkTab')}</button>
                <button class="share-tab-btn" onclick="switchShareTab('qr')"><i class="fas fa-qrcode" style="font-size:11px"></i> ${t('qrCodeTab')}</button>
            </div>
            <!-- Link Tab -->
            <div class="share-tab-content active" id="share-tab-link">
                ${shareUrl ? `
                    <div style="margin-bottom:16px">
                        <label style="font-size:12px;font-weight:500;margin-bottom:4px;display:block">${t('shareLink')}</label>
                        <div style="display:flex;gap:6px">
                            <input type="text" class="input" id="share-url-input" aria-label="Share link" readonly style="font-size:12px;font-family:'JetBrains Mono',monospace">
                            <button class="btn btn-primary btn-sm" onclick="copyShareLink(window._currentShareUrl)" aria-label="Copy link"><i class="fas fa-copy"></i></button>
                        </div>
                    </div>
                ` : ''}
                <div style="display:flex;flex-direction:column;gap:12px">
                    <div>
                        <label style="font-size:12px;font-weight:500;display:block;margin-bottom:4px">${t('password')} (${APP.lang==='id'?'opsional':'optional'})</label>
                        <input type="text" id="share-password" class="input" aria-label="Link password" placeholder="••••••">
                    </div>
                    <div>
                        <label style="font-size:12px;font-weight:500;display:block;margin-bottom:4px">${t('expiry')}</label>
                        <select id="share-expiry" class="input" aria-label="Link expiry">
                            <option value="0">${APP.lang==='id'?'Tidak pernah':'Never'}</option>
                            <option value="1">${t('expires1h')}</option>
                            <option value="24">${t('expires24h')}</option>
                            <option value="168">${t('expires7d')}</option>
                            <option value="720">${t('expires30d')}</option>
                        </select>
                    </div>
                    <div style="display:flex;align-items:center;gap:10px">
                        <label class="toggle-switch"><input type="checkbox" id="share-selfdestruct"><span class="toggle-slider"></span></label>
                        <label for="share-selfdestruct" style="font-size:13px;cursor:pointer">${t('selfDestruct')} (${APP.lang==='id'?'1x pakai':'1x use'})</label>
                    </div>
                    <div>
                        <label style="font-size:12px;font-weight:500;display:block;margin-bottom:4px">${APP.lang==='id'?'Izin Akses':'Access Permission'}</label>
                        <select id="share-permission" class="input" aria-label="Permission">
                            <option value="view">${APP.lang==='id'?'Lihat Saja':'View Only'}</option>
                            <option value="download" selected>${APP.lang==='id'?'Bisa Download':'Can Download'}</option>
                            <option value="edit">${APP.lang==='id'?'Bisa Edit':'Can Edit'}</option>
                        </select>
                        <div style="display:flex;gap:6px;margin-top:6px">
                            <span class="perm-badge view" id="perm-preview-badge"><i class="fas fa-eye" style="font-size:10px"></i> ${APP.lang==='id'?'Lihat':'View'}</span>
                            <span class="perm-badge download" id="perm-download-badge"><i class="fas fa-download" style="font-size:10px"></i> ${APP.lang==='id'?'Download':'Download'}</span>
                            <span class="perm-badge edit" id="perm-edit-badge" style="opacity:.35"><i class="fas fa-pen" style="font-size:10px"></i> ${APP.lang==='id'?'Edit':'Edit'}</span>
                        </div>
                    </div>
                    <div>
                        <label style="font-size:12px;font-weight:500;display:block;margin-bottom:4px">${t('customAlias')} (${APP.lang==='id'?'opsional':'optional'})</label>
                        <input type="text" id="share-alias" class="input" aria-label="Custom alias" placeholder="my-file">
                    </div>
                </div>
                <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:20px;flex-wrap:wrap">
                    <button class="btn btn-ghost btn-sm" onclick="closeModal();createGallery('${file.folderId || 'all'}')"><i class="fas fa-images"></i> ${t('createGallery')}</button>
                    <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
                    <button class="btn btn-primary" onclick="createShareLink('${fileId}')"><i class="fas fa-link"></i> ${t('shareLink')}</button>
                </div>
                <!-- Existing Shares with Expiry Timer & Download Count -->
                ${existingShares.length > 0 ? `
                    <div style="margin-top:16px;border-top:1px solid var(--border);padding-top:12px">
                        <div style="font-size:12px;font-weight:600;margin-bottom:8px">${APP.lang==='id'?'Link Bagikan Aktif':'Active Share Links'}</div>
                        ${existingShares.slice(0, 5).map(s => `
                            <div class="share-link-row">
                                <div class="slr-info">
                                    <i class="fas fa-link"></i>
                                    <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${s.alias || s.id.substring(0,8)}</span>
                                    <span style="color:var(--text-secondary)">${s.downloadCount || 0} <i class="fas fa-download" style="font-size:9px"></i></span>
                                </div>
                                <div class="slr-meta">
                                    ${getExpiryBadge(s)}
                                </div>
                            </div>
                        `).join('')}
                    </div>
                ` : ''}
                <!-- Analytics Cards -->
                ${totalShares > 0 ? `
                    <div style="margin-top:12px;border-top:1px solid var(--border);padding-top:12px">
                        <div style="font-size:12px;font-weight:600;margin-bottom:4px">${t('shareStats')}</div>
                        <div class="share-analytics-grid">
                            <div class="share-analytics-card accent">
                                <div class="sa-icon"><i class="fas fa-link"></i></div>
                                <div class="sa-number">${totalShares}</div>
                                <div class="sa-label">${t('totalShares')}</div>
                            </div>
                            <div class="share-analytics-card green">
                                <div class="sa-icon"><i class="fas fa-download"></i></div>
                                <div class="sa-number">${totalDownloads}</div>
                                <div class="sa-label">${t('totalDownloads')}</div>
                            </div>
                            <div class="share-analytics-card purple">
                                <div class="sa-icon"><i class="fas fa-eye"></i></div>
                                <div class="sa-number">${totalClicks}</div>
                                <div class="sa-label">${APP.lang==='id'?'Total Klik':'Total Clicks'}</div>
                            </div>
                            <div class="share-analytics-card orange">
                                <div class="sa-icon"><i class="fas fa-clock"></i></div>
                                <div class="sa-number">${activeLinks}/${totalShares}</div>
                                <div class="sa-label">${t('activeLinks')}</div>
                            </div>
                        </div>
                        ${lastAccessed > 0 ? `<div style="font-size:11px;color:var(--text-secondary);margin-top:8px;text-align:center"><i class="fas fa-clock" style="font-size:9px"></i> ${t('lastAccessed')}: ${formatDate(lastAccessed)}</div>` : ''}
                    </div>
                ` : ''}
            </div>
            <!-- QR Code Tab -->
            <div class="share-tab-content" id="share-tab-qr">
                <div class="qr-container">
                    ${shareUrl ? `
                        <div class="qr-canvas-wrap">
                            <canvas id="share-qr-canvas" width="200" height="200"></canvas>
                        </div>
                        <div style="font-size:12px;color:var(--text-secondary);margin-bottom:12px;word-break:break-all;max-width:300px;text-align:center">${shareUrl}</div>
                        <div style="display:flex;gap:8px">
                            <button class="btn btn-primary btn-sm" onclick="copyShareLink(window._currentShareUrl)"><i class="fas fa-copy"></i> ${APP.lang==='id'?'Salin Link':'Copy Link'}</button>
                            <button class="btn btn-secondary btn-sm qr-download-btn" onclick="downloadQRCode()"><i class="fas fa-download"></i> ${t('downloadQR')}</button>
                        </div>
                    ` : `
                        <div style="text-align:center;padding:20px;color:var(--text-secondary)">
                            <i class="fas fa-qrcode" style="font-size:48px;margin-bottom:12px;opacity:.3"></i>
                            <p style="font-size:13px">${APP.lang==='id'?'Buat link bagikan terlebih dahulu':'Create a share link first'}</p>
                        </div>
                    `}
                </div>
            </div>
        </div>`);
    // Set share URL input value safely (base64 chars can break HTML attributes)
    if (shareUrl) {
        setTimeout(async () => {
            const urlInput = document.getElementById('share-url-input');
            if (urlInput) urlInput.value = shareUrl;
            // Generate QR code (lazy-load QRious on demand)
            const qrCanvas = document.getElementById('share-qr-canvas');
            if (qrCanvas) {
                if (typeof QRious === 'undefined') { try { await window.LazyLibs.load('qrious'); } catch(e) { console.warn('QRious load failed:', e); } }
                if (typeof QRious !== 'undefined') {
                    try {
                        new QRious({
                            element: qrCanvas,
                            value: shareUrl,
                            size: 200,
                            foreground: getComputedStyle(document.documentElement).getPropertyValue('--text').trim() || '#0f172a',
                            background: getComputedStyle(document.documentElement).getPropertyValue('--bg-secondary').trim() || '#f8fafc',
                            level: 'M'
                        });
                    } catch(e) { console.warn('QR generation error:', e); }
                }
            }
        }, 50);
    }
    // Permission selector badge feedback
    setTimeout(() => {
        const permSelect = document.getElementById('share-permission');
        if (permSelect) {
            permSelect.onchange = () => {
                const val = permSelect.value;
                const viewBadge = document.getElementById('perm-preview-badge');
                const downloadBadge = document.getElementById('perm-download-badge');
                const editBadge = document.getElementById('perm-edit-badge');
                if (viewBadge) viewBadge.style.opacity = '1';
                if (downloadBadge) downloadBadge.style.opacity = val === 'download' || val === 'edit' ? '1' : '.35';
                if (editBadge) editBadge.style.opacity = val === 'edit' ? '1' : '.35';
            };
        }
    }, 100);
}

// Switch tabs in share modal
function switchShareTab(tab) {
    document.querySelectorAll('.share-tab-btn').forEach((btn, i) => {
        btn.classList.toggle('active', (tab === 'link' && i === 0) || (tab === 'qr' && i === 1));
    });
    document.getElementById('share-tab-link')?.classList.toggle('active', tab === 'link');
    document.getElementById('share-tab-qr')?.classList.toggle('active', tab === 'qr');
    // Regenerate QR if switching to QR tab
    if (tab === 'qr' && window._currentShareUrl) {
        setTimeout(async () => {
            const qrCanvas = document.getElementById('share-qr-canvas');
            if (qrCanvas) {
                if (typeof QRious === 'undefined') { try { await window.LazyLibs.load('qrious'); } catch(e) {} }
                if (typeof QRious !== 'undefined') {
                    try {
                        new QRious({
                            element: qrCanvas,
                            value: window._currentShareUrl,
                            size: 200,
                            foreground: getComputedStyle(document.documentElement).getPropertyValue('--text').trim() || '#0f172a',
                            background: getComputedStyle(document.documentElement).getPropertyValue('--bg-secondary').trim() || '#f8fafc',
                            level: 'M'
                        });
                    } catch(e) { console.warn('QR generation error:', e); }
                }
            }
        }, 100);
    }
}

// Download QR code as PNG
function downloadQRCode() {
    const canvas = document.getElementById('share-qr-canvas');
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = 'ridgebox-qr-' + (window._currentShareFileId || 'share') + '.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
    showToast(APP.lang==='id'?'QR Code diunduh':'QR Code downloaded', 'success');
}

async function createShareLink(fileId) {
    const password = document.getElementById('share-password')?.value || '';
    const expiry = parseInt(document.getElementById('share-expiry')?.value || '0');
    const selfDestruct = document.getElementById('share-selfdestruct')?.checked || false;
    const permission = document.getElementById('share-permission')?.value || 'download';
    const alias = document.getElementById('share-alias')?.value.trim() || genId().substring(0, 8);
    const file = APP.files.find(f => f.id === fileId);
    if (!file) { showToast('File not found', 'error'); return; }
    const share = {
        id: genId(),
        fileId: fileId,
        alias: alias,
        password: password ? await hashPin(password) : '',
        expiry: expiry > 0 ? Date.now() + expiry * 3600000 : 0,
        expiresAt: expiry > 0 ? Date.now() + expiry * 3600000 : 0,
        selfDestruct: selfDestruct,
        permission: permission,
        clicks: 0,
        downloadCount: 0,
        lastAccess: null,
        lastAccessedAt: null,
        createdAt: Date.now()
    };
    await saveShare(share);
    APP.shares.push(share);
    if (file) { file.shareCount = (file.shareCount || 0) + 1; await saveFile(file); }
    triggerWebhook('file.shared', { fileId, fileName: file.name, fileSize: file.size, shareId: share.id, permission });
    // Encode file info into the share URL so it works cross-device
    const payload = {
        fn: file.name,
        fs: file.size,
        fm: file.mime || '',
        fp: file.filePath || '',
        fi: file.fileId || '',
        bi: file.botIndex || '0',
        ci: file.chatId || '',
        pw: share.password,
        ex: share.expiry,
        sd: selfDestruct ? 1 : 0,
        pm: permission,
        sid: share.id,
        enc: file.encrypted ? 1 : 0,
        ca: file.caption || '',
        al: alias
    };
    const encoded = btoa(unescape(encodeURIComponent(JSON.stringify(payload))));
    const url = `${location.origin}${location.pathname}#/s/${encoded}`;
    closeModal();
    openShareModal(fileId);
    copyShareLink(url);
    showToast(t('shareCreated'), 'success');
}

function copyShareLink(url) {
    navigator.clipboard.writeText(url).then(() => showToast(t('linkCopied'), 'success')).catch(() => showToast(t('linkCopied'), 'info'));
}

// ===== SHARE PORTAL (F5, F6, F78, F88) =====
function decodeSharePayload(raw) {
    try {
        const json = decodeURIComponent(escape(atob(raw)));
        const p = JSON.parse(json);
        return {
            isEncoded: true,
            name: p.fn || 'Unknown',
            size: p.fs || 0,
            mime: p.fm || '',
            filePath: p.fp || '',
            fileId: p.fi || '',
            botIndex: p.bi || '0',
            chatId: p.ci || '',
            password: p.pw || '',
            expiry: p.ex || 0,
            selfDestruct: p.sd === 1,
            permission: p.pm || 'download',
            id: p.sid || raw.substring(0, 8),
            encrypted: p.enc === 1,
            caption: p.ca || '',
            alias: p.al || ''
        };
    } catch (e) {
        return null;
    }
}

function renderSharePortal(rawAlias) {
    const main = document.getElementById('app-main');
    if (!main) return;
    renderHeader();

    // Try decoding base64 payload first (new cross-device format)
    let shareData = decodeSharePayload(rawAlias);
    let share = null;
    let file = null;

    if (shareData && shareData.isEncoded) {
        // New format: data is embedded in URL
        share = shareData;
        file = {
            name: shareData.name,
            size: shareData.size,
            mime: shareData.mime,
            filePath: shareData.filePath,
            fileId: shareData.fileId,
            botIndex: shareData.botIndex,
            chatId: shareData.chatId,
            encrypted: shareData.encrypted,
            caption: shareData.caption
        };
    } else {
        // Legacy format: look up alias in local IndexedDB
        share = APP.shares.find(s => s.alias === rawAlias || s.id === rawAlias);
        if (!share) {
            main.innerHTML = render404Content();
            return;
        }
        const f = APP.files.find(f => f.id === share.fileId);
        if (!f) {
            main.innerHTML = render404Content();
            return;
        }
        file = f;
    }

    // F78: Check self-destruct
    if (share.selfDestruct && APP.usedSelfDestructLinks.has(share.id || '')) {
        main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
            <div style="text-align:center;padding:40px">
                <i class="fas fa-link-slash" style="font-size:48px;color:var(--text-secondary);margin-bottom:16px"></i>
                <h2>${t('linkExpired')}</h2>
                <p style="color:var(--text-secondary)">${t('selfDestructUsed')}</p>
                <a href="#/" class="btn btn-primary" style="margin-top:16px">${t('backToHome')}</a>
            </div>
        </div>`;
        return;
    }
    // Check expiry
    if (share.expiry > 0 && Date.now() > share.expiry) {
        main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
            <div style="text-align:center;padding:40px">
                <i class="fas fa-hourglass-end" style="font-size:48px;color:var(--text-secondary);margin-bottom:16px"></i>
                <h2>${t('linkExpired')}</h2>
                <p style="color:var(--text-secondary)">${t('linkExpiredDesc')}</p>
                <a href="#/" class="btn btn-primary" style="margin-top:16px">${t('backToHome')}</a>
            </div>
        </div>`;
        return;
    }
    const type = getFileType(file.name, file.mime);
    const icon = getFileIcon(type);
    // Check if password protected
    if (share.password) {
        main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
            <div style="text-align:center;max-width:360px;padding:40px">
                <div style="width:64px;height:64px;border-radius:16px;background:${icon.color}15;display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
                    <i class="fas ${icon.icon}" style="font-size:28px;color:${icon.color}"></i>
                </div>
                <h2>${t('protectedFile')}</h2>
                <p style="color:var(--text-secondary);margin-bottom:16px">${file.name}</p>
                <input type="password" id="share-pw-input" class="input" aria-label="Password" placeholder="${t('enterPassword')}" onkeydown="if(event.key==='Enter')verifySharePassword('${share.id || ''}')">
                <p id="share-pw-error" style="color:#ef4444;font-size:12px;margin-top:4px;display:none">${t('wrongPassword')}</p>
                <button class="btn btn-primary" style="width:100%;margin-top:12px" onclick="verifySharePassword('${share.id || ''}')">${t('confirm')}</button>
            </div>
        </div>`;
        // Store share data for password verification
        window._shareVerifyData = share;
        return;
    }
    renderShareDownload(share, file);
}

async function verifySharePassword(shareId) {
    // Support both local IndexedDB shares and cross-device encoded shares
    let share = APP.shares.find(s => s.id === shareId);
    if (!share && window._shareVerifyData) {
        share = window._shareVerifyData;
    }
    if (!share) return;
    const input = document.getElementById('share-pw-input');
    const errEl = document.getElementById('share-pw-error');
    if (!input) return;
    const hashed = await hashPin(input.value);
    if (hashed === share.password) {
        // Build file object from encoded share data or find in local files
        let file;
        if (share.isEncoded || window._shareVerifyData) {
            file = {
                name: share.name || 'Unknown',
                size: share.size || 0,
                mime: share.mime || '',
                filePath: share.filePath || '',
                botIndex: share.botIndex || '0',
                chatId: share.chatId || '',
                encrypted: share.encrypted || false,
                caption: share.caption || ''
            };
        } else {
            file = APP.files.find(f => f.id === share.fileId);
        }
        if (file) renderShareDownload(share, file);
    } else {
        if (errEl) errEl.style.display = 'block';
        input.value = '';
    }
}

function renderShareDownload(share, file) {
    const main = document.getElementById('app-main');
    if (!main) return;
    const type = getFileType(file.name, file.mime);
    const icon = getFileIcon(type);
    // Update share analytics (only for local shares stored in IndexedDB)
    const localShare = APP.shares.find(s => s.id === (share.id || ''));
    if (localShare) {
        localShare.clicks = (localShare.clicks || 0) + 1;
        localShare.lastAccess = Date.now();
        localShare.lastAccessedAt = Date.now();
        saveShare(localShare);
        share.clicks = localShare.clicks;
    } else {
        share.clicks = (share.clicks || 0) + 1;
    }
    // F78: Mark self-destruct as used
    if (share.selfDestruct) {
        APP.usedSelfDestructLinks.add(share.id || '');
        localStorage.setItem('rb_used_links', JSON.stringify([...APP.usedSelfDestructLinks]));
    }
    // Build download function: use fileId for local files, or filePath+fileId for cross-device shares
    const isLocalFile = file.id && APP.files.find(f => f.id === file.id);
    const shareIdForDownload = share.id || '';
    const downloadFn = isLocalFile
        ? `downloadFileWithShareTracking('${file.id}','${shareIdForDownload}')`
        : `downloadSharedFile('${encodeURIComponent(file.filePath || '')}','${encodeURIComponent(file.fileId || '')}','${file.botIndex || '0'}','${encodeURIComponent(file.name)}',${file.encrypted ? 1 : 0},'${file.chatId || ''}','${shareIdForDownload}')`;
    const permissionLevel = share.permission || 'download';
    const isViewOnly = permissionLevel === 'view';
    const permLabel = permissionLevel === 'view' ? (APP.lang==='id'?'Lihat Saja':'View Only') : permissionLevel === 'edit' ? (APP.lang==='id'?'Bisa Edit':'Can Edit') : (APP.lang==='id'?'Bisa Download':'Can Download');
    const permBadgeClass = permissionLevel === 'view' ? 'view' : permissionLevel === 'edit' ? 'edit' : 'download';
    main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
        <div style="text-align:center;max-width:400px;padding:40px">
            <div style="width:80px;height:80px;border-radius:20px;background:${icon.color}15;display:flex;align-items:center;justify-content:center;margin:0 auto 20px">
                <i class="fas ${icon.icon}" style="font-size:36px;color:${icon.color}"></i>
            </div>
            <h2 style="margin-bottom:4px">${t('sharedFile')}</h2>
            <h3 style="font-size:16px;font-weight:500;margin-bottom:4px">${file.name}</h3>
            <p style="color:var(--text-secondary);font-size:13px;margin-bottom:4px">${formatSize(file.size)} · ${type}</p>
            ${file.caption ? `<p style="color:var(--text-secondary);font-size:13px;margin-bottom:16px;font-style:italic">"${file.caption}"</p>` : ''}
            <span class="perm-badge ${permBadgeClass}" style="margin-bottom:12px"><i class="fas ${permissionLevel==='view'?'fa-eye':permissionLevel==='edit'?'fa-pen':'fa-download'}" style="font-size:10px"></i> ${permLabel}</span>
            ${share.selfDestruct ? `<p style="color:#ef4444;font-size:12px;margin-bottom:16px"><i class="fas fa-fire"></i> ${APP.lang==='id'?'Link ini hanya bisa digunakan sekali':'This link can only be used once'}</p>` : ''}
            ${share.expiry && share.expiry > 0 ? (() => {
                const rem = share.expiry - Date.now();
                if (rem > 0) {
                    const d = Math.floor(rem / 86400000);
                    const h = Math.floor((rem % 86400000) / 3600000);
                    const m = Math.floor((rem % 3600000) / 60000);
                    let expStr = d > 0 ? d + 'd ' + h + 'h' : h > 0 ? h + 'h ' + m + 'm' : m + 'm';
                    return `<p style="color:#f59e0b;font-size:12px;margin-bottom:16px"><i class="fas fa-clock"></i> ${t('expiresIn')} ${expStr}</p>`;
                }
                return '';
            })() : ''}
            ${isViewOnly ? `<div style="padding:14px;background:rgba(59,130,246,.06);border:1px solid rgba(59,130,246,.15);border-radius:10px;margin-bottom:8px"><i class="fas fa-eye" style="color:var(--accent);margin-right:6px"></i> ${APP.lang==='id'?'File ini hanya bisa dilihat, tidak bisa didownload':'This file is view-only and cannot be downloaded'}</div>` : `<button class="btn btn-primary" style="width:100%;padding:14px" onclick="${downloadFn}"><i class="fas fa-download"></i> ${t('downloadFile')}</button>`}
            <div style="margin-top:16px;font-size:11px;color:var(--text-secondary)">${t('downloadCount')} ${localShare ? (localShare.downloadCount || 0) : 0} ${t('times')} · ${share.clicks || 0} ${APP.lang==='id'?'klik':'clicks'} · ${formatDate(share.createdAt || Date.now())}</div>
        </div>
    </div>`;
}

// Download file from share portal (cross-device, uses filePath with fileId fallback)
async function downloadSharedFile(encodedPath, encodedFileId, botIndex, encodedName, encrypted, chatId, shareId) {
    let filePath = decodeURIComponent(encodedPath);
    const fileId = decodeURIComponent(encodedFileId);
    const fileName = decodeURIComponent(encodedName);
    try {
        // Build download URL — always include name for Content-Disposition: attachment
        let url;
        if (filePath) {
            url = '/api/download?path=' + encodeURIComponent(filePath) + '&bot_index=' + botIndex + '&name=' + encodeURIComponent(fileName);
        } else if (fileId) {
            url = '/api/download?file_id=' + encodeURIComponent(fileId) + '&bot_index=' + botIndex + '&name=' + encodeURIComponent(fileName);
        } else {
            throw new Error('No file path or ID available');
        }

        // If encrypted, must fetch+blob+decrypt
        if (encrypted) {
            const resp = await fetch(url);
            if (!resp.ok) {
                const errData = await resp.json().catch(() => ({}));
                throw new Error(errData.error || 'Download failed (' + resp.status + ')');
            }
            let blob = await resp.blob();
            try {
                const encData = new Uint8Array(await blob.arrayBuffer());
                const decData = await decryptData(encData, 'ridgebox_' + chatId);
                blob = new Blob([decData]);
            } catch(e) { console.warn('Decrypt failed, returning raw file'); }
            await saveToDevice(blob, fileName);
            showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
            return;
        }

        // Non-encrypted: Direct download — MediaFire style, click → save to phone
        directDownload(url, fileName);
        // Increment download count for the share
        incrementShareDownloadCount(shareId);
        showToast(t('download') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
    } catch (err) {
        showToast('Download error: ' + err.message, 'error');
    }
}

// Download a local file and track share download count
async function downloadFileWithShareTracking(fileId, shareId) {
    await downloadFile(fileId);
    incrementShareDownloadCount(shareId);
}

// Increment downloadCount on a share record
function incrementShareDownloadCount(shareId) {
    if (!shareId) return;
    const localShare = APP.shares.find(s => s.id === shareId);
    if (localShare) {
        localShare.downloadCount = (localShare.downloadCount || 0) + 1;
        localShare.lastAccessedAt = Date.now();
        localShare.lastAccess = Date.now();
        saveShare(localShare);
        const file = APP.files.find(f => f.id === localShare.fileId);
        sendNotification('Ridgebox', APP.lang==='id'?`Link bagikan "${file?.name||'file'}" diakses`:`Share link for "${file?.name||'file'}" accessed`);
    }
}

// ===== PUBLIC GALLERY =====
function renderGallery(galleryId) {
    const main = document.getElementById('app-main');
    if (!main) return;
    renderHeader();
    // Find gallery in shares store
    const gallery = APP.shares.find(s => s.id === galleryId && s.type === 'gallery');
    if (!gallery) {
        main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
            <div style="text-align:center;padding:40px">
                <i class="fas fa-images" style="font-size:48px;color:var(--text-secondary);margin-bottom:16px"></i>
                <h2>${t('galleryEmpty')}</h2>
                <p style="color:var(--text-secondary)">${t('noFilesInGallery')}</p>
                <a href="#/" class="btn btn-primary" style="margin-top:16px">${t('backToHome')}</a>
            </div>
        </div>`;
        return;
    }
    // Resolve file objects from gallery fileIds
    const galleryFiles = (gallery.fileIds || []).map(fid => APP.files.find(f => f.id === fid)).filter(Boolean);
    main.innerHTML = `<div class="page-transition">
        <div style="text-align:center;padding:32px 20px 8px">
            <div style="width:64px;height:64px;border-radius:16px;background:rgba(139,92,246,.1);display:flex;align-items:center;justify-content:center;margin:0 auto 12px">
                <i class="fas fa-images" style="font-size:28px;color:#8b5cf6"></i>
            </div>
            <h2 style="font-size:22px;font-weight:700;margin-bottom:4px">${gallery.title || t('galleryTitle')}</h2>
            ${gallery.description ? `<p style="color:var(--text-secondary);font-size:13px;margin-bottom:4px">${gallery.description}</p>` : ''}
            <p style="color:var(--text-secondary);font-size:11px">${galleryFiles.length} ${APP.lang==='id'?'file':'files'} · ${formatDate(gallery.createdAt)}</p>
        </div>
        ${galleryFiles.length > 0 ? `
            <div class="gallery-grid">
                ${galleryFiles.map(file => {
                    const type = getFileType(file.name, file.mime);
                    const icon = getFileIcon(type);
                    const isLocalFile = file.id && APP.files.find(f => f.id === file.id);
                    const downloadFn = isLocalFile
                        ? `downloadFile('${file.id}')`
                        : `downloadSharedFile('${encodeURIComponent(file.filePath || '')}','${encodeURIComponent(file.fileId || '')}','${file.botIndex || '0'}','${encodeURIComponent(file.name)}',${file.encrypted ? 1 : 0},'${file.chatId || ''}','')`;
                    return `<div class="gallery-card">
                        <div class="gc-icon" style="background:${icon.color}15">
                            <i class="fas ${icon.icon}" style="font-size:24px;color:${icon.color}"></i>
                        </div>
                        <div class="gc-name" title="${file.name}">${file.name}</div>
                        <div class="gc-size">${formatSize(file.size)} · ${type}</div>
                        <div class="gc-download">
                            <button class="btn btn-primary btn-sm" style="width:100%" onclick="${downloadFn}"><i class="fas fa-download"></i> ${t('download')}</button>
                        </div>
                    </div>`;
                }).join('')}
            </div>
        ` : `
            <div style="text-align:center;padding:40px;color:var(--text-secondary)">
                <i class="fas fa-folder-open" style="font-size:48px;margin-bottom:16px;opacity:.3"></i>
                <p>${t('noFilesInGallery')}</p>
            </div>
        `}
        <div style="text-align:center;padding:16px;font-size:11px;color:var(--text-secondary)">
            ${APP.lang==='id'?'Didukung oleh':'Powered by'} Ridgebox
        </div>
    </div>`;
}

async function createGallery(folderId) {
    // Get files in the folder
    const folderFiles = folderId === 'all' 
        ? APP.files.filter(f => !f.trashed) 
        : APP.files.filter(f => f.folderId === folderId && !f.trashed);
    if (folderFiles.length === 0) {
        showToast(APP.lang==='id'?'Tidak ada file untuk galeri':'No files for gallery', 'warning');
        return;
    }
    const galleryId = genId();
    const galleryTitle = folderId === 'all' 
        ? (APP.lang==='id'?'Semua File':'All Files') 
        : (APP.folders.find(f => f.id === folderId)?.name || t('galleryTitle'));
    const gallery = {
        id: galleryId,
        type: 'gallery',
        title: galleryTitle,
        description: '',
        fileIds: folderFiles.map(f => f.id),
        createdAt: Date.now()
    };
    await saveShare(gallery);
    APP.shares.push(gallery);
    const galleryUrl = `${location.origin}${location.pathname}#/gallery/${galleryId}`;
    closeModal();
    // Show the gallery URL in a new modal
    openModal(`
        <div style="padding:24px;text-align:center">
            <div style="width:64px;height:64px;border-radius:16px;background:rgba(139,92,246,.1);display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
                <i class="fas fa-images" style="font-size:28px;color:#8b5cf6"></i>
            </div>
            <h3 style="font-size:18px;font-weight:600;margin-bottom:4px">${t('galleryCreated')}</h3>
            <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${folderFiles.length} ${APP.lang==='id'?'file':'files'}</p>
            <div style="margin-bottom:16px">
                <label style="font-size:12px;font-weight:500;margin-bottom:4px;display:block">${t('shareLink')}</label>
                <div style="display:flex;gap:6px">
                    <input type="text" class="input" id="gallery-url-input" aria-label="Gallery link" readonly style="font-size:12px;font-family:'JetBrains Mono',monospace" value="${galleryUrl}">
                    <button class="btn btn-primary btn-sm" onclick="copyShareLink('${galleryUrl}')" aria-label="Copy link"><i class="fas fa-copy"></i></button>
                </div>
            </div>
            <div class="qr-container">
                <div class="qr-canvas-wrap">
                    <canvas id="gallery-qr-canvas" width="200" height="200"></canvas>
                </div>
                <button class="btn btn-secondary btn-sm" onclick="downloadGalleryQR()"><i class="fas fa-download"></i> ${t('downloadQR')}</button>
            </div>
            <div style="display:flex;gap:8px;justify-content:center;margin-top:12px">
                <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
                <a href="#/gallery/${galleryId}" class="btn btn-primary" onclick="closeModal()"><i class="fas fa-external-link-alt"></i> ${t('viewGallery')}</a>
            </div>
        </div>`);
    // Generate QR for gallery (lazy-load QRious on demand)
    setTimeout(async () => {
        const qrCanvas = document.getElementById('gallery-qr-canvas');
        if (qrCanvas) {
            if (typeof QRious === 'undefined') { try { await window.LazyLibs.load('qrious'); } catch(e) {} }
            if (typeof QRious !== 'undefined') {
                try {
                    new QRious({
                        element: qrCanvas,
                        value: galleryUrl,
                        size: 200,
                        foreground: getComputedStyle(document.documentElement).getPropertyValue('--text').trim() || '#0f172a',
                        background: getComputedStyle(document.documentElement).getPropertyValue('--bg-secondary').trim() || '#f8fafc',
                        level: 'M'
                    });
                } catch(e) { console.warn('Gallery QR error:', e); }
            }
        }
    }, 100);
    showToast(t('galleryCreated'), 'success');
}

function downloadGalleryQR() {
    const canvas = document.getElementById('gallery-qr-canvas');
    if (!canvas) return;
    const link = document.createElement('a');
    link.download = 'ridgebox-gallery-qr.png';
    link.href = canvas.toDataURL('image/png');
    link.click();
    showToast(APP.lang==='id'?'QR Code diunduh':'QR Code downloaded', 'success');
}

// ===== UPLOAD PORTAL (F79, F104) =====
function renderUploadPortal(token) {
    const main = document.getElementById('app-main');
    if (!main) return;
    renderHeader();
    // Find collaborative folder by token
    const folder = APP.folders.find(f => f.shareToken === token);
    const folderName = folder ? folder.name : (APP.lang==='id'?'Unggah File':'Upload File');
    main.innerHTML = `<div class="page-transition" style="display:flex;align-items:center;justify-content:center;min-height:80vh">
        <div style="text-align:center;max-width:500px;padding:40px;width:100%">
            <div style="width:64px;height:64px;border-radius:16px;background:rgba(59,130,246,.1);display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
                <i class="fas fa-cloud-arrow-up" style="font-size:28px;color:var(--accent)"></i>
            </div>
            <h2>${t('uploadPortal')}</h2>
            <p style="color:var(--text-secondary);margin-bottom:24px">${folderName}</p>
            <div class="drop-zone" id="portal-drop-zone" style="padding:40px 20px;margin-bottom:16px;cursor:pointer" onclick="document.getElementById('portal-file-input').click()">
                <i class="fas fa-cloud-arrow-up" style="font-size:36px;color:var(--accent);margin-bottom:8px"></i>
                <p>${t('uploadDrop')}</p>
            </div>
            <input type="file" id="portal-file-input" multiple style="display:none" onchange="handlePortalUpload(this.files, '${folder ? folder.id : ''}')">
        </div>
    </div>`;
    // Setup drag & drop for portal
    const zone = document.getElementById('portal-drop-zone');
    if (zone) {
        zone.addEventListener('dragover', (e) => { e.preventDefault(); zone.classList.add('drag-over'); });
        zone.addEventListener('dragleave', () => zone.classList.remove('drag-over'));
        zone.addEventListener('drop', (e) => { e.preventDefault(); zone.classList.remove('drag-over'); if (e.dataTransfer.files.length) handlePortalUpload(e.dataTransfer.files, folder ? folder.id : ''); });
    }
}

async function handlePortalUpload(fileList, folderId) {
    for (const file of fileList) {
        await executeUpload(file, folderId || null);
    }
    showToast(t('uploaded'), 'success');
    haptic('uploadComplete');
    const _glowC3 = document.getElementById('file-list-container');
    if (_glowC3) { _glowC3.classList.add('success-glow'); setTimeout(() => _glowC3.classList.remove('success-glow'), 1000); }
}

// ===== PREVIEW (F6, F47, F63, F100, F101) =====
function openPreview(fileId) {
    haptic('tap');
    // F126: Use carousel preview for images/videos/audio/PDFs
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    const type = getFileType(file.name, file.mime);
    if (['image','video','audio','pdf'].includes(type)) {
        openPreviewCarousel(fileId);
        return;
    }
    // Original preview for docs, code, etc.
    updateLastAccessed(fileId);
    closeContextMenu();
    closeDetailPanel();
    const icon = getFileIcon(type);
    const isId = APP.lang === 'id';
    let previewContent = '';
    const downloadUrl = APP.settings.proxyMode !== false
        ? `/api/download?path=${encodeURIComponent(file.filePath)}&bot_index=${file.botIndex}`
        : `https://api.telegram.org/file/bot${APP.bots[0]?.token}/${file.filePath}`;
    if (type === 'document') {
        previewContent = `<div id="office-preview-container" style="min-height:200px">
            <div style="text-align:center;padding:40px"><div style="display:inline-block;width:32px;height:32px;border:3px solid var(--accent);border-top-color:transparent;border-radius:50%;animation:spin .8s linear infinite"></div><p style="margin-top:12px;color:var(--text-secondary);font-size:13px">${isId ? 'Memuat dokumen...' : 'Loading document...'}</p></div>
        </div>`;
        setTimeout(() => fetchDocxPreview(file, downloadUrl), 100);
    } else if (type === 'spreadsheet') {
        previewContent = `<div id="office-preview-container" style="min-height:200px">
            <div style="text-align:center;padding:40px"><div style="display:inline-block;width:32px;height:32px;border:3px solid var(--accent);border-top-color:transparent;border-radius:50%;animation:spin .8s linear infinite"></div><p style="margin-top:12px;color:var(--text-secondary);font-size:13px">${isId ? 'Memuat spreadsheet...' : 'Loading spreadsheet...'}</p></div>
        </div>`;
        setTimeout(() => fetchXlsxPreview(file, downloadUrl), 100);
    } else if (type === 'presentation') {
        previewContent = `<div style="text-align:center;padding:40px">
            <div style="width:80px;height:80px;border-radius:20px;background:#f9731615;display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
                <i class="fas fa-file-powerpoint" style="font-size:36px;color:#f97316"></i>
            </div>
            <p style="color:var(--text-secondary);margin-bottom:16px">${isId ? 'Pratinjau PowerPoint tidak tersedia' : 'PowerPoint preview not available'}</p>
            <button class="btn btn-primary" onclick="downloadFile('${file.id}');closeModal()"><i class="fas fa-download"></i> ${t('download')}</button>
        </div>`;
    } else if (type === 'code' || (file.name && file.name.endsWith('.md'))) {
        previewContent = `<div id="code-preview" style="background:var(--bg-secondary);border-radius:8px;padding:16px;font-family:'JetBrains Mono',monospace;font-size:13px;max-height:60vh;overflow:auto;white-space:pre-wrap;word-break:break-all"><div class="skeleton" style="height:200px"></div></div>`;
        fetchCodePreview(file, downloadUrl);
    } else {
        previewContent = `<div style="text-align:center;padding:40px">
            <div style="width:80px;height:80px;border-radius:20px;background:${icon.color}15;display:flex;align-items:center;justify-content:center;margin:0 auto 16px">
                <i class="fas ${icon.icon}" style="font-size:36px;color:${icon.color}"></i>
            </div>
            <p style="color:var(--text-secondary)">${APP.lang==='id'?'Pratinjau tidak tersedia untuk tipe file ini':'Preview not available for this file type'}</p>
        </div>`;
    }
    openModal(`
        <div style="padding:20px">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">
                <div style="display:flex;align-items:center;gap:8px">
                    <i class="fas ${icon.icon}" style="color:${icon.color}"></i>
                    <span style="font-weight:600;font-size:14px;max-width:300px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${file.name}</span>
                </div>
                <div style="display:flex;gap:4px">
                    <button class="btn btn-ghost btn-sm" onclick="downloadFile('${file.id}')" aria-label="Download"><i class="fas fa-download"></i></button>
                    <button class="btn btn-ghost btn-sm" onclick="closeModal()" aria-label="Close"><i class="fas fa-times"></i></button>
                </div>
            </div>
            ${previewContent}
            <div style="margin-top:12px;font-size:12px;color:var(--text-secondary);display:flex;justify-content:space-between">
                <span>${formatSize(file.size)} · ${type}</span>
                <span>${formatDate(file.uploadedAt)}</span>
            </div>
        </div>`);
}

async function fetchCodePreview(file, url) {
    try {
        const resp = await fetch(url);
        const text = await resp.text();
        const container = document.getElementById('code-preview');
        if (!container) return;
        if (file.name.endsWith('.md')) {
            // F100: Simple markdown rendering
            container.innerHTML = renderMarkdown(text);
            container.style.fontFamily = "'Space Grotesk', sans-serif";
        } else {
            container.textContent = text.substring(0, 50000);
        }
    } catch (e) {
        const container = document.getElementById('code-preview');
        if (container) container.textContent = 'Failed to load preview';
    }
}

// ===== Feature 5: Office Document Preview (.docx, .xlsx) =====
async function fetchDocxPreview(file, url) {
    const container = document.getElementById('office-preview-container');
    if (!container) return;
    const isId = APP.lang === 'id';
    try {
        // Lazy-load mammoth.js on demand
        if (typeof mammoth === 'undefined') {
            container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-spinner fa-spin" style="font-size:24px;color:var(--accent)"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Memuat pustaka dokumen...' : 'Loading document library...'}</p></div>`;
            try { await window.LazyLibs.load('mammoth'); } catch(e) {
                container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-exclamation-triangle" style="font-size:24px;color:#f59e0b"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Gagal memuat pustaka dokumen' : 'Failed to load document library'}</p></div>`;
                return;
            }
        }
        const resp = await fetch(url);
        if (!resp.ok) throw new Error('Download failed');
        const blob = await resp.blob();
        const arrayBuffer = await blob.arrayBuffer();
        const result = await mammoth.convertToHtml({ arrayBuffer });
        container.innerHTML = `<div style="padding:20px;max-height:60vh;overflow:auto;background:var(--bg-secondary);border-radius:8px;line-height:1.7;font-size:14px">${result.value || '<p style="color:var(--text-secondary)">' + (isId ? 'Dokumen kosong' : 'Empty document') + '</p>'}</div>`;
        if (result.messages && result.messages.length > 0) {
            console.warn('mammoth warnings:', result.messages);
        }
    } catch (e) {
        container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-exclamation-circle" style="font-size:24px;color:#ef4444"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Gagal memuat dokumen' : 'Failed to load document'}</p><button class="btn btn-primary btn-sm" style="margin-top:12px" onclick="downloadFile('${file.id}');closeModal()"><i class="fas fa-download"></i> ${t('download')}</button></div>`;
    }
}

async function fetchXlsxPreview(file, url) {
    const container = document.getElementById('office-preview-container');
    if (!container) return;
    const isId = APP.lang === 'id';
    try {
        // Lazy-load XLSX on demand
        if (typeof XLSX === 'undefined') {
            container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-spinner fa-spin" style="font-size:24px;color:var(--accent)"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Memuat pustaka spreadsheet...' : 'Loading spreadsheet library...'}</p></div>`;
            try { await window.LazyLibs.load('xlsx'); } catch(e) {
                container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-exclamation-triangle" style="font-size:24px;color:#f59e0b"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Gagal memuat pustaka spreadsheet' : 'Failed to load spreadsheet library'}</p></div>`;
                return;
            }
        }
        const resp = await fetch(url);
        if (!resp.ok) throw new Error('Download failed');
        const blob = await resp.blob();
        const arrayBuffer = await blob.arrayBuffer();
        const workbook = XLSX.read(arrayBuffer, { type: 'array' });
        const firstSheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[firstSheetName];
        const htmlTable = XLSX.utils.sheet_to_html(worksheet, { editable: false });
        const sheetTabs = workbook.SheetNames.map((name, i) => 
            `<button class="btn ${i === 0 ? 'btn-primary' : 'btn-secondary'} btn-sm" style="font-size:11px" onclick="switchXlsxSheet(this, '${file.id}', ${i})">${name}</button>`
        ).join(' ');
        container.innerHTML = `<div>
            <div style="display:flex;gap:4px;flex-wrap:wrap;margin-bottom:8px">${sheetTabs}</div>
            <div id="xlsx-table-container" style="max-height:55vh;overflow:auto;background:var(--bg-secondary);border-radius:8px;padding:8px">${htmlTable}</div>
        </div>`;
        // Style the table
        const tableEl = container.querySelector('table');
        if (tableEl) {
            tableEl.style.width = '100%';
            tableEl.style.borderCollapse = 'collapse';
            tableEl.style.fontSize = '12px';
            tableEl.querySelectorAll('td, th').forEach(cell => {
                cell.style.border = '1px solid var(--border)';
                cell.style.padding = '4px 8px';
                cell.style.textAlign = 'left';
            });
            tableEl.querySelectorAll('th').forEach(cell => {
                cell.style.background = 'var(--bg)';
                cell.style.fontWeight = '600';
            });
        }
        // Store workbook in memory for sheet switching
        window._xlsxWorkbook = workbook;
    } catch (e) {
        container.innerHTML = `<div style="text-align:center;padding:40px"><i class="fas fa-exclamation-circle" style="font-size:24px;color:#ef4444"></i><p style="margin-top:8px;color:var(--text-secondary)">${isId ? 'Gagal memuat spreadsheet' : 'Failed to load spreadsheet'}</p><button class="btn btn-primary btn-sm" style="margin-top:12px" onclick="downloadFile('${file.id}');closeModal()"><i class="fas fa-download"></i> ${t('download')}</button></div>`;
    }
}

function switchXlsxSheet(btn, fileId, sheetIndex) {
    const container = document.getElementById('xlsx-table-container');
    if (!container || !window._xlsxWorkbook) return;
    const workbook = window._xlsxWorkbook;
    const sheetName = workbook.SheetNames[sheetIndex];
    const worksheet = workbook.Sheets[sheetName];
    const htmlTable = XLSX.utils.sheet_to_html(worksheet, { editable: false });
    container.innerHTML = htmlTable;
    // Style the table
    const tableEl = container.querySelector('table');
    if (tableEl) {
        tableEl.style.width = '100%';
        tableEl.style.borderCollapse = 'collapse';
        tableEl.style.fontSize = '12px';
        tableEl.querySelectorAll('td, th').forEach(cell => {
            cell.style.border = '1px solid var(--border)';
            cell.style.padding = '4px 8px';
            cell.style.textAlign = 'left';
        });
        tableEl.querySelectorAll('th').forEach(cell => {
            cell.style.background = 'var(--bg)';
            cell.style.fontWeight = '600';
        });
    }
    // Update active tab
    const tabs = btn.parentElement.querySelectorAll('button');
    tabs.forEach((t, i) => { t.className = `btn ${i === sheetIndex ? 'btn-primary' : 'btn-secondary'} btn-sm`; t.style.fontSize = '11px'; });
}

function renderMarkdown(md) { // F100
    let html = md
        .replace(/^### (.+)$/gm, '<h3 style="font-size:16px;font-weight:600;margin:12px 0 4px">$1</h3>')
        .replace(/^## (.+)$/gm, '<h2 style="font-size:18px;font-weight:700;margin:16px 0 6px">$1</h2>')
        .replace(/^# (.+)$/gm, '<h1 style="font-size:22px;font-weight:700;margin:20px 0 8px">$1</h1>')
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\*(.+?)\*/g, '<em>$1</em>')
        .replace(/`(.+?)`/g, '<code style="background:var(--bg);padding:2px 4px;border-radius:3px;font-family:JetBrains Mono,monospace;font-size:12px">$1</code>')
        .replace(/^- (.+)$/gm, '<li style="margin-left:16px">$1</li>')
        .replace(/^> (.+)$/gm, '<blockquote style="border-left:3px solid var(--accent);padding-left:12px;color:var(--text-secondary)">$1</blockquote>')
        .replace(/\n/g, '<br>');
    return html;
}

function generateWaveform(audioEl) { // F63
    const container = document.getElementById('waveform-container');
    if (!container || !audioEl) return;
    const barCount = 50;
    container.innerHTML = '';
    for (let i = 0; i < barCount; i++) {
        const bar = document.createElement('div');
        bar.className = 'waveform-bar';
        bar.style.height = Math.random() * 40 + 10 + 'px';
        container.appendChild(bar);
    }
    // Animate waveform on play
    audioEl.addEventListener('play', () => {
        const bars = container.querySelectorAll('.waveform-bar');
        const animate = () => {
            if (audioEl.paused) return;
            bars.forEach(bar => { bar.style.height = Math.random() * 50 + 5 + 'px'; });
            requestAnimationFrame(animate);
        };
        animate();
    });
}

// ===== COMPARE FILES (F57) =====
function openCompareModal() {
    if (APP.selectedFiles.size !== 2) {
        showToast(t('selectTwo'), 'warning');
        return;
    }
    const ids = [...APP.selectedFiles];
    const fileA = APP.files.find(f => f.id === ids[0]);
    const fileB = APP.files.find(f => f.id === ids[1]);
    if (!fileA || !fileB) return;
    const identical = fileA.name === fileB.name && fileA.size === fileB.size;
    openModal(`
        <div style="padding:24px">
            <h3 style="font-size:18px;font-weight:600;margin-bottom:16px"><i class="fas fa-columns" style="color:var(--accent)"></i> ${t('compareFiles')}</h3>
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
                ${[fileA, fileB].map(f => {
                    const type = getFileType(f.name, f.mime);
                    const icon = getFileIcon(type);
                    return `<div style="padding:16px;background:var(--bg-secondary);border-radius:8px">
                        <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
                            <i class="fas ${icon.icon}" style="color:${icon.color}"></i>
                            <span style="font-weight:500;font-size:13px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${f.name}</span>
                        </div>
                        <div style="font-size:12px;color:var(--text-secondary)">
                            <div>${t('sortBySize')}: ${formatSize(f.size)}</div>
                            <div>${t('sortByDate')}: ${formatDate(f.uploadedAt)}</div>
                            <div>${t('sortById')}: ${type}</div>
                            <div>${t('version')}: v${f.version || 1}</div>
                        </div>
                    </div>`;
                }).join('')}
            </div>
            <div style="text-align:center;margin-top:16px;padding:12px;background:${identical?'#10b98115':'#f59e0b15'};border-radius:8px">
                <i class="fas fa-${identical?'check-circle':'exclamation-triangle'}" style="color:${identical?'#10b981':'#f59e0b'}"></i>
                ${identical ? t('identical') : t('difference')}
            </div>
            <div style="display:flex;gap:8px;justify-content:flex-end;margin-top:16px">
                <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
            </div>
        </div>`);
}

// ===== FILE DETAIL PAGE (Route #/file/xxx) =====
function renderFileDetail(fileId) {
    const main = document.getElementById('app-main');
    if (!main) return;
    renderHeader();
    const file = APP.files.find(f => f.id === fileId);
    if (!file) {
        main.innerHTML = render404Content();
        return;
    }
    const type = getFileType(file.name, file.mime);
    const icon = getFileIcon(type);
    const versions = APP.files.filter(f => f.name === file.name && f.folderId === file.folderId && !f.trashed);
    main.innerHTML = `<div class="page-transition" style="max-width:800px;margin:0 auto;padding:24px">
        <a href="#/dashboard" style="display:inline-flex;align-items:center;gap:6px;color:var(--accent);text-decoration:none;font-size:14px;margin-bottom:16px"><i class="fas fa-arrow-left"></i> ${t('backToHome')}</a>
        <div style="display:flex;gap:20px;flex-wrap:wrap">
            <div style="flex:1;min-width:300px">
                <div style="display:flex;align-items:center;gap:12px;margin-bottom:16px">
                    <div style="width:56px;height:56px;border-radius:14px;background:${icon.color}15;display:flex;align-items:center;justify-content:center">
                        <i class="fas ${icon.icon}" style="font-size:24px;color:${icon.color}"></i>
                    </div>
                    <div>
                        <h1 style="font-size:20px;font-weight:600">${file.name}</h1>
                        <p style="font-size:13px;color:var(--text-secondary)">${formatSize(file.size)} · ${type} · ${formatDate(file.uploadedAt)}</p>
                    </div>
                </div>
                ${file.caption ? `<div style="padding:12px;background:var(--bg-secondary);border-radius:8px;margin-bottom:16px;font-size:14px">${file.caption}</div>` : ''}
                <div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:20px">
                    <button class="btn btn-primary" onclick="openPreview('${file.id}')"><i class="fas fa-eye"></i> ${t('preview')}</button>
                    <button class="btn btn-secondary" onclick="downloadFile('${file.id}')"><i class="fas fa-download"></i> ${t('download')}</button>
                    <button class="btn btn-secondary" onclick="openShareModal('${file.id}')"><i class="fas fa-share-alt"></i> ${t('share')}</button>
                    <button class="btn btn-ghost" onclick="toggleStar('${file.id}')" aria-label="Toggle star"><i class="fas fa-star" style="color:${file.starred?'#f59e0b':'inherit'}"></i></button>
                    <button class="btn btn-ghost" onclick="togglePin('${file.id}')" aria-label="Toggle pin"><i class="fas fa-thumbtack" style="color:${file.pinned?'var(--accent)':'inherit'}"></i></button>
                    ${!file.trashed ? `<button class="btn btn-danger" onclick="moveToTrash('${file.id}')"><i class="fas fa-trash"></i> ${t('delete')}</button>` : `<button class="btn btn-secondary" onclick="restoreFile('${file.id}')"><i class="fas fa-undo"></i> ${t('restore')}</button> <button class="btn btn-danger" onclick="deletePermanently('${file.id}')"><i class="fas fa-times-circle"></i> ${t('delete')}</button>`}
                </div>
            </div>
            <div style="width:260px">
                <div style="padding:16px;background:var(--bg-secondary);border-radius:8px;margin-bottom:12px">
                    <h4 style="font-size:13px;font-weight:600;margin-bottom:8px">${t('versionHistory')}</h4>
                    ${versions.map(v => `
                        <div style="display:flex;align-items:center;gap:6px;padding:4px 0;font-size:12px;color:${v.id === file.id ? 'var(--accent)' : 'var(--text-secondary)'}">
                            <i class="fas fa-file" style="font-size:10px"></i>
                            v${v.version || 1} · ${formatSize(v.size)} · ${formatDate(v.uploadedAt)}
                        </div>
                    `).join('') || '<div style="font-size:12px;color:var(--text-secondary)">v1</div>'}
                </div>
                <div style="padding:16px;background:var(--bg-secondary);border-radius:8px">
                    <h4 style="font-size:13px;font-weight:600;margin-bottom:8px">${t('shareStats')}</h4>
                    ${(() => {
                        const fileShares = APP.shares.filter(s => s.fileId === file.id && s.type !== 'gallery');
                        const totalDls = fileShares.reduce((sum, s) => sum + (s.downloadCount || 0), 0);
                        const totalClks = fileShares.reduce((sum, s) => sum + (s.clicks || 0), 0);
                        const lastAcc = fileShares.reduce((max, s) => Math.max(max, s.lastAccess || s.lastAccessedAt || 0), 0);
                        return `
                        <div class="share-analytics-grid" style="margin-top:4px">
                            <div class="share-analytics-card accent">
                                <div class="sa-icon"><i class="fas fa-link"></i></div>
                                <div class="sa-number">${fileShares.length}</div>
                                <div class="sa-label">${t('totalShares')}</div>
                            </div>
                            <div class="share-analytics-card green">
                                <div class="sa-icon"><i class="fas fa-download"></i></div>
                                <div class="sa-number">${totalDls}</div>
                                <div class="sa-label">${t('totalDownloads')}</div>
                            </div>
                        </div>
                        ${lastAcc > 0 ? `<div style="font-size:11px;color:var(--text-secondary);margin-top:6px"><i class="fas fa-clock" style="font-size:9px"></i> ${t('lastAccessed')}: ${formatDate(lastAcc)}</div>` : ''}`;
                    })()}
                </div>
                ${file.tag ? `<div style="margin-top:12px"><span class="badge" style="background:${file.tag}20;color:${file.tag};cursor:pointer" onclick="toggleTagFilter('${file.tag}')"><span class="tag-dot" style="background:${file.tag};margin-right:4px;width:8px;height:8px"></span>${type}</span></div>` : ''}
                ${file.encrypted ? `<div style="margin-top:8px"><span class="badge" style="background:#3b82f620;color:#3b82f6"><i class="fas fa-lock" style="margin-right:4px"></i>${t('encrypted')}</span></div>` : ''}
            </div>
        </div>
    </div>`;
}


