function scheduleUpload() { // F80
    const timeInput = document.getElementById('scheduled-time');
    if (!timeInput || !timeInput.value) return;
    const scheduledTime = new Date(timeInput.value).getTime();
    if (scheduledTime <= Date.now()) { showToast(APP.lang==='id'?'Waktu harus di masa depan':'Time must be in the future', 'warning'); return; }
    const delay = scheduledTime - Date.now();
    const timerId = setTimeout(() => {
        showToast(APP.lang==='id'?'Unggah terjadwal siap!':'Scheduled upload ready!', 'info');
        sendNotification('Ridgebox', APP.lang==='id'?'Unggah terjadwal siap':'Scheduled upload ready');
    }, delay);
    APP.scheduledUploads.push({ id: genId(), time: scheduledTime, timerId });
    localStorage.setItem('rb_scheduled', JSON.stringify(APP.scheduledUploads.map(s => ({ id: s.id, time: s.time }))));
    showToast(t('scheduledUpload') + ' <i class="fas fa-check" style="font-size:11px"></i>', 'success');
}

function restoreScheduledUploads() { // F80
    try {
        const saved = JSON.parse(localStorage.getItem('rb_scheduled') || '[]');
        saved.forEach(s => {
            const delay = s.time - Date.now();
            if (delay > 0) {
                const timerId = setTimeout(() => {
                    showToast(APP.lang==='id'?'Unggah terjadwal siap!':'Scheduled upload ready!', 'info');
                }, delay);
                APP.scheduledUploads.push({ id: s.id, time: s.time, timerId });
            }
        });
    } catch(e) {}
}

// ===== STORAGE ANALYTICS (F85) =====
function openStorageAnalytics() {
    haptic('tap');
    const totalFiles = APP.files.filter(f => !f.trashed).length;
    const totalSize = APP.files.filter(f => !f.trashed).reduce((sum, f) => sum + (f.size || 0), 0);
    const quotaLimit = getStorageLimitBytes();
    const botCount = Math.max(APP.bots.length || 1, 1);
    const isId = APP.lang === 'id';
    const typeStats = {};
    APP.files.filter(f => !f.trashed).forEach(f => {
        const type = getFileType(f.name, f.mime);
        typeStats[type] = (typeStats[type] || 0) + (f.size || 0);
    });
    const topFiles = [...APP.files].filter(f => !f.trashed).sort((a, b) => (b.size || 0) - (a.size || 0)).slice(0, 5);
    const days = {};
    APP.files.forEach(f => {
        const d = new Date(f.uploadedAt).toLocaleDateString(APP.lang === 'id' ? 'id-ID' : 'en-US', { weekday: 'short' });
        days[d] = (days[d] || 0) + 1;
    });

    openModal(`
        <div style="padding:24px;max-width:560px">
            <h3 style="font-size:18px;font-weight:600;margin-bottom:20px"><i class="fas fa-chart-pie" style="color:var(--accent)"></i> ${t('storageAnalytics')}</h3>
            
            <!-- Summary Cards -->
            <div style="display:grid;grid-template-columns:1fr 1fr 1fr 1fr;gap:12px;margin-bottom:20px">
                <div style="padding:12px;background:var(--bg-secondary);border-radius:8px;text-align:center">
                    <div style="font-size:20px;font-weight:700;color:var(--accent)">${totalFiles}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${isId?'Total File':'Total Files'}</div>
                </div>
                <div style="padding:12px;background:var(--bg-secondary);border-radius:8px;text-align:center">
                    <div style="font-size:20px;font-weight:700;color:#10b981">${formatSize(totalSize)}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${t('storage')}</div>
                </div>
                <div style="padding:12px;background:var(--bg-secondary);border-radius:8px;text-align:center">
                    <div style="font-size:20px;font-weight:700;color:#8b5cf6">${formatSize(quotaLimit)}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${isId?'Kuota':'Quota'}</div>
                </div>
                <div style="padding:12px;background:var(--bg-secondary);border-radius:8px;text-align:center">
                    <div style="font-size:20px;font-weight:700;color:#f59e0b">${botCount}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${isId?'Bot Aktif':'Active Bots'}</div>
                </div>
            </div>
            <div style="padding:10px 12px;background:var(--bg-secondary);border-radius:8px;margin-bottom:16px;font-size:12px;color:var(--text-secondary)">
                <i class="fas fa-info-circle" style="color:var(--accent)"></i> ${isId?`Kuota: ${botCount} bot × 2 GB = ${formatSize(quotaLimit)}`:`Quota: ${botCount} bot(s) × 2 GB = ${formatSize(quotaLimit)}`}
            </div>

            <!-- Type Distribution (Donut) -->
            <div style="margin-bottom:20px">
                <h4 style="font-size:13px;font-weight:600;margin-bottom:8px">${APP.lang==='id'?'Distribusi Tipe':'Type Distribution'}</h4>
                <div style="display:flex;flex-wrap:wrap;gap:8px">
                    ${Object.entries(typeStats).map(([type, size]) => {
                        const icon = getFileIcon(type);
                        const pct = totalSize > 0 ? Math.round(size / totalSize * 100) : 0;
                        return `<div style="display:flex;align-items:center;gap:6px;padding:6px 10px;background:var(--bg-secondary);border-radius:6px;font-size:12px">
                            <i class="fas ${icon.icon}" style="color:${icon.color}"></i>
                            <span>${type}</span>
                            <span style="color:var(--text-secondary)">${pct}%</span>
                            <div style="width:40px;height:4px;background:var(--border);border-radius:2px;overflow:hidden"><div class="analytics-bar" style="height:100%;width:0;--bar-w:${pct}%;background:${icon.color};border-radius:2px"></div></div>
                        </div>`;
                    }).join('')}
                </div>
            </div>

            <!-- Activity Heatmap -->
            <div style="margin-bottom:20px">
                <h4 style="font-size:13px;font-weight:600;margin-bottom:8px">${APP.lang==='id'?'Aktivitas':'Activity'}</h4>
                <div style="display:flex;gap:4px;align-items:flex-end">
                    ${Object.entries(days).map(([day, count]) => `
                        <div style="flex:1;text-align:center">
                            <div style="height:${Math.max(4, count * 8)}px;background:var(--accent);border-radius:2px;margin-bottom:4px;opacity:${Math.min(1, count / 5)}"></div>
                            <span style="font-size:9px;color:var(--text-secondary)">${day}</span>
                        </div>
                    `).join('')}
                </div>
            </div>

            <!-- Top Files -->
            <div style="margin-bottom:16px">
                <h4 style="font-size:13px;font-weight:600;margin-bottom:8px">${APP.lang==='id'?'File Terbesar':'Top Files'}</h4>
                ${topFiles.map((f, i) => {
                    const type = getFileType(f.name, f.mime);
                    const icon = getFileIcon(type);
                    return `<div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border);font-size:12px">
                        <span style="color:var(--text-secondary);width:16px">${i + 1}</span>
                        <i class="fas ${icon.icon}" style="color:${icon.color};width:14px"></i>
                        <span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${f.name}</span>
                        <span style="color:var(--text-secondary)">${formatSize(f.size)}</span>
                    </div>`;
                }).join('')}
            </div>

            <div style="display:flex;justify-content:space-between;align-items:center">
                <button class="btn btn-secondary" onclick="findDuplicateFiles()" style="display:flex;align-items:center;gap:6px"><i class="fas fa-clone"></i> ${isId ? 'Cari Duplikat' : 'Find Duplicates'}</button>
                <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
            </div>
        </div>`);
}

// ===== 2FA / TOTP AUTHENTICATION (F106) =====
let _totpSecret = null;
let _totpVerified = false;

function generateTOTPSecret() {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567'; // Base32
    let secret = '';
    const arr = new Uint8Array(20);
    crypto.getRandomValues(arr);
    for (let i = 0; i < 20; i++) secret += chars[arr[i] % 32];
    return secret;
}

function getTOTPUri(secret) {
    const account = APP.user?.email || 'ridgebox@user';
    return `otpauth://totp/RidgeBox:${account}?secret=${secret}&issuer=RidgeBox&algorithm=SHA1&digits=6&period=30`;
}

async function setup2FA() {
    const isId = APP.lang === 'id';
    if (!APP.supabase || !isLoggedIn()) {
        showToast(isId ? 'Login diperlukan untuk 2FA' : 'Login required for 2FA', 'warning');
        return;
    }
    const secret = generateTOTPSecret();
    _totpSecret = secret;
    const uri = getTOTPUri(secret);
    // Generate QR code (lazy-load QRious on demand)
    let qrDataUrl = '';
    if (typeof QRious === 'undefined') { try { await window.LazyLibs.load('qrious'); } catch(e) {} }
    try { const qr = new QRious({ value: uri, size: 200, background: 'var(--bg)', foreground: 'var(--text)', level: 'M' }); qrDataUrl = qr.toDataURL(); } catch(e) { qrDataUrl = ''; }
    openModal(`<div style="padding:24px;text-align:center">
        <div style="width:56px;height:56px;border-radius:50%;background:rgba(139,92,246,.1);display:flex;align-items:center;justify-content:center;margin:0 auto 16px"><i class="fas fa-shield-halved" style="color:#8b5cf6;font-size:22px"></i></div>
        <h3 style="font-size:18px;font-weight:700;margin-bottom:4px">${isId ? 'Setup 2FA' : 'Setup 2FA'}</h3>
        <p style="font-size:12px;color:var(--text-secondary);margin-bottom:16px">${isId ? 'Scan QR code dengan app authenticator (Google Authenticator, Authy)' : 'Scan QR code with authenticator app (Google Authenticator, Authy)'}</p>
        ${qrDataUrl ? `<img src="${qrDataUrl}" style="border-radius:12px;border:1px solid var(--border);margin:0 auto 16px;display:block" alt="2FA QR">` : ''}
        <div style="background:var(--bg-secondary);border-radius:8px;padding:10px 14px;margin-bottom:16px;font-family:'JetBrains Mono',monospace;font-size:13px;word-break:break-all;user-select:all">${secret}</div>
        <p style="font-size:11px;color:var(--text-secondary);margin-bottom:12px">${isId ? 'Masukkan kode 6 digit dari app authenticator:' : 'Enter 6-digit code from authenticator app:'}</p>
        <div style="display:flex;gap:6px;justify-content:center;margin-bottom:16px">
            <input type="text" id="totp-verify-code" class="input" aria-label="Verification code" style="width:160px;text-align:center;font-family:'JetBrains Mono',monospace;font-size:18px;letter-spacing:6px" maxlength="6" placeholder="000000" oninput="this.value=this.value.replace(/\\D/g,'')">
        </div>
        <div style="display:flex;gap:8px;justify-content:center">
            <button class="btn btn-secondary" onclick="closeModal()">${isId ? 'Batal' : 'Cancel'}</button>
            <button class="btn btn-primary" onclick="verifyAndEnable2FA()">${isId ? 'Aktifkan 2FA' : 'Enable 2FA'}</button>
        </div>
    </div>`);
}

async function verifyAndEnable2FA() {
    const isId = APP.lang === 'id';
    const code = document.getElementById('totp-verify-code')?.value;
    if (!code || code.length !== 6) { showToast(isId ? 'Kode harus 6 digit' : 'Code must be 6 digits', 'warning'); return; }
    // Verify TOTP code
    const valid = await verifyTOTP(_totpSecret, code);
    if (valid) {
        APP.settings.totpSecret = _totpSecret;
        APP.settings.totpEnabled = true;
        await updateSetting('totpSecret', _totpSecret);
        await updateSetting('totpEnabled', true);
        // Generate recovery codes
        const recoveryCodes = generateRecoveryCodes(8);
        _pendingRecoveryCodes = recoveryCodes;
        await storeRecoveryCodes(recoveryCodes);
        closeModal();
        showToast(isId ? '2FA berhasil diaktifkan!' : '2FA enabled successfully!', 'success');
        // Show recovery codes modal
        setTimeout(() => showRecoveryCodesModal(recoveryCodes, true), 400);
    } else {
        showToast(isId ? 'Kode salah, coba lagi' : 'Invalid code, try again', 'error');
    }
}

async function verifyTOTP(secret, code) {
    // Simple TOTP verification using Web Crypto
    try {
        const key = base32Decode(secret);
        const timeStep = Math.floor(Date.now() / 30000);
        for (let offset = -1; offset <= 1; offset++) {
            const step = timeStep + offset;
            const timeBuf = new ArrayBuffer(8);
            const view = new DataView(timeBuf);
            view.setBigUint64(0, BigInt(step));
            const cryptoKey = await crypto.subtle.importKey('raw', key, { name: 'HMAC', hash: 'SHA-1' }, false, ['sign']);
            const hmac = await crypto.subtle.sign('HMAC', cryptoKey, timeBuf);
            const hmacArr = new Uint8Array(hmac);
            const offsetByte = hmacArr[hmacArr.length - 1] & 0xf;
            const otp = ((hmacArr[offsetByte] & 0x7f) << 24 | (hmacArr[offsetByte+1] & 0xff) << 16 | (hmacArr[offsetByte+2] & 0xff) << 8 | (hmacArr[offsetByte+3] & 0xff)) % 1000000;
            if (String(otp).padStart(6, '0') === code) return true;
        }
    } catch(e) { console.error('TOTP verify error:', e); }
    return false;
}

function base32Decode(str) {
    const alphabet = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567';
    let bits = '', bytes = [];
    for (const c of str) { const val = alphabet.indexOf(c.toUpperCase()); if (val === -1) continue; bits += val.toString(2).padStart(5, '0'); }
    for (let i = 0; i + 8 <= bits.length; i += 8) bytes.push(parseInt(bits.substr(i, 8), 2));
    return new Uint8Array(bytes);
}

