// Pull-to-refresh
let _pullStartY = 0, _pulling = false;
document.addEventListener('touchstart', e => {
    if (window.scrollY === 0 && location.hash.startsWith('#/dashboard')) _pullStartY = e.touches[0].clientY;
}, { passive: true });
document.addEventListener('touchmove', e => {
    if (_pullStartY > 0 && e.touches[0].clientY - _pullStartY > 80 && !_pulling && window.scrollY === 0) {
        _pulling = true;
        showToast(APP.lang === 'id' ? 'Menyegarkan...' : 'Refreshing...', 'info', 2000);
        setTimeout(() => { checkUrlRouting(); _pulling = false; _pullStartY = 0; }, 1000);
    }
}, { passive: true });
document.addEventListener('touchend', () => { _pullStartY = 0; }, { passive: true });

// ===== DRAG & DROP ENHANCEMENT (F119) =====
function initEnhancedDragDrop() {
    const main = document.getElementById('app-main');
    if (!main) return;
    let dragCounter = 0;
    let overlay = null;

    main.addEventListener('dragenter', e => {
        e.preventDefault();
        dragCounter++;
        if (!overlay) {
            overlay = document.createElement('div');
            overlay.id = 'drag-overlay';
            overlay.style.cssText = 'position:fixed;inset:0;z-index:500;background:rgba(59,130,246,.08);backdrop-filter:blur(4px);display:flex;align-items:center;justify-content:center;pointer-events:none';
            overlay.innerHTML = `<div style="background:var(--bg-card);border:2px dashed var(--accent);border-radius:20px;padding:40px 60px;text-align:center;animation:fadeIn .2s ease">
                <i class="fas fa-cloud-arrow-up" style="font-size:48px;color:var(--accent);margin-bottom:12px;display:block"></i>
                <div style="font-size:18px;font-weight:700;color:var(--text)">${APP.lang==='id'?'Lepas untuk Mengunggah':'Drop to Upload'}</div>
                <div style="font-size:13px;color:var(--text-secondary);margin-top:4px">${APP.lang==='id'?'File akan diunggah ke folder saat ini':'Files will be uploaded to current folder'}</div>
            </div>`;
            document.body.appendChild(overlay);
        }
    });
    main.addEventListener('dragleave', e => { e.preventDefault(); dragCounter--; if (dragCounter <= 0) { dragCounter = 0; overlay?.remove(); overlay = null; } });
    main.addEventListener('dragover', e => e.preventDefault());
    main.addEventListener('drop', e => {
        e.preventDefault();
        dragCounter = 0;
        overlay?.remove();
        overlay = null;
        if (e.dataTransfer?.files?.length > 0) {
            Array.from(e.dataTransfer.files).forEach(f => executeUpload(f));
        }
    });
}

// ===== ENHANCED FILE TAGGING (F120) =====
const CUSTOM_TAG_COLORS = [
    { name: 'Red', color: '#ef4444' }, { name: 'Orange', color: '#f97316' },
    { name: 'Amber', color: '#f59e0b' }, { name: 'Green', color: '#10b981' },
    { name: 'Cyan', color: '#06b6d4' }, { name: 'Blue', color: '#3b82f6' },
    { name: 'Purple', color: '#8b5cf6' }, { name: 'Pink', color: '#ec4899' }
];

function openTagManager(fileId) {
    const isId = APP.lang === 'id';
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    const customTags = JSON.parse(localStorage.getItem('rb_custom_tags') || '[]');
    openModal(`<div style="padding:24px">
        <h3 style="font-size:16px;font-weight:600;margin-bottom:16px"><i class="fas fa-tags" style="color:var(--accent);margin-right:6px"></i>${isId ? 'Kelola Tag' : 'Manage Tags'}</h3>
        <div style="margin-bottom:16px">
            <div style="font-size:12px;font-weight:600;color:var(--text-secondary);margin-bottom:8px">${isId ? 'TAG CEPAT' : 'QUICK TAGS'}</div>
            <div style="display:flex;gap:8px;flex-wrap:wrap">
                ${CUSTOM_TAG_COLORS.map(c => `<div onclick="setFileTag('${fileId}','${c.color}');closeModal()" style="display:flex;align-items:center;gap:6px;padding:6px 12px;border-radius:99px;border:2px solid ${file.tag === c.color ? c.color : 'var(--border)'};cursor:pointer;background:${file.tag === c.color ? c.color + '15' : 'transparent'};transition:all .15s" onmouseover="this.style.borderColor='${c.color}'" onmouseout="this.style.borderColor='${file.tag === c.color ? c.color : 'var(--border)'}'">
                    <div style="width:12px;height:12px;border-radius:50%;background:${c.color}"></div>
                    <span style="font-size:12px;font-weight:500">${c.name}</span>
                </div>`).join('')}
            </div>
        </div>
        <div style="margin-bottom:16px">
            <div style="font-size:12px;font-weight:600;color:var(--text-secondary);margin-bottom:8px">${isId ? 'TAG KUSTOM' : 'CUSTOM TAGS'}</div>
            <div style="display:flex;gap:8px;margin-bottom:8px">
                <input type="text" id="custom-tag-name" class="input" aria-label="Tag name" placeholder="${isId ? 'Nama tag...' : 'Tag name...'}" style="flex:1">
                <input type="color" id="custom-tag-color" value="#3b82f6" style="width:36px;height:36px;border:none;border-radius:8px;cursor:pointer;background:none">
                <button class="btn btn-primary btn-sm" onclick="addCustomTag()" aria-label="Add tag"><i class="fas fa-plus"></i></button>
            </div>
            ${customTags.map(t => `<div style="display:inline-flex;align-items:center;gap:6px;padding:4px 10px;border-radius:99px;background:${t.color}15;border:1px solid ${t.color}30;margin:2px">
                <div style="width:8px;height:8px;border-radius:50%;background:${t.color}"></div>
                <span style="font-size:11px;font-weight:500">${t.name}</span>
                <button style="background:none;border:none;cursor:pointer;color:var(--text-secondary);font-size:10px;padding:0 2px" onclick="removeCustomTag('${t.id}')" aria-label="Remove tag"><i class="fas fa-times"></i></button>
            </div>`).join('')}
        </div>
        ${file.tag ? `<div style="margin-bottom:12px"><div style="font-size:12px;font-weight:600;color:var(--text-secondary);margin-bottom:8px">${isId ? 'TAG SAAT INI' : 'CURRENT TAG'}</div>
            <div style="display:inline-flex;align-items:center;gap:6px;padding:6px 12px;border-radius:99px;background:${file.tag}15;border:1px solid ${file.tag}30">
                <div style="width:10px;height:10px;border-radius:50%;background:${file.tag}"></div>
                <span style="font-size:12px;font-weight:500">${CUSTOM_TAG_COLORS.find(c=>c.color===file.tag)?.name || 'Custom'}</span>
                <button style="background:none;border:none;cursor:pointer;color:#ef4444;font-size:11px;padding:0 4px" onclick="setFileTag('${fileId}','');closeModal()" aria-label="Remove tag"><i class="fas fa-times"></i></button>
            </div>
        </div>` : ''}
        <div style="display:flex;justify-content:flex-end"><button class="btn btn-secondary" onclick="closeModal()">${isId ? 'Tutup' : 'Close'}</button></div>
    </div>`);
}

function addCustomTag() {
    const name = document.getElementById('custom-tag-name')?.value;
    const color = document.getElementById('custom-tag-color')?.value;
    if (!name) return;
    const tags = JSON.parse(localStorage.getItem('rb_custom_tags') || '[]');
    tags.push({ id: genId(), name, color });
    localStorage.setItem('rb_custom_tags', JSON.stringify(tags));
    openTagManager(APP.selectedFiles.values().next().value); // Refresh
}

function removeCustomTag(tagId) {
    const tags = JSON.parse(localStorage.getItem('rb_custom_tags') || '[]').filter(t => t.id !== tagId);
    localStorage.setItem('rb_custom_tags', JSON.stringify(tags));
}

async function setFileTag(fileId, tagColor) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    file.tag = tagColor;
    await saveFile(file);
    if (location.hash === '#/dashboard') renderFileList();
}

// ===== ONEDRIVE OAUTH (F121) =====
function connectOneDrive() {
    const isId = APP.lang === 'id';
    const clientId = ''; // Would need Microsoft App registration
    if (!clientId) {
        showToast(isId ? 'OneDrive OAuth belum dikonfigurasi. Hubungi admin.' : 'OneDrive OAuth not configured. Contact admin.', 'warning');
        return;
    }
    const redirectUri = encodeURIComponent(`${location.origin}/api/gdrive/callback`);
    const scope = encodeURIComponent('Files.ReadWrite.All offline_access');
    window.open(`https://login.microsoftonline.com/common/oauth2/v2.0/authorize?client_id=${clientId}&response_type=code&redirect_uri=${redirectUri}&scope=${scope}`, '_blank');
}

function connectDropbox() {
    const isId = APP.lang === 'id';
    const clientId = ''; // Would need Dropbox App registration
    if (!clientId) {
        showToast(isId ? 'Dropbox OAuth belum dikonfigurasi. Hubungi admin.' : 'Dropbox OAuth not configured. Contact admin.', 'warning');
        return;
    }
    const redirectUri = encodeURIComponent(`${location.origin}/api/gdrive/callback`);
    window.open(`https://www.dropbox.com/oauth2/authorize?client_id=${clientId}&response_type=code&redirect_uri=${redirectUri}`, '_blank');
}

