async function disconnectS3Account(accountId) {
    const isId = APP.lang === 'id';
    const account = APP.s3Accounts.find(a => a.id === accountId);
    if (!account) return;
    const provider = account.type === 's3' ? 's3' : 'token';
    if (APP.storageProviders[provider]) {
        await APP.storageProviders[provider].disconnect(accountId);
    } else {
        await dbDelete('s3_accounts', accountId);
        const idx = APP.s3Accounts.findIndex(a => a.id === accountId);
        if (idx !== -1) APP.s3Accounts.splice(idx, 1);
    }
    if (location.hash === '#/storage') renderStorageManagement();
}

async function refreshS3Account(accountId) {
    const isId = APP.lang === 'id';
    const account = APP.s3Accounts.find(a => a.id === accountId);
    if (!account) return;
    showToast(isId ? 'Menyinkronkan akun...' : 'Syncing account...', 'info');
    try {
        const provider = account.type === 's3' ? APP.storageProviders.s3 : APP.storageProviders.token;
        if (provider) {
            const quota = await provider.getQuota(accountId);
            if (quota) {
                account.quota = quota;
                account.lastSync = Date.now();
                await dbPut('s3_accounts', account);
                showToast(isId ? `Akun ${account.label || account.providerId} disinkronkan` : `Account ${account.label || account.providerId} synced`, 'success');
            }
        }
    } catch(e) {
        showToast(isId ? 'Gagal menyinkronkan' : 'Failed to sync', 'error');
    }
    if (location.hash === '#/storage') renderStorageManagement();
}

// ===== STORAGE CHARTS (Canvas-based) =====
function drawStorageDonutChart(accounts, stats) {
    const canvas = document.getElementById('storage-donut-chart');
    if (!canvas) return;
    // Use parent card width for sizing to avoid zoom loop
    const parent = canvas.parentElement;
    const parentW = parent ? parent.clientWidth - 40 : 240; // subtract padding
    const displayW = Math.max(80, Math.min(parentW, 300));
    const displayH = 200;
    const dpr = window.devicePixelRatio || 1;
    canvas.style.width = displayW + 'px';
    canvas.style.height = displayH + 'px';
    canvas.width = displayW * dpr; canvas.height = displayH * dpr;
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);
    const w = displayW, h = displayH, cx = w / 2, cy = h / 2;
    const radius = Math.max(10, Math.min(w, h) / 2 - 16), innerRadius = radius * 0.6;
    const colors = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ec4899', '#06b6d4'];
    ctx.clearRect(0, 0, w, h);
    if (accounts.length === 0 || stats.totalUsage === 0) {
        ctx.beginPath(); ctx.arc(cx, cy, radius, 0, Math.PI * 2); ctx.arc(cx, cy, innerRadius, 0, Math.PI * 2, true);
        ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--bg-secondary').trim() || '#f1f5f9'; ctx.fill();
        ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--text-secondary').trim() || '#64748b';
        ctx.font = '12px Space Grotesk, sans-serif'; ctx.textAlign = 'center';
        ctx.fillText(APP.lang === 'id' ? 'Belum ada data' : 'No data yet', cx, cy + 4); return;
    }
    let startAngle = -Math.PI / 2;
    accounts.forEach((a, i) => {
        if (a.status !== 'connected' || !a.quota) return;
        const usage = parseInt(a.quota.usage) || 0;
        const sliceAngle = (usage / stats.totalUsage) * Math.PI * 2;
        ctx.beginPath(); ctx.arc(cx, cy, radius, startAngle, startAngle + sliceAngle);
        ctx.arc(cx, cy, innerRadius, startAngle + sliceAngle, startAngle, true); ctx.closePath();
        ctx.fillStyle = colors[i % colors.length]; ctx.fill(); startAngle += sliceAngle;
    });
    const textColor = getComputedStyle(document.documentElement).getPropertyValue('--text').trim() || '#0f172a';
    const subColor = getComputedStyle(document.documentElement).getPropertyValue('--text-secondary').trim() || '#64748b';
    ctx.fillStyle = textColor; ctx.font = 'bold 14px JetBrains Mono, monospace'; ctx.textAlign = 'center';
    ctx.fillText(formatStorageBytes(stats.totalUsage), cx, cy - 2);
    ctx.fillStyle = subColor; ctx.font = '9px Space Grotesk, sans-serif';
    ctx.fillText(APP.lang === 'id' ? 'terpakai' : 'used', cx, cy + 12);
}

function drawStorageBarChart(accounts) {
    const canvas = document.getElementById('storage-bar-chart');
    if (!canvas) return;
    // Use parent card width for sizing to avoid zoom loop
    const parent = canvas.parentElement;
    const parentW = parent ? parent.clientWidth - 40 : 240; // subtract padding
    const displayW = Math.max(80, Math.min(parentW, 300));
    const displayH = 200;
    const dpr = window.devicePixelRatio || 1;
    canvas.style.width = displayW + 'px';
    canvas.style.height = displayH + 'px';
    canvas.width = displayW * dpr; canvas.height = displayH * dpr;
    const ctx = canvas.getContext('2d');
    ctx.scale(dpr, dpr);
    const w = displayW, h = displayH;
    ctx.clearRect(0, 0, w, h);
    const textColor = getComputedStyle(document.documentElement).getPropertyValue('--text-secondary').trim() || '#64748b';
    const borderColor = getComputedStyle(document.documentElement).getPropertyValue('--border').trim() || '#e2e8f0';
    const barColors = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ec4899', '#06b6d4'];
    if (accounts.length === 0) {
        ctx.fillStyle = textColor; ctx.font = '12px Space Grotesk, sans-serif'; ctx.textAlign = 'center';
        ctx.fillText(APP.lang === 'id' ? 'Hubungkan akun untuk melihat chart' : 'Connect accounts to see chart', w / 2, h / 2); return;
    }
    const padding = { top: 10, right: 10, bottom: 30, left: 10 };
    const chartW = w - padding.left - padding.right, chartH = h - padding.top - padding.bottom;
    const barWidth = Math.min(30, chartW / accounts.length - 8);
    const barGap = (chartW - barWidth * accounts.length) / (accounts.length + 1);
    let maxVal = 0;
    accounts.forEach(a => { const l = parseInt(a.quota?.limit) || 15 * 1073741824; if (l > maxVal) maxVal = l; });
    if (maxVal === 0) maxVal = 15 * 1073741824;
    accounts.forEach((a, i) => {
        const limit = parseInt(a.quota?.limit) || 15 * 1073741824, usage = parseInt(a.quota?.usage) || 0;
        const x = padding.left + barGap + i * (barWidth + barGap);
        const limitH = (limit / maxVal) * chartH, usageH = (usage / maxVal) * chartH;
        ctx.fillStyle = getComputedStyle(document.documentElement).getPropertyValue('--bg-secondary').trim() || '#f1f5f9';
        ctx.beginPath(); ctx.roundRect(x, padding.top + chartH - limitH, barWidth, limitH, [4, 4, 0, 0]); ctx.fill();
        ctx.fillStyle = barColors[i % barColors.length];
        ctx.beginPath(); ctx.roundRect(x, padding.top + chartH - usageH, barWidth, usageH, [4, 4, 0, 0]); ctx.fill();
        ctx.fillStyle = textColor; ctx.font = '8px Space Grotesk, sans-serif'; ctx.textAlign = 'center';
        const label = a.email ? a.email.split('@')[0] : 'Drive ' + (i + 1);
        ctx.fillText(label.length > 6 ? label.slice(0, 5) + '..' : label, x + barWidth / 2, h - padding.bottom + 12);
    });
}

// ===== SMART UPLOAD WITH GDRIVE FALLBACK =====
async function executeUploadToGDrive(file, folderId) {
    const isId = APP.lang === 'id';
    const bestDrive = selectBestDrive(file.size);
    if (!bestDrive) return null; // Fallback to Telegram
    APP.activeUploads++; updateGlobalProgress();
    try {
        const result = await APP.storageProviders.gdrive.upload(bestDrive.id, file, { parentFolderId: null });
        const fileType = getFileType(file.name, file.type);
        const autoTag = getAutoTagColor(fileType);
        const fid = folderId || APP.currentFolder;
        const effectiveFolderId = ['all', 'recent', 'favorites', 'trash', 'shared', 'encrypted'].includes(fid) ? null : fid;
        const existing = APP.files.filter(f => f.name === file.name && f.folderId === effectiveFolderId && !f.trashed);
        const version = existing.length + 1;
        const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: effectiveFolderId, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: autoTag, caption: '', shareCount: 0, storageProvider: 'gdrive', providerAccountId: bestDrive.id, driveFileId: result.driveFileId };
        await saveFile(meta); APP.files.push(meta);
        if (bestDrive.quota) { bestDrive.quota.usage = (parseInt(bestDrive.quota.usage) || 0) + file.size; await dbPut('gdrive_accounts', bestDrive); }
        showToast(`${file.name} → Google Drive (${bestDrive.email.split('@')[0]})`, 'success');
        logActivity('upload', `${isId ? 'Mengunggah' : 'Uploaded'} ${file.name} → GDrive`);
        sendNotification('Ridgebox', `${file.name} uploaded to Google Drive`);
        triggerWebhook('file.uploaded', { fileId: meta.id, fileName: meta.name, fileSize: meta.size, storageProvider: 'gdrive' });
        checkStorageWarning(); updateUploadPreviewProgress(file.name, 100);
        const suz = document.getElementById('smart-upload-zone');
        if (suz && !suz.classList.contains('minimized')) suz.classList.add('minimized');
        APP.activeUploads--; updateGlobalProgress(); return meta;
    } catch (e) { APP.activeUploads--; updateGlobalProgress(); showToast(`Google Drive upload failed: ${e.message}`, 'error'); return null; }
}

// ===== INIT GDRIVE CONFIG =====
async function initGDriveConfig() {
    try {
        const resp = await fetch('/api/gdrive/config');
        const data = await resp.json();
        APP.gdriveConfig = { configured: data.configured, clientId: data.clientId || '' };
    } catch (e) { APP.gdriveConfig = { configured: false, clientId: '' }; }
}

// ===== CHECK GDRIVE CONFIG (for setup wizard) =====
async function checkGDriveConfig() {
    const isId = APP.lang === 'id';
    showToast(isId ? 'Memeriksa konfigurasi Google Drive...' : 'Checking Google Drive configuration...', 'info');
    await initGDriveConfig();
    if (APP.gdriveConfig.configured) {
        showToast(isId ? 'Google Drive sudah dikonfigurasi! Menghubungkan...' : 'Google Drive is configured! Connecting...', 'success');
        if (location.hash === '#/storage') renderStorageManagement();
    } else {
        showToast(isId ? 'Google Drive belum dikonfigurasi. Ikuti langkah-langkah di atas.' : 'Google Drive not yet configured. Follow the steps above.', 'warning');
    }
}

// ===== GDRIVE SYNC — List and import files from Google Drive =====
async function syncGDriveAccount(accountId) {
    const isId = APP.lang === 'id';
    const account = APP.gdriveAccounts.find(a => a.id === accountId);
    if (!account || account.status !== 'connected') {
        showToast(isId ? 'Akun tidak terhubung' : 'Account not connected', 'warning');
        return;
    }
    showToast(isId ? 'Menyinkronkan file dari Google Drive...' : 'Syncing files from Google Drive...', 'info');
    try {
        const accessToken = await APP.storageProviders.gdrive.getAccessToken(accountId);
        if (!accessToken) { showToast(isId ? 'Gagal memperoleh token' : 'Failed to get token', 'error'); return; }
        // List files from Google Drive (not in trash, max 100)
        const listResp = await fetch('/api/gdrive/proxy', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ accessToken, method: 'GET', path: '/drive/v3/files', params: { pageSize: '100', fields: 'files(id,name,mimeType,size,modifiedTime)', q: "trashed = false and 'me' in owners" } })
        });
        const listData = await listResp.json();
        if (!listData.ok || !listData.data?.files) {
            showToast(isId ? 'Gagal mengambil daftar file' : 'Failed to list files', 'error');
            return;
        }
        const driveFiles = listData.data.files;
        let importedCount = 0;
        for (const df of driveFiles) {
            // Skip if already imported
            if (APP.files.some(f => f.driveFileId === df.id && !f.trashed)) continue;
            // Skip Google Docs/Sheets/Slides (they have no real size and need export)
            if (df.mimeType && df.mimeType.startsWith('application/vnd.google-apps')) continue;
            const meta = {
                id: genId(),
                name: df.name || 'Unnamed',
                size: parseInt(df.size) || 0,
                mime: df.mimeType || 'application/octet-stream',
                fileId: null,
                filePath: '',
                messageId: null,
                botIndex: '0',
                chatId: '',
                folderId: null,
                uploadedAt: df.modifiedTime ? new Date(df.modifiedTime).getTime() : Date.now(),
                pinned: false,
                starred: false,
                trashed: false,
                encrypted: false,
                version: 1,
                tag: getAutoTagColor(getFileType(df.name, df.mimeType)),
                caption: '',
                shareCount: 0,
                storageProvider: 'gdrive',
                providerAccountId: accountId,
                driveFileId: df.id,
                syncedAt: Date.now()
            };
            await saveFile(meta);
            APP.files.push(meta);
            importedCount++;
        }
        // Update last sync time
        account.lastSync = Date.now();
        await dbPut('gdrive_accounts', account);
        if (importedCount > 0) {
            showToast(isId ? `${importedCount} file berhasil disinkronkan dari Google Drive` : `${importedCount} files synced from Google Drive`, 'success');
            logActivity('upload', isId ? `Sinkronisasi ${importedCount} file dari ${account.email}` : `Synced ${importedCount} files from ${account.email}`);
        } else {
            showToast(isId ? 'Semua file sudah tersinkronisasi' : 'All files already synced', 'info');
        }
        if (location.hash === '#/storage') renderStorageManagement();
        else renderFileList();
    } catch (e) {
        showToast(isId ? 'Gagal menyinkronkan: ' + e.message : 'Sync failed: ' + e.message, 'error');
    }
}

// ===== DRIVE SELECT MODAL — Manual drive selection for uploads =====
let _driveSelectFile = null; // Stores the file for drive selection modal

function openDriveSelectModal(file) {
    _driveSelectFile = file;
    const isId = APP.lang === 'id';
    const gdriveAccounts = APP.gdriveAccounts.filter(a => a.status === 'connected');
    const accountColors = ['#3b82f6', '#8b5cf6', '#10b981', '#f59e0b', '#ec4899', '#06b6d4'];
    const bestDrive = selectBestDrive(file.size);

    const gdriveCards = gdriveAccounts.map((a, i) => {
        const limit = parseInt(a.quota?.limit) || 15 * 1024 * 1024 * 1024;
        const usage = parseInt(a.quota?.usage) || 0;
        const available = limit - usage;
        const pct = limit > 0 ? Math.min((usage / limit) * 100, 100) : 0;
        const isBest = bestDrive && bestDrive.type === 'gdrive' && bestDrive.id === a.id;
        const canFit = available >= file.size;
        return `<div class="drive-select-card ${isBest ? 'selected' : ''}" onclick="executeUploadToSpecificDrive('${a.id}', _driveSelectFile)" style="${!canFit ? 'opacity:.5' : ''}">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">
                <div style="width:32px;height:32px;border-radius:8px;background:linear-gradient(135deg,${accountColors[i % accountColors.length]},${accountColors[(i + 1) % accountColors.length]});display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px;font-weight:700">${(a.name || a.email || 'G').charAt(0).toUpperCase()}</div>
                <div style="flex:1;min-width:0">
                    <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${a.email}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${formatStorageBytes(available)} ${isId ? 'tersedia' : 'available'} · ${pct.toFixed(0)}% ${isId ? 'terpakai' : 'used'}</div>
                </div>
                ${isBest ? `<span style="font-size:10px;font-weight:700;color:var(--accent);background:rgba(59,130,246,.1);padding:2px 8px;border-radius:4px">${isId ? 'TERBAIK' : 'BEST'}</span>` : ''}
            </div>
            <div class="storage-bar-track" style="height:4px"><div class="storage-bar-fill ${pct > 80 ? 'gradient-red' : pct > 50 ? 'gradient-amber' : 'gradient-green'}" style="width:${pct}%"></div></div>
            ${!canFit ? `<div style="font-size:10px;color:#ef4444;margin-top:4px">${isId ? 'Ruang tidak cukup' : 'Not enough space'}</div>` : ''}
        </div>`;
    }).join('');

    const s3Accounts = APP.s3Accounts.filter(a => a.status === 'connected');
    const s3Cards = s3Accounts.map(a => {
        const pInfo = S3_PROVIDER_INFO[a.providerId] || {};
        const pIcon = pInfo.icon || 'fa-database';
        const pIconClass = pInfo.iconPrefix || 'fas';
        const pColor = pInfo.color || '#6b7280';
        const isBest = bestDrive && (bestDrive.type === 's3' || bestDrive.type === 'token') && bestDrive.id === a.id;
        return `<div class="drive-select-card ${isBest ? 'selected' : ''}" onclick="executeUploadToS3Drive('${a.id}', _driveSelectFile)">
            <div style="display:flex;align-items:center;gap:10px">
                <div style="width:32px;height:32px;border-radius:8px;background:${pColor}22;display:flex;align-items:center;justify-content:center"><i class="${pIconClass} ${pIcon}" style="color:${pColor};font-size:14px"></i></div>
                <div style="flex:1;min-width:0">
                    <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${a.label || pInfo.name || a.providerId}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">${pInfo.name || a.providerId}${a.type === 's3' ? ' · ' + a.bucket : ''}</div>
                </div>
                ${isBest ? `<span style="font-size:10px;font-weight:700;color:var(--accent);background:rgba(59,130,246,.1);padding:2px 8px;border-radius:4px">${isId ? 'TERBAIK' : 'BEST'}</span>` : ''}
            </div>
        </div>`;
    }).join('');

    // OneDrive accounts
    const onedriveAccounts = APP.onedriveAccounts.filter(a => a.status === 'connected');
    const onedriveCards = onedriveAccounts.map(a => {
        const limit = parseInt(a.quota?.limit) || 5*1024*1024*1024;
        const usage = parseInt(a.quota?.usage) || 0;
        const available = limit - usage;
        const pct = limit > 0 ? Math.min((usage/limit)*100, 100) : 0;
        const isBest = bestDrive && bestDrive.type === 'onedrive' && bestDrive.id === a.id;
        const canFit = available >= file.size;
        return `<div class="drive-select-card ${isBest ? 'selected' : ''}" onclick="executeUploadToOneDriveDrive('${a.id}', _driveSelectFile)" style="${!canFit ? 'opacity:.5' : ''}">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">
                <div style="width:32px;height:32px;border-radius:8px;background:linear-gradient(135deg,#0078d4,#00bcf2);display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px"><i class="fab fa-microsoft"></i></div>
                <div style="flex:1;min-width:0">
                    <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${a.email}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">OneDrive · ${formatStorageBytes(available)} ${isId ? 'tersedia' : 'available'}</div>
                </div>
                ${isBest ? `<span style="font-size:10px;font-weight:700;color:var(--accent);background:rgba(59,130,246,.1);padding:2px 8px;border-radius:4px">${isId ? 'TERBAIK' : 'BEST'}</span>` : ''}
            </div>
            <div class="storage-bar-track" style="height:4px"><div class="storage-bar-fill ${pct > 80 ? 'gradient-red' : pct > 50 ? 'gradient-amber' : 'gradient-green'}" style="width:${pct}%"></div></div>
        </div>`;
    }).join('');

    // Dropbox accounts
    const dropboxAccounts = APP.dropboxAccounts.filter(a => a.status === 'connected');
    const dropboxCards = dropboxAccounts.map(a => {
        const limit = parseInt(a.quota?.limit) || 2*1024*1024*1024;
        const usage = parseInt(a.quota?.usage) || 0;
        const available = limit - usage;
        const pct = limit > 0 ? Math.min((usage/limit)*100, 100) : 0;
        const isBest = bestDrive && bestDrive.type === 'dropbox' && bestDrive.id === a.id;
        const canFit = available >= file.size;
        return `<div class="drive-select-card ${isBest ? 'selected' : ''}" onclick="executeUploadToDropboxDrive('${a.id}', _driveSelectFile)" style="${!canFit ? 'opacity:.5' : ''}">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:8px">
                <div style="width:32px;height:32px;border-radius:8px;background:linear-gradient(135deg,#0061ff,#0052cc);display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px"><i class="fab fa-dropbox"></i></div>
                <div style="flex:1;min-width:0">
                    <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${a.email}</div>
                    <div style="font-size:11px;color:var(--text-secondary)">Dropbox · ${formatStorageBytes(available)} ${isId ? 'tersedia' : 'available'}</div>
                </div>
                ${isBest ? `<span style="font-size:10px;font-weight:700;color:var(--accent);background:rgba(59,130,246,.1);padding:2px 8px;border-radius:4px">${isId ? 'TERBAIK' : 'BEST'}</span>` : ''}
            </div>
            <div class="storage-bar-track" style="height:4px"><div class="storage-bar-fill ${pct > 80 ? 'gradient-red' : pct > 50 ? 'gradient-amber' : 'gradient-green'}" style="width:${pct}%"></div></div>
        </div>`;
    }).join('');

    const telegramCard = `<div class="drive-select-card" onclick="executeUploadToTelegramDirect(_driveSelectFile)">
        <div style="display:flex;align-items:center;gap:10px">
            <div style="width:32px;height:32px;border-radius:8px;background:linear-gradient(135deg,#0088cc,#00a8e8);display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px"><i class="fas fa-paper-plane"></i></div>
            <div>
                <div style="font-size:13px;font-weight:600;color:var(--text)">Telegram Bot</div>
                <div style="font-size:11px;color:var(--text-secondary)">${isId ? 'Upload via Telegram Bot API' : 'Upload via Telegram Bot API'}</div>
            </div>
        </div>
    </div>`;

    openModal(`<div style="padding:20px;max-width:480px;margin:0 auto">
        <h3 style="font-size:18px;font-weight:700;margin-bottom:4px;display:flex;align-items:center;gap:8px"><i class="fas fa-cloud-upload-alt" style="color:var(--accent)"></i> ${isId ? 'Pilih Drive Tujuan' : 'Select Target Drive'}</h3>
        <p style="font-size:12px;color:var(--text-secondary);margin-bottom:16px">${isId ? `File: <b>${file.name}</b> (${formatSize(file.size)})` : `File: <b>${file.name}</b> (${formatSize(file.size)})`}</p>
        <div style="display:flex;flex-direction:column;gap:10px;max-height:400px;overflow-y:auto">
            ${gdriveCards}
            ${onedriveCards}
            ${dropboxCards}
            ${s3Cards}
            ${telegramCard}
        </div>
        <div style="margin-top:14px;text-align:center">
            <button class="btn btn-secondary" onclick="closeModal()">${isId ? 'Batal' : 'Cancel'}</button>
        </div>
    </div>`);
}

// Upload to specific drive (from manual selection)
async function executeUploadToSpecificDrive(accountId, file) {
    if (!file) { closeModal(); return; }
    closeModal();
    const isId = APP.lang === 'id';
    APP.activeUploads++; updateGlobalProgress();
    try {
        const result = await APP.storageProviders.gdrive.upload(accountId, file, { parentFolderId: null });
        const account = APP.gdriveAccounts.find(a => a.id === accountId);
        const fileType = getFileType(file.name, file.type);
        const autoTag = getAutoTagColor(fileType);
        const fid = APP.currentFolder;
        const effectiveFolderId = ['all', 'recent', 'favorites', 'trash', 'shared', 'encrypted'].includes(fid) ? null : fid;
        const existing = APP.files.filter(f => f.name === file.name && f.folderId === effectiveFolderId && !f.trashed);
        const version = existing.length + 1;
        const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: effectiveFolderId, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: autoTag, caption: '', shareCount: 0, storageProvider: 'gdrive', providerAccountId: accountId, driveFileId: result.driveFileId };
        await saveFile(meta); APP.files.push(meta);
        if (account?.quota) { account.quota.usage = (parseInt(account.quota.usage) || 0) + file.size; await dbPut('gdrive_accounts', account); }
        showToast(`${file.name} → Google Drive (${account?.email?.split('@')[0] || 'Drive'})`, 'success');
        logActivity('upload', `${isId ? 'Mengunggah' : 'Uploaded'} ${file.name} → GDrive (${account?.email || 'manual'})`);
        APP.activeUploads--; updateGlobalProgress();
        const suz = document.getElementById('smart-upload-zone');
        if (suz && !suz.classList.contains('minimized')) suz.classList.add('minimized');
        renderFileList();
    } catch (e) { APP.activeUploads--; updateGlobalProgress(); showToast(`Upload failed: ${e.message}`, 'error'); }
}

// Upload to Telegram directly (from drive selection modal)
async function executeUploadToTelegramDirect(file) {
    if (!file) { closeModal(); return; }
    closeModal();
    // Delegate to existing upload flow
    await executeUpload(file);
}

