        const effectiveFolderId = ['all', 'recent', 'favorites', 'trash', 'shared', 'encrypted'].includes(fid) ? null : fid;
        const existing = APP.files.filter(f => f.name === file.name && f.folderId === effectiveFolderId && !f.trashed);
        const version = existing.length + 1;
        const meta = {
            id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream',
            fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '',
            folderId: effectiveFolderId, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false,
            encrypted: false, version, tag: autoTag, caption: '', shareCount: 0,
            storageProvider: 's3', providerAccountId: accountId, driveFileId: result.driveFileId
        };
        await saveFile(meta); APP.files.push(meta);
        showToast(`${file.name} → ${account.label || pInfo.name || account.providerId}`, 'success');
        logActivity('upload', `${isId ? 'Mengunggah' : 'Uploaded'} ${file.name} → ${pInfo.name || account.providerId}`);
