async function init() {
    try {
        // Load theme
        APP.theme = localStorage.getItem('rb_theme') || 'light';
        APP.lang = localStorage.getItem('rb_lang') || 'id';
        applyTheme();
        applyLangDir();
        loadAccentColor();
        applyViewMode();

        // Load data from IndexedDB
        await loadAllData();

        // Init Google Drive config
        initGDriveConfig();

        // Fetch bot config + Supabase config (non-blocking — don't await)
        const configPromise = (async () => {
            try {
                const resp = await fetch('/api/config');
                const data = await resp.json();
                if (data.ok && data.bots && data.bots.length > 0) {
                    APP.bots = data.bots;
                    APP.settings.proxyMode = data.proxyMode !== false;
                    APP.connected = true;
                }
                // Load Supabase config from server env vars
                if (data.supabaseUrl && data.supabaseAnonKey) {
                    window.__supabaseConfig = { url: data.supabaseUrl, anonKey: data.supabaseAnonKey };
                }
            } catch (e) {
                console.warn('Config fetch failed:', e);
                APP.connected = navigator.onLine;
            }

            // Fallback: Hardcode Supabase config if server env vars not set
            if (!window.__supabaseConfig || !window.__supabaseConfig.url) {
                window.__supabaseConfig = {
                    url: 'https://tztpwbasrajvkjbrvwfu.supabase.co',
                    anonKey: 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InR6dHB3YmFzcmFqdmtqYnJ2d2Z1Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODA3NzQ1OTMsImV4cCI6MjA5NjM1MDU5M30.3O4-5PbSlRC8cro8hbbIgkxdnUOIXmWHa2mA5NVnhxc'
                };
            }

            // Init Supabase Auth (deferred script should be loaded by now)
            if (window.supabase) {
                initSupabaseAuth();
            } else {
                // Wait briefly for deferred Supabase script (max 3s)
                await new Promise(resolve => {
                    const check = setInterval(() => { if (window.supabase) { clearInterval(check); resolve(); } }, 50);
                    setTimeout(() => { clearInterval(check); resolve(); }, 3000);
                });
                if (window.supabase) initSupabaseAuth();
            }
        })();

        // Route immediately for faster FCP — auth will catch up
        if (APP.files.length > 0 || location.hash !== '') {
            checkUrlRouting();
        }
        window.addEventListener('hashchange', checkUrlRouting);

        // Wait for auth to resolve, then proceed with post-auth init
        await configPromise;

        // If auth not required (no Supabase), proceed normally
        if (!isAuthRequired()) {
            APP.authReady = true;
        }

        // Update connection status
        updateConnectionStatus();
        window.addEventListener('online', () => { APP.connected = true; updateConnectionStatus(); showToast(t('connectionOk'), 'success', 2000); });
        window.addEventListener('offline', () => { APP.connected = false; updateConnectionStatus(); showToast(t('connectionOff'), 'warning', 2000); });

        // Auto purge trash (deferred to reduce main thread blocking)
        requestIdleCallback ? requestIdleCallback(() => autoPurgeTrash()) : setTimeout(() => autoPurgeTrash(), 1000);

        // Feature 6: Clear old thumbnails (deferred)
        requestIdleCallback ? requestIdleCallback(() => clearOldThumbnails()) : setTimeout(() => clearOldThumbnails(), 2000);

        // Feature 1: Init auto-lock
        initAutoLock();

        // Feature 14: Init backup schedule
        try { initBackupSchedule(); } catch(e) {}

        // Feature 5: Init notifications
        initNotifications();

        // F109: Init push notifications
        initPushNotifications();

        // F111: Init file metadata server sync
        if (APP.supabase && isLoggedIn()) {
            loadFilesFromServer();
            initRealtimeSync();
            // F11: Ensure Supabase tables are set up
            ensureSupabaseTables();
            // F10: Register current session
            registerCurrentSession();
            // F9: Load recovery codes
            loadRecoveryCodes();
        }

        // Update session activity periodically
        setInterval(updateSessionActivity, 60000);

        // F118: Init enhanced drag & drop
        initEnhancedDragDrop();

        // Feature 4: Check pending uploads (deferred)
        requestIdleCallback ? requestIdleCallback(() => checkPendingUploads()) : setTimeout(() => checkPendingUploads(), 1500);

        // Route (auth should be ready by now)
        if (APP.authReady) checkUrlRouting();

        // Onboarding (F95) - show on first dashboard visit
        if (!APP.onboardingDone && location.hash === '#/dashboard') {
            setTimeout(startOnboarding, 500);
        }

        // Register service worker with auto-update
        if ('serviceWorker' in navigator) {
            try {
                const reg = await navigator.serviceWorker.register('sw.js');
                // Force check for updates immediately
                reg.update();
                // Check for SW updates every 5 minutes
                setInterval(() => reg.update(), 300000);
                // When new SW activates, reload to get latest code
                reg.addEventListener('updatefound', () => {
                    const newWorker = reg.installing;
                    newWorker.addEventListener('statechange', () => {
                        if (newWorker.state === 'activated') {
                            // New service worker activated — reload for latest code
                            location.reload();
                        }
                    });
                });
            } catch(e) { console.warn('SW registration failed:', e); }
        }

        // Load type filter options
        APP.filterType = 'all';

    } catch (err) {
        console.error('Init error:', err);
        showToast('Initialization error: ' + err.message, 'error');
    }
}

// Safe init wrapper (error handling pattern)
function safeInit() {
    try {
        init().catch(err => {
            console.error('Async init error:', err);
            showToast('Startup error: ' + err.message, 'error');
        });
    } catch (err) {
        console.error('Sync init error:', err);
        showToast('Critical error: ' + err.message, 'error');
    }
}

