// ===== FEATURE 14: Backup/Sync Folder =====
async function selectBackupFolder() {
    const isId = APP.lang === 'id';
    if (!window.showDirectoryPicker) {
        showToast(isId ? 'Browser tidak mendukung File System Access API. Gunakan Chrome/Edge.' : 'Browser does not support File System Access API. Use Chrome/Edge.', 'warning');
        return;
    }
    try {
        const handle = await window.showDirectoryPicker({ mode: 'read' });
        // Request permission
        const perm = await handle.queryPermission({ mode: 'read' });
        if (perm !== 'granted') {
            const req = await handle.requestPermission({ mode: 'read' });
            if (req !== 'granted') {
                showToast(isId ? 'Izin baca folder ditolak' : 'Folder read permission denied', 'error');
                return;
            }
        }
        // Store handle in IndexedDB
        APP.backupConfig.folderHandle = handle;
        APP.backupConfig.folderName = handle.name;
        // Count files
        let fileCount = 0;
        for await (const entry of handle.values()) {
            if (entry.kind === 'file') fileCount++;
        }
        APP.backupConfig.fileCount = fileCount;
        APP.backupConfig.status = 'synced';
        await saveSetting('backup_config', {
            folderName: APP.backupConfig.folderName,
            fileCount: APP.backupConfig.fileCount,
            frequency: APP.backupConfig.frequency,
            lastSync: APP.backupConfig.lastSync,
            status: APP.backupConfig.status,
            history: APP.backupConfig.history || [],
            nextSync: APP.backupConfig.nextSync
        });
        // Store handle separately (IndexedDB can store FileSystemDirectoryHandle)
        try {
            await dbPut('backup_config', { id: 'folder_handle', handle });
        } catch(e) { console.warn('Could not persist folder handle:', e); }
        showToast(isId ? `Folder "${handle.name}" dipilih (${fileCount} file)` : `Folder "${handle.name}" selected (${fileCount} files)`, 'success');
        openSettings(); // Refresh settings UI
    } catch(e) {
        if (e.name !== 'AbortError') showToast(isId ? 'Gagal memilih folder' : 'Failed to select folder', 'error');
    }
}

async function syncBackupFolder() {
    const isId = APP.lang === 'id';
    if (!APP.backupConfig.folderHandle) {
        showToast(isId ? 'Pilih folder terlebih dahulu' : 'Select a folder first', 'warning');
        return;
    }
    // Storage quota check for backup sync (F16) — check if already at limit
    const quotaCheck = checkStorageQuota(0);
    if (quotaCheck.percentage >= 100) {
        showQuotaExceededModal(quotaCheck);
        return;
    }
    APP.backupConfig.status = 'syncing';
    openSettings(); // Update UI

    try {
        const handle = APP.backupConfig.folderHandle;
        // Re-request permission
        const perm = await handle.requestPermission({ mode: 'read' });
        if (perm !== 'granted') {
            APP.backupConfig.status = 'error';
            showToast(isId ? 'Izin baca folder ditolak' : 'Folder read permission denied', 'error');
            return;
        }

        let syncedCount = 0, errorCount = 0;
        const bestDrive = selectBestDrive(0);

        for await (const entry of handle.values()) {
            if (entry.kind === 'file') {
                try {
                    const file = await entry.getFile();
                    // Check if file already exists by name and size+lastModified
                    const existing = APP.files.find(f => f.name === file.name && f.size === file.size && !f.trashed);
                    if (!existing) {
                        // Upload new file
                        if (bestDrive) {
                            if (bestDrive.type === 'gdrive') {
                                const result = await APP.storageProviders.gdrive.upload(bestDrive.id, file, {});
                                const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: null, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: 'backup', caption: '', shareCount: 0, storageProvider: 'gdrive', providerAccountId: bestDrive.id, driveFileId: result.driveFileId };
                                APP.files.push(meta);
                                await saveFile(meta);
                            } else if (bestDrive.type === 'onedrive') {
                                const result = await APP.storageProviders.onedrive.upload(bestDrive.id, file, {});
                                const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: null, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: 'backup', caption: '', shareCount: 0, storageProvider: 'onedrive', providerAccountId: bestDrive.id, driveFileId: result.driveFileId };
                                APP.files.push(meta);
                                await saveFile(meta);
                            } else if (bestDrive.type === 'dropbox') {
                                const result = await APP.storageProviders.dropbox.upload(bestDrive.id, file, {});
                                const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: result.driveFileId, filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: null, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: 'backup', caption: '', shareCount: 0, storageProvider: 'dropbox', providerAccountId: bestDrive.id, driveFileId: result.driveFileId };
                                APP.files.push(meta);
                                await saveFile(meta);
                            }
                            syncedCount++;
                        } else {
                            // No connected drive - store locally
                            const meta = { id: genId(), name: file.name, size: file.size, mime: file.type || 'application/octet-stream', fileId: '', filePath: '', messageId: null, botIndex: '0', chatId: '', folderId: null, uploadedAt: Date.now(), pinned: false, starred: false, trashed: false, encrypted: false, version, tag: 'backup', caption: '', shareCount: 0, storageProvider: 'local' };
                            APP.files.push(meta);
                            await saveFile(meta);
                            syncedCount++;
                        }
                    }
                } catch(e) {
                    console.error('Backup sync error for file:', e);
                    errorCount++;
                }
            }
        }

        APP.backupConfig.lastSync = Date.now();
        APP.backupConfig.status = errorCount > 0 ? (syncedCount > 0 ? 'synced' : 'error') : 'synced';
        APP.backupConfig.nextSync = getNextSyncTime(APP.backupConfig.frequency);

        // Add to history
        if (!APP.backupConfig.history) APP.backupConfig.history = [];
        APP.backupConfig.history.unshift({ timestamp: Date.now(), fileCount: syncedCount, status: errorCount > 0 ? (syncedCount > 0 ? 'partial' : 'error') : 'success' });
        APP.backupConfig.history = APP.backupConfig.history.slice(0, 10);

        await saveSetting('backup_config', {
            folderName: APP.backupConfig.folderName,
            fileCount: APP.backupConfig.fileCount,
            frequency: APP.backupConfig.frequency,
            lastSync: APP.backupConfig.lastSync,
            status: APP.backupConfig.status,
            history: APP.backupConfig.history,
            nextSync: APP.backupConfig.nextSync
        });

        showToast(isId ? `Sinkronisasi selesai: ${syncedCount} file baru, ${errorCount} error` : `Sync complete: ${syncedCount} new files, ${errorCount} errors`, syncedCount > 0 ? 'success' : 'warning');
        openSettings();
    } catch(e) {
        APP.backupConfig.status = 'error';
        showToast(isId ? 'Sinkronisasi gagal: ' + e.message : 'Sync failed: ' + e.message, 'error');
        openSettings();
    }
}

function getNextSyncTime(frequency) {
    const now = Date.now();
    if (frequency === 'daily') return now + 24 * 60 * 60 * 1000;
    if (frequency === 'weekly') return now + 7 * 24 * 60 * 60 * 1000;
    return null;
}

async function setBackupFrequency(freq) {
    const isId = APP.lang === 'id';
    APP.backupConfig.frequency = freq;
    APP.backupConfig.nextSync = getNextSyncTime(freq);

    // Clear existing interval
    if (APP.backupSyncInterval) { clearInterval(APP.backupSyncInterval); APP.backupSyncInterval = null; }

    // Set up scheduled sync
    if (freq === 'daily') {
        APP.backupSyncInterval = setInterval(async () => {
            if (APP.backupConfig.folderHandle && APP.backupConfig.nextSync && Date.now() >= APP.backupConfig.nextSync) {
                await syncBackupFolder();
            }
        }, 60 * 60 * 1000); // Check every hour
    } else if (freq === 'weekly') {
        APP.backupSyncInterval = setInterval(async () => {
            if (APP.backupConfig.folderHandle && APP.backupConfig.nextSync && Date.now() >= APP.backupConfig.nextSync) {
                await syncBackupFolder();
            }
        }, 6 * 60 * 60 * 1000); // Check every 6 hours
    }

    await saveSetting('backup_config', {
        folderName: APP.backupConfig.folderName,
        fileCount: APP.backupConfig.fileCount,
        frequency: freq,
        lastSync: APP.backupConfig.lastSync,
        status: APP.backupConfig.status,
        history: APP.backupConfig.history || [],
        nextSync: APP.backupConfig.nextSync
    });
    showToast(isId ? `Frekuensi backup: ${freq === 'daily' ? 'Harian' : freq === 'weekly' ? 'Mingguan' : 'Manual'}` : `Backup frequency: ${freq === 'daily' ? 'Daily' : freq === 'weekly' ? 'Weekly' : 'Manual'}`, 'info');
}

// Init backup schedule on load
function initBackupSchedule() {
    if (APP.backupConfig.frequency && APP.backupConfig.frequency !== 'manual' && APP.backupConfig.folderHandle) {
        setBackupFrequency(APP.backupConfig.frequency);
    }
}

