// ===== BULK MOVE TO FOLDER (Premium UX) =====
function bulkMoveToFolder() {
    if (APP.selectedFiles.size === 0) return;
    const folders = APP.folders.filter(f => !f.system);
    const allOption = `<div class="context-menu-item" onclick="executeBulkMove('all')"><i class="fas fa-layer-group" style="color:var(--accent)"></i> ${APP.lang==='id'?'Semua File':'All Files'}</div>`;
    const folderOptions = folders.map(f => `<div class="context-menu-item" onclick="executeBulkMove('${f.id}')"><i class="fas ${f.icon||'fa-folder'}" style="color:var(--accent)"></i> ${f.name}</div>`).join('');
    openModal(`<div style="padding:24px">
        <h3 style="font-size:17px;font-weight:600;margin-bottom:4px"><i class="fas fa-folder-open" style="color:var(--accent)"></i> ${APP.lang==='id'?'Pindahkan ke Folder':'Move to Folder'}</h3>
        <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${APP.selectedFiles.size} ${APP.lang==='id'?'file dipilih':'files selected'}</p>
        ${allOption}
        ${folderOptions || `<p style="font-size:13px;color:var(--text-secondary);padding:8px 0">${APP.lang==='id'?'Belum ada folder kustom':'No custom folders yet'}</p>`}
        <div style="margin-top:16px;text-align:right">
            <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
        </div>
    </div>`);
}

async function executeBulkMove(folderId) {
    const moveCount = APP.selectedFiles.size;
    for (const id of APP.selectedFiles) {
        const file = APP.files.find(f => f.id === id);
        if (file) {
            file.folderId = folderId === 'all' ? null : folderId;
            await saveFile(file);
        }
    }
    const targetName = folderId === 'all' ? (APP.lang==='id'?'Semua File':'All Files') : (APP.folders.find(f => f.id === folderId)?.name || folderId);
    APP.selectedFiles.clear();
    APP.batchMode = false;
    closeModal();
    closeDetailPanel();
    await refreshUI();
    showToast(`${moveCount} ${APP.lang==='id'?'file dipindahkan ke':'files moved to'} ${targetName}`, 'success');
}

