// --- Smart Upload Zone ---
let _pasteListenerAdded = false;
function setupSmartUploadZone() {
    const zone = document.getElementById('smart-upload-zone');
    if (!zone) return;
    let dragCounter = 0;
    zone.addEventListener('dragenter', (e) => {
        e.preventDefault();
        dragCounter++;
        zone.classList.add('drag-active');
    });
    zone.addEventListener('dragover', (e) => {
        e.preventDefault();
    });
    zone.addEventListener('dragleave', (e) => {
        dragCounter--;
        if (dragCounter <= 0) { dragCounter = 0; zone.classList.remove('drag-active'); }
    });
    zone.addEventListener('drop', (e) => {
        e.preventDefault();
        dragCounter = 0;
        zone.classList.remove('drag-active');
        if (e.dataTransfer.files.length > 0) {
            showUploadPreview(e.dataTransfer.files);
            handleFileSelect(e.dataTransfer.files);
        }
    });
    // Paste from clipboard (add only once)
    if (!_pasteListenerAdded) {
        _pasteListenerAdded = true;
        document.addEventListener('paste', (e) => {
            // Only handle paste when dashboard is visible and no input is focused
            if (location.hash !== '#/dashboard') return;
            if (e.target.closest('input,textarea,[contenteditable]')) return;
            const items = e.clipboardData?.items;
            if (!items) return;
            const files = [];
            for (let i = 0; i < items.length; i++) {
                if (items[i].kind === 'file') {
                    const f = items[i].getAsFile();
                    if (f) files.push(f);
                }
            }
            if (files.length > 0) {
                e.preventDefault();
                showUploadPreview(files);
                handleFileSelect(files);
            }
        });
    }
}

function handleSmartUploadClick(e) {
    // Don't trigger if clicking on a method button
    if (e.target.closest('.upload-method')) return;
    triggerUpload();
}

function handleClipboardPaste() {
    showToast(APP.lang === 'id' ? 'Tekan Ctrl+V untuk menempel file' : 'Press Ctrl+V to paste files', 'info', 3000);
}

// Show upload preview before/during upload
function showUploadPreview(files) {
    const queue = document.getElementById('upload-preview-queue');
    if (!queue) return;
    queue.style.display = 'flex';
    let html = '';
    for (const file of files) {
        const fType = getFileType(file.name, file.type);
        const fIcon = getFileIcon(fType);
        html += `<div class="upload-preview-item" data-upload-name="${file.name}">
            <div class="upi-icon" style="background:${fIcon.color}15;color:${fIcon.color}"><i class="fas ${fIcon.icon}"></i></div>
            <div class="upi-info">
                <div class="upi-name">${file.name}</div>
                <div class="upi-meta">${formatSize(file.size)} · ${fType}</div>
                <div class="upi-progress"><div class="upi-progress-bar" style="width:0%"></div></div>
            </div>
        </div>`;
    }
    queue.innerHTML = html;
    // Animate progress bars
    setTimeout(() => {
        queue.querySelectorAll('.upi-progress-bar').forEach(bar => {
            bar.style.width = '30%';
        });
    }, 100);
}

function updateUploadPreviewProgress(fileName, pct) {
    const queue = document.getElementById('upload-preview-queue');
    if (!queue) return;
    const item = queue.querySelector(`[data-upload-name="${fileName}"]`);
    if (item) {
        const bar = item.querySelector('.upi-progress-bar');
        if (bar) bar.style.width = pct + '%';
    }
}

function clearUploadPreview() {
    const queue = document.getElementById('upload-preview-queue');
    if (queue) { queue.innerHTML = ''; queue.style.display = 'none'; }
}

