// --- Dashboard Analytics (Enhanced) ---
function renderDashboardAnalytics() {
    const isId = APP.lang === 'id';
    const activeFiles = APP.files.filter(f => !f.trashed);
    const totalUsed = activeFiles.reduce((sum, f) => sum + (f.size || 0), 0);
    const maxStorage = getStorageLimitBytes();
    const usedPercent = maxStorage > 0 ? Math.min((totalUsed / maxStorage) * 100, 100) : 0;

    // Total Downloads from shares
    const totalDownloads = APP.shares.reduce((sum, s) => sum + (s.downloadCount || 0), 0);

    // Total Shares
    const totalShares = APP.shares.length;

    // Storage Growth: compare current week vs last week
    const now = Date.now();
    const thisWeekStart = now - 7 * 86400000;
    const lastWeekStart = now - 14 * 86400000;
    const thisWeekStorage = activeFiles.filter(f => f.uploadedAt >= thisWeekStart).reduce((sum, f) => sum + (f.size || 0), 0);
    const lastWeekStorage = activeFiles.filter(f => f.uploadedAt >= lastWeekStart && f.uploadedAt < thisWeekStart).reduce((sum, f) => sum + (f.size || 0), 0);
    const growthDiff = lastWeekStorage > 0 ? ((thisWeekStorage - lastWeekStorage) / lastWeekStorage * 100) : (thisWeekStorage > 0 ? 100 : 0);
    const growthUp = growthDiff >= 0;

    // Most Downloaded Files (top 5)
    const filesWithDl = activeFiles.map(f => {
        const shares = APP.shares.filter(s => s.fileId === f.id);
        const dlCount = shares.reduce((sum, s) => sum + (s.downloadCount || 0), 0);
        return { id: f.id, name: f.name, size: f.size, mime: f.mime, totalDownloads: dlCount };
    }).sort((a, b) => b.totalDownloads - a.totalDownloads).slice(0, 5);

    // Recent Uploads (last 5)
    const recentUploads = [...activeFiles].sort((a, b) => (b.uploadedAt || 0) - (a.uploadedAt || 0)).slice(0, 5);

    // Breakdown by type
    const typeMap = {
        image: { label: isId ? 'Foto' : 'Photos', color: '#10b981', size: 0 },
        video: { label: isId ? 'Video' : 'Videos', color: '#ef4444', size: 0 },
        audio: { label: isId ? 'Audio' : 'Audio', color: '#8b5cf6', size: 0 },
        document: { label: isId ? 'Dokumen' : 'Documents', color: '#3b82f6', size: 0 },
        other: { label: isId ? 'Lainnya' : 'Others', color: '#64748b', size: 0 }
    };
    const docTypes = ['document','pdf','spreadsheet','presentation','text','code'];
    activeFiles.forEach(f => {
        const fType = getFileType(f.name, f.mime);
        if (fType === 'image') typeMap.image.size += (f.size || 0);
        else if (fType === 'video') typeMap.video.size += (f.size || 0);
        else if (fType === 'audio') typeMap.audio.size += (f.size || 0);
        else if (docTypes.includes(fType)) typeMap.document.size += (f.size || 0);
        else typeMap.other.size += (f.size || 0);
    });

    // SVG ring (bigger)
    const r = 52, c = 2 * Math.PI * r;
    const offset = c - (usedPercent / 100) * c;
    const usedGB = (totalUsed / (1024*1024*1024)).toFixed(2);
    const level = usedPercent > 90 ? '#ef4444' : usedPercent > 75 ? '#f97316' : usedPercent > 50 ? '#f59e0b' : 'var(--accent)';
    const ringColor = level;

    let breakdownHtml = Object.values(typeMap).map(t => {
        const pct = totalUsed > 0 ? ((t.size / totalUsed) * 100).toFixed(1) : '0.0';
        return `<div style="display:flex;align-items:center;gap:8px;padding:4px 0">
            <div style="width:8px;height:8px;border-radius:50%;background:${t.color};flex-shrink:0"></div>
            <div style="flex:1;font-size:12px;color:var(--text)">${t.label}</div>
            <div style="font-size:11px;color:var(--text-secondary);font-family:'JetBrains Mono',monospace">${formatSize(t.size)}</div>
            <div style="font-size:11px;color:var(--text-secondary);width:40px;text-align:right">${pct}%</div>
        </div>`;
    }).join('');

    // Most downloaded mini-list
    const mostDownloadedHtml = filesWithDl.filter(f => f.totalDownloads > 0).length > 0
        ? filesWithDl.filter(f => f.totalDownloads > 0).map(f => {
            const fIcon = getFileIcon(getFileType(f.name, f.mime));
            return `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;cursor:pointer" onclick="openDetailPanel('${f.id}')">
                <div style="width:24px;height:24px;border-radius:6px;background:${fIcon.color}15;display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="fas ${fIcon.icon}" style="color:${fIcon.color};font-size:10px"></i></div>
                <div style="flex:1;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${f.name}</div>
                <div style="font-size:11px;font-weight:700;color:var(--accent);font-family:'JetBrains Mono',monospace">${f.totalDownloads}</div>
            </div>`;
        }).join('')
        : `<div style="font-size:11px;color:var(--text-secondary);padding:8px 0">${isId ? 'Belum ada unduhan' : 'No downloads yet'}</div>`;

    // Recent uploads mini-list
    const recentUploadsHtml = recentUploads.length > 0 ? recentUploads.map(f => {
        const fIcon = getFileIcon(getFileType(f.name, f.mime));
        return `<div style="display:flex;align-items:center;gap:8px;padding:4px 0;cursor:pointer" onclick="openDetailPanel('${f.id}')">
            <div style="width:24px;height:24px;border-radius:6px;background:${fIcon.color}15;display:flex;align-items:center;justify-content:center;flex-shrink:0"><i class="fas ${fIcon.icon}" style="color:${fIcon.color};font-size:10px"></i></div>
            <div style="flex:1;font-size:11px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${f.name}</div>
            <div style="font-size:10px;color:var(--text-secondary)">${formatSize(f.size || 0)}</div>
        </div>`;
    }).join('') : `<div style="font-size:11px;color:var(--text-secondary);padding:8px 0">${isId ? 'Belum ada file' : 'No files yet'}</div>`;

    // Storage growth indicator
    const growthHtml = `<div style="display:flex;align-items:center;gap:4px;font-size:11px;font-weight:600;${growthUp ? 'color:#10b981' : 'color:#ef4444'}">
        <i class="fas fa-arrow-${growthUp ? 'up' : 'down'}" style="font-size:10px"></i>
        ${Math.abs(growthDiff).toFixed(1)}%
        <span style="color:var(--text-secondary);font-weight:400">${isId ? 'minggu ini' : 'this week'}</span>
    </div>`;

    return `<div class="dash-card-title"><i class="fas fa-chart-pie"></i> ${isId ? 'Analisis Penyimpanan' : 'Storage Analytics'}</div>
        <div style="font-size:11px;color:var(--text-secondary);margin-bottom:12px">${Math.max(APP.bots.length || 1, 1)} bot · 2 GB/bot = ${formatSize(maxStorage)}</div>
        <div style="display:flex;gap:20px;align-items:flex-start">
            <!-- Ring Chart -->
            <div style="flex-shrink:0;text-align:center">
                <svg viewBox="0 0 120 120" width="120" height="120" style="transform:rotate(-90deg)">
                    <circle cx="60" cy="60" r="${r}" fill="none" stroke="var(--bg-secondary)" stroke-width="8"/>
                    <circle cx="60" cy="60" r="${r}" fill="none" stroke="${ringColor}" stroke-width="8" stroke-dasharray="${c}" stroke-dashoffset="${c}" data-target-offset="${offset}" class="storage-ring-fill" style="stroke-dashoffset:${c};transition:stroke-dashoffset .8s cubic-bezier(.4,0,.2,1);stroke-linecap:round"/>
                </svg>
                <div style="margin-top:-76px;position:relative;text-align:center;margin-bottom:30px">
                    <div style="font-size:18px;font-weight:700;color:var(--text);font-family:'JetBrains Mono',monospace">${usedGB} GB</div>
                    <div style="font-size:10px;color:var(--text-secondary)">${isId ? 'dari' : 'of'} ${formatSize(maxStorage)}</div>
                </div>
            </div>
            <!-- Breakdown + Growth -->
            <div style="flex:1;min-width:0">
                <div style="margin-bottom:8px">${growthHtml}</div>
                ${breakdownHtml}
            </div>
        </div>
        <!-- Most Downloaded + Recent Uploads -->
        <div style="margin-top:14px;display:grid;grid-template-columns:1fr 1fr;gap:12px">
            <div>
                <div style="font-size:10px;font-weight:600;color:var(--text-secondary);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">${isId ? 'Paling Diunduh' : 'Most Downloaded'}</div>
                ${mostDownloadedHtml}
            </div>
            <div>
                <div style="font-size:10px;font-weight:600;color:var(--text-secondary);text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px">${isId ? 'Unggahan Terbaru' : 'Recent Uploads'}</div>
                ${recentUploadsHtml}
            </div>
        </div>`;
}

// --- Storage Analytics Card ---
function renderStorageAnalyticsCard() {
    const files = APP.files.filter(f => !f.trashed);
    const totalUsed = files.reduce((sum, f) => sum + (f.size || 0), 0);
    const maxStorage = getStorageLimitBytes();
    const usedPercent = maxStorage > 0 ? Math.min((totalUsed / maxStorage) * 100, 100) : 0;

    // Calculate breakdown by type
    const typeMap = { image: { label: APP.lang==='id'?'Foto':'Photos', color: '#10b981', size: 0 },
        video: { label: APP.lang==='id'?'Video':'Videos', color: '#ef4444', size: 0 },
        audio: { label: APP.lang==='id'?'Audio':'Audio', color: '#8b5cf6', size: 0 },
        document: { label: APP.lang==='id'?'Dokumen':'Documents', color: '#3b82f6', size: 0 },
        other: { label: APP.lang==='id'?'Lainnya':'Others', color: '#64748b', size: 0 } };
    const docTypes = ['document','pdf','spreadsheet','presentation','text','code'];
    files.forEach(f => {
        const fType = getFileType(f.name, f.mime);
        if (fType === 'image') typeMap.image.size += (f.size || 0);
        else if (fType === 'video') typeMap.video.size += (f.size || 0);
        else if (fType === 'audio') typeMap.audio.size += (f.size || 0);
        else if (docTypes.includes(fType)) typeMap.document.size += (f.size || 0);
        else typeMap.other.size += (f.size || 0);
    });

    // SVG ring parameters
    const r = 40, c = 2 * Math.PI * r;
    const offset = c - (usedPercent / 100) * c;

    const usedGB = (totalUsed / (1024*1024*1024)).toFixed(2);
    const level = getStorageWarningLevel(totalUsed);
    const ringColor = level === 'red' ? '#ef4444' : level === 'orange' ? '#f97316' : level === 'yellow' ? '#f59e0b' : 'var(--accent)';

    let breakdownHtml = Object.values(typeMap).map(t => {
        const pct = totalUsed > 0 ? ((t.size / totalUsed) * 100).toFixed(1) : '0.0';
        return `<div class="storage-breakdown-item">
            <div class="storage-breakdown-dot" style="background:${t.color}"></div>
            <div class="storage-breakdown-label">${t.label}</div>
            <div class="storage-breakdown-pct">${pct}%</div>
        </div>`;
    }).join('');

    const botCount = Math.max(APP.bots.length || 1, 1);
    return `<div class="dash-card-title"><i class="fas fa-chart-pie"></i> ${APP.lang==='id'?'Penyimpanan':'Storage'}</div>
        <div style="font-size:11px;color:var(--text-secondary);margin-bottom:8px">${botCount} bot · 2 GB/bot = ${formatSize(maxStorage)}</div>
        <div class="storage-ring-wrap">
            <svg class="storage-ring-svg" viewBox="0 0 100 100">
                <circle class="storage-ring-bg" cx="50" cy="50" r="${r}"/>
                <circle class="storage-ring-fill" cx="50" cy="50" r="${r}"
                    stroke-dasharray="${c}" stroke-dashoffset="${c}"
                    data-target-offset="${offset}" style="stroke-dashoffset:${c};stroke:${ringColor}"/>
                <text class="storage-ring-center" x="50" y="46" fill="var(--text)" font-size="10" font-weight="700" font-family="JetBrains Mono,monospace">${usedGB} GB</text>
                <text class="storage-ring-center" x="50" y="58" fill="var(--text-secondary)" font-size="7" font-family="Space Grotesk,sans-serif">/ ${formatSize(maxStorage)}</text>
            </svg>
            <div class="storage-breakdown">${breakdownHtml}</div>
        </div>`;
}

// Animate storage ring on load
function animateStorageRing() {
    const fill = document.querySelector('#storage-analytics-card .storage-ring-fill');
    if (!fill) return;
    const target = fill.getAttribute('data-target-offset');
    // Trigger animation after a short delay
    requestAnimationFrame(() => {
        requestAnimationFrame(() => {
            fill.style.strokeDashoffset = target;
        });
    });
}

// --- Weekly Summary Card ---
function renderWeeklySummaryCard() {
    const files = APP.files.filter(f => !f.trashed);
    const now = Date.now();
    const weekAgo = now - 7 * 24 * 60 * 60 * 1000;
    const weekFiles = files.filter(f => f.uploadedAt && f.uploadedAt >= weekAgo);
    const uploadedCount = weekFiles.length;
    const weekStorage = weekFiles.reduce((s, f) => s + (f.size || 0), 0);
    const weekShared = weekFiles.filter(f => f.shareCount > 0).length;

    // Most active day
    const dayNames = APP.lang === 'id'
        ? ['Minggu','Senin','Selasa','Rabu','Kamis','Jumat','Sabtu']
        : ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];
    const dayCounts = {};
    weekFiles.forEach(f => {
        if (f.uploadedAt) {
            const day = new Date(f.uploadedAt).getDay();
            dayCounts[day] = (dayCounts[day] || 0) + 1;
        }
    });
    let mostActiveDay = '-';
    let maxDayCount = 0;
    for (const [day, count] of Object.entries(dayCounts)) {
        if (count > maxDayCount) { maxDayCount = count; mostActiveDay = dayNames[parseInt(day)]; }
    }

    return `<div class="dash-card-title"><i class="fas fa-calendar-week"></i> ${APP.lang==='id'?'Minggu Ini':'This Week'}</div>
        <div class="weekly-stat-grid">
            <div class="weekly-stat">
                <div class="weekly-stat-val">${uploadedCount}</div>
                <div class="weekly-stat-label">${APP.lang==='id'?'File Diunggah':'Files Uploaded'}</div>
            </div>
            <div class="weekly-stat">
                <div class="weekly-stat-val">${formatSize(weekStorage)}</div>
                <div class="weekly-stat-label">${APP.lang==='id'?'Penyimpanan':'Storage Used'}</div>
            </div>
            <div class="weekly-stat">
                <div class="weekly-stat-val">${weekShared}</div>
                <div class="weekly-stat-label">${APP.lang==='id'?'Dibagikan':'Shared'}</div>
            </div>
            <div class="weekly-stat">
                <div class="weekly-stat-val" style="font-size:16px">${mostActiveDay}</div>
                <div class="weekly-stat-label">${APP.lang==='id'?'Hari Teraktif':'Most Active'}</div>
            </div>
        </div>`;
}

// --- Top Files Widget ---
function renderTopFilesCard() {
    const files = APP.files.filter(f => !f.trashed).sort((a, b) => (b.size || 0) - (a.size || 0)).slice(0, 5);
    const maxSize = files.length > 0 ? files[0].size || 1 : 1;

    if (files.length === 0) {
        return `<div class="dash-card-title"><i class="fas fa-ranking-star"></i> ${APP.lang==='id'?'File Terbesar':'Top Files'}</div>
            <div style="text-align:center;padding:20px 0;color:var(--text-secondary);font-size:12px">${APP.lang==='id'?'Belum ada file':'No files yet'}</div>`;
    }

    let itemsHtml = files.map(f => {
        const fType = getFileType(f.name, f.mime);
        const fIcon = getFileIcon(fType);
        const barWidth = ((f.size || 0) / maxSize * 100).toFixed(1);
        return `<div class="top-file-item" onclick="openDetailPanel('${f.id}')" style="cursor:pointer">
            <div class="top-file-icon" style="background:${fIcon.color}15;color:${fIcon.color}"><i class="fas ${fIcon.icon}"></i></div>
            <div class="top-file-info">
                <div class="top-file-name" title="${f.name}">${f.name}</div>
                <div class="top-file-size">${formatSize(f.size || 0)}</div>
                <div class="top-file-bar"><div class="top-file-bar-fill" style="width:${barWidth}%;background:${fIcon.color}"></div></div>
            </div>
        </div>`;
    }).join('');

    return `<div class="dash-card-title"><i class="fas fa-ranking-star"></i> ${APP.lang==='id'?'File Terbesar':'Top Files'}</div>
        ${itemsHtml}
        <div class="top-file-link" onclick="APP.sortBy='size';renderFileList()">${APP.lang==='id'?'Lihat Semua':'View All'}</div>`;
}

// --- Activity Timeline ---
// _activityCache is stored in APP._activityCache (initialized in APP object)

async function logActivity(type, description) {
    const entry = {
        key: 'activityLog',
        log: [] // Will be replaced
    };
    try {
        const existing = await dbGet('settings', 'activityLog');
        const log = existing ? (existing.log || []) : [];
        log.unshift({
            type,
            description,
            timestamp: Date.now()
        });
        // Keep only last 50 entries
        if (log.length > 50) log.length = 50;
        entry.log = log;
        await dbPut('settings', entry);
        APP._activityCache = log;
        // Update activity timeline if visible
        refreshActivityUI();
    } catch(e) {
        console.warn('logActivity error:', e);
        // Fallback to memory-only
        if (!APP._activityCache) APP._activityCache = [];
        APP._activityCache.unshift({ type, description, timestamp: Date.now() });
        if (APP._activityCache.length > 50) APP._activityCache.length = 50;
        refreshActivityUI();
    }
}

async function loadActivityLog() {
    if (APP._activityCache) return APP._activityCache;
    try {
        const data = await dbGet('settings', 'activityLog');
        APP._activityCache = data ? (data.log || []) : [];
    } catch(e) {
        APP._activityCache = [];
    }
    return APP._activityCache;
}

function refreshActivityUI() {
    const cardTL = document.getElementById('activity-card');
    if (cardTL) {
        const inner = cardTL.querySelector('.activity-timeline');
        if (inner) inner.innerHTML = renderActivityItems();
    }
}

function renderActivityTimeline() {
    return `<div class="dash-card-title"><i class="fas fa-clock-rotate-left"></i> ${APP.lang==='id'?'Aktivitas Terbaru':'Recent Activity'}</div>
        <div class="activity-timeline">${renderActivityItems()}</div>`;
}

function renderActivityItems() {
    const log = APP._activityCache || [];
    const last20 = log.slice(0, 20);
    if (last20.length === 0) {
        return `<div style="text-align:center;padding:20px 0;color:var(--text-secondary);font-size:12px">${APP.lang==='id'?'Belum ada aktivitas':'No activity yet'}</div>`;
    }
    const typeConfig = {
        upload: { icon: 'fa-cloud-arrow-up', color: '#10b981' },
        download: { icon: 'fa-download', color: '#3b82f6' },
        share: { icon: 'fa-share-alt', color: '#8b5cf6' },
        delete: { icon: 'fa-trash', color: '#ef4444' },
        rename: { icon: 'fa-pen', color: '#f59e0b' },
        move: { icon: 'fa-arrows-alt', color: '#06b6d4' }
    };
    return last20.map(a => {
        const cfg = typeConfig[a.type] || typeConfig.move;
        return `<div class="activity-item">
            <div class="activity-icon" style="background:${cfg.color}15;color:${cfg.color}"><i class="fas ${cfg.icon}"></i></div>
            <div class="activity-body">
                <div class="activity-desc">${a.description}</div>
                <div class="activity-time">${timeAgo(a.timestamp)}</div>
            </div>
        </div>`;
    }).join('');
}

function timeAgo(ts) {
    if (!ts) return '';
    const diff = Date.now() - ts;
    if (diff < 60000) return APP.lang === 'id' ? 'Baru saja' : 'Just now';
    if (diff < 3600000) return Math.floor(diff / 60000) + (APP.lang === 'id' ? 'm lalu' : 'm ago');
    if (diff < 86400000) return Math.floor(diff / 3600000) + (APP.lang === 'id' ? 'j lalu' : 'h ago');
    if (diff < 604800000) return Math.floor(diff / 86400000) + (APP.lang === 'id' ? 'h lalu' : 'd ago');
    return new Date(ts).toLocaleDateString(APP.lang === 'id' ? 'id-ID' : 'en-US', { day: 'numeric', month: 'short' });
}

// Preload activity log when dashboard renders
async function preloadActivityLog() {
    await loadActivityLog();
    refreshActivityUI();
}

// ===== KEYBOARD SHORTCUTS (Enhanced) =====
function openShortcutsPanel() {
    const isId = APP.lang === 'id';
    openModal(`<div style="padding:24px">
        <h3 style="font-size:17px;font-weight:600;margin-bottom:16px;display:flex;align-items:center;gap:8px"><i class="fas fa-keyboard" style="color:var(--accent)"></i> ${isId?'Pintasan Keyboard':'Keyboard Shortcuts'}</h3>
        <div class="shortcuts-grid">
            <div class="shortcut-section">${isId?'File':'File'}</div>
            <div class="shortcut-row"><kbd>N</kbd><span class="shortcut-desc">${t('upload')}</span></div>
            <div class="shortcut-row"><kbd>F</kbd><span class="shortcut-desc">${t('newFolder')}</span></div>
            <div class="shortcut-row"><kbd>Del</kbd><span class="shortcut-desc">${isId?'Hapus file terpilih':'Delete selected file'}</span></div>
            <div class="shortcut-row"><kbd>E</kbd><span class="shortcut-desc">${isId?'Edit/Ganti Nama':'Edit/Rename selected'}</span></div>
            <div class="shortcut-row"><kbd>S</kbd><span class="shortcut-desc">${isId?'Bintangi/Lepas':'Star/Unstar selected'}</span></div>
            <div class="shortcut-section">${isId?'Navigasi':'Navigation'}</div>
            <div class="shortcut-row"><kbd>/</kbd><span class="shortcut-desc">${isId?'Fokus pencarian':'Focus search'}</span></div>
            <div class="shortcut-row"><kbd>G</kbd> <kbd>D</kbd><span class="shortcut-desc">${isId?'Ke Dashboard':'Go to Dashboard'}</span></div>
            <div class="shortcut-row"><kbd>G</kbd> <kbd>A</kbd><span class="shortcut-desc">${isId?'Ke Semua File':'Go to All Files'}</span></div>
            <div class="shortcut-row"><kbd>G</kbd> <kbd>T</kbd><span class="shortcut-desc">${isId?'Ke Sampah':'Go to Trash'}</span></div>
            <div class="shortcut-section">${isId?'Tampilan':'View'}</div>
            <div class="shortcut-row"><kbd>V</kbd><span class="shortcut-desc">${isId?'Grid/List/Kategori':'Toggle grid/list/categories'}</span></div>
            <div class="shortcut-row"><kbd>B</kbd><span class="shortcut-desc">${t('batchMode')}</span></div>
            <div class="shortcut-row"><kbd>D</kbd><span class="shortcut-desc">${isId?'Tema Gelap/Terang':'Toggle dark/light'}</span></div>
            <div class="shortcut-section">${isId?'Umum':'General'}</div>
            <div class="shortcut-row"><kbd>?</kbd> <kbd>Ctrl</kbd>+<kbd>/</kbd><span class="shortcut-desc">${isId?'Pintasan keyboard':'Keyboard shortcuts'}</span></div>
            <div class="shortcut-row"><kbd>Esc</kbd><span class="shortcut-desc">${isId?'Tutup panel/modal':'Close panels/modals'}</span></div>
        </div>
    </div>`);
}

document.addEventListener('keydown', (e) => {
    const inInput = !!e.target.closest('input,textarea,select');
    // G-then-X sequence (navigation)
    if (APP.gSequence) {
        APP.gSequence = false;
        if (!inInput) {
            if (e.key === 'd') { selectFolder('all'); return; }
            if (e.key === 'a') { selectFolder('all'); return; }
            if (e.key === 't') { selectFolder('trash'); return; }
        }
        return;
    }
    // Toggle shortcuts panel
    if ((e.key === '?' || (e.ctrlKey && e.key === '/')) && !inInput) {
        e.preventDefault();
        openShortcutsPanel();
        return;
    }
    if (e.key === 'Escape') {
        closeModal();
        closeDetailPanel();
        closeContextMenu();
        APP.gSequence = false;
        return;
    }
    if (inInput) return;
    // File actions
    if (e.key === 'n' || e.key === 'N') { triggerUpload(); return; }
    if (e.key === 'f' || e.key === 'F') { createFolderDialog(); return; }
    if (e.key === '/') { e.preventDefault(); const s = document.querySelector('.search-premium input'); if (s) s.focus(); return; }
    if (e.key === 'g' || e.key === 'G') { APP.gSequence = true; setTimeout(() => { APP.gSequence = false; }, 1000); return; }
    if (e.key === 'v' || e.key === 'V') {
        const views = ['list','grid','categories'];
        const idx = views.indexOf(APP.currentView);
        APP.currentView = views[(idx + 1) % views.length];
        renderFileList();
        return;
    }
    if (e.key === 'b' || e.key === 'B') { APP.batchMode = !APP.batchMode; renderFileList(); return; }
    if (e.key === 'd' || e.key === 'D') { toggleTheme(); return; }
    // Actions on selected file
    if (APP.selectedFiles.size === 1) {
        const fileId = [...APP.selectedFiles][0];
        if (e.key === 'Delete') { moveToTrash(fileId); return; }
        if (e.key === 'e' || e.key === 'E') { startRename(fileId); return; }
        if (e.key === 's' || e.key === 'S') { toggleStar(fileId); return; }
    }
    // Legacy: u for upload
    if (e.key === 'u' || e.key === 'U') { triggerUpload(); return; }
});

// ===== COLOR TAGS ENHANCEMENT =====
var TAG_COLORS = [
    { name: 'Red', hex: '#ef4444' },
    { name: 'Orange', hex: '#f97316' },
    { name: 'Yellow', hex: '#eab308' },
    { name: 'Green', hex: '#22c55e' },
    { name: 'Blue', hex: '#3b82f6' },
    { name: 'Purple', hex: '#8b5cf6' },
    { name: 'Pink', hex: '#ec4899' },
    { name: 'Gray', hex: '#6b7280' }
];

// ===== FILE PREVIEW CAROUSEL =====
function renderCarousel() {
    const recentFiles = [...APP.files].filter(f => !f.trashed).sort((a, b) => (b.uploadedAt || 0) - (a.uploadedAt || 0)).slice(0, 8);
    if (recentFiles.length === 0) return '';

    const cards = recentFiles.map(f => {
        const type = getFileType(f.name, f.mime);
        const icon = getFileIcon(type);
        const name = f.name.length > 16 ? f.name.substring(0, 14) + '…' : f.name;
        return `<div class="carousel-card" onclick="openDetailPanel('${f.id}')" title="${f.name}">
            ${f.tag ? `<span class="cc-tag" style="background:${f.tag}"></span>` : ''}
            <div class="cc-icon" style="background:${icon.color}15"><i class="fas ${icon.icon}" style="color:${icon.color}"></i></div>
            <div class="cc-name">${name}</div>
            <div class="cc-date">${formatDate(f.uploadedAt)}</div>
        </div>`;
    }).join('');

    return `<div class="carousel-wrap" id="carousel-wrap"
        onmouseenter="pauseCarousel()" onmouseleave="resumeCarousel()"
        ontouchstart="pauseCarousel()" ontouchend="resumeCarousel()">
        <button class="carousel-nav prev" onclick="scrollCarousel(-1)" aria-label="Previous"><i class="fas fa-chevron-left"></i></button>
        <div class="carousel-track" id="recent-carousel-track">${cards}</div>
        <button class="carousel-nav next" onclick="scrollCarousel(1)" aria-label="Next"><i class="fas fa-chevron-right"></i></button>
        <div class="carousel-dots" id="recent-carousel-dots">${recentFiles.map((_, i) => `<span class="carousel-dot ${i === 0 ? 'active' : ''}" data-idx="${i}"></span>`).join('')}</div>
    </div>`;
}

function scrollCarousel(dir) {
    const track = document.getElementById('recent-carousel-track');
    if (!track) return;
    const cardW = 150; // card width + gap
    track.scrollBy({ left: dir * cardW * 2, behavior: 'smooth' });
}

function pauseCarousel() {
    if (APP.carouselTimer) { clearInterval(APP.carouselTimer); APP.carouselTimer = null; }
}

function resumeCarousel() {
    startCarouselAutoScroll();
}

function startCarouselAutoScroll() {
    if (APP.carouselTimer) clearInterval(APP.carouselTimer);
    APP.carouselTimer = setInterval(() => {
        const track = document.getElementById('recent-carousel-track');
        if (!track) { clearInterval(APP.carouselTimer); return; }
        const maxScroll = track.scrollWidth - track.clientWidth;
        if (track.scrollLeft >= maxScroll - 10) {
            track.scrollTo({ left: 0, behavior: 'smooth' });
        } else {
            track.scrollBy({ left: 150, behavior: 'smooth' });
        }
        updateCarouselDots();
    }, 5000);
}

function updateCarouselDots() {
    const track = document.getElementById('recent-carousel-track');
    const dots = document.querySelectorAll('#recent-carousel-dots .carousel-dot');
    if (!track || !dots.length) return;
    const cardW = 150;
    const idx = Math.round(track.scrollLeft / cardW);
    dots.forEach((d, i) => d.classList.toggle('active', i === Math.min(idx, dots.length - 1)));
}

// ===== COLOR TAGS ENHANCEMENT (functions only — TAG_COLORS defined above) =====

function renderTagFilterBar() {
    const bar = document.getElementById('tag-filter-bar');
    if (!bar) return;
    const activeTag = APP.tagFilter;
    let html = `<span style="font-size:11px;color:var(--text-secondary);margin-right:4px"><i class="fas fa-tag" style="font-size:10px"></i></span>`;
    html += TAG_COLORS.map(c => {
        const isActive = activeTag === c.hex;
        return `<button class="tag-filter-btn ${isActive ? 'active' : ''}" onclick="toggleTagFilter('${c.hex}')" title="${c.name}">
            <span class="tf-dot" style="background:${c.hex}"></span>
        </button>`;
    }).join('');
    if (activeTag) {
        html += `<button class="tag-filter-btn" onclick="toggleTagFilter(null)" title="${APP.lang==='id'?'Hapus filter':'Clear filter'}" aria-label="Clear filter"><i class="fas fa-times" style="font-size:10px"></i></button>`;
    }
    bar.innerHTML = html;
}

function toggleTagFilter(color) {
    APP.tagFilter = APP.tagFilter === color ? null : color;
    renderTagFilterBar();
    renderFileList();
}

function renderDetailTagPicker(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return '';
    let html = `<div style="margin-bottom:14px"><div style="font-size:11px;font-weight:600;color:var(--text-secondary);margin-bottom:6px;text-transform:uppercase;letter-spacing:.5px">${t('addTag')}</div><div class="detail-tag-picker">`;
    html += TAG_COLORS.map(c => {
        const isActive = file.tag === c.hex;
        return `<button class="detail-tag-dot ${isActive ? 'active' : ''}" style="background:${c.hex}" onclick="executeTagDetail('${fileId}','${c.hex}')" title="${c.name}" aria-label="Tag"></button>`;
    }).join('');
    html += `<button class="detail-tag-remove" onclick="executeTagDetail('${fileId}','')" title="${APP.lang==='id'?'Hapus tag':'Remove tag'}" aria-label="Remove tag"><i class="fas fa-times"></i></button>`;
    html += '</div></div>';
    return html;
}

async function executeTagDetail(fileId, color) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;
    file.tag = color || '';
    await saveFile(file);
    openDetailPanel(fileId); // Re-render detail panel
    renderFileList();
}

// ===== SMART CATEGORIES / AUTO-GROUP =====
function getFileCategory(name, mime) {
    const ext = (name || '').split('.').pop().toLowerCase();
    const docExts = ['pdf','doc','docx','txt','xls','xlsx','ppt','pptx'];
    const photoExts = ['jpg','jpeg','png','gif','webp','svg','bmp'];
    const videoExts = ['mp4','avi','mov','mkv','webm','flv'];
    const audioExts = ['mp3','wav','ogg','flac','aac','m4a'];
    const archiveExts = ['zip','rar','7z','tar','gz'];
    const codeExts = ['js','py','html','css','json','xml','ts','jsx','tsx','yaml','yml','md','sh','sql','go','rs','rb','php','java','c','cpp','h'];
    if (docExts.includes(ext)) return 'documents';
    if (photoExts.includes(ext)) return 'photos';
    if (videoExts.includes(ext)) return 'videos';
    if (audioExts.includes(ext)) return 'audio';
    if (archiveExts.includes(ext)) return 'archives';
    if (codeExts.includes(ext)) return 'code';
    return 'others';
}

function getCategoryInfo(cat) {
    const map = {
        documents: { icon: 'fa-file-alt', name: APP.lang==='id'?'Dokumen':'Documents', css: 'cat-docs' },
        photos:    { icon: 'fa-image', name: APP.lang==='id'?'Foto':'Photos', css: 'cat-photos' },
        videos:    { icon: 'fa-film', name: APP.lang==='id'?'Video':'Videos', css: 'cat-videos' },
        audio:     { icon: 'fa-music', name: APP.lang==='id'?'Audio':'Audio', css: 'cat-audio' },
        archives:  { icon: 'fa-box-archive', name: APP.lang==='id'?'Arsip':'Archives', css: 'cat-archives' },
        code:      { icon: 'fa-code', name: APP.lang==='id'?'Kode':'Code', css: 'cat-code' },
        others:    { icon: 'fa-folder', name: APP.lang==='id'?'Lainnya':'Others', css: 'cat-others' }
    };
    return map[cat] || map.others;
}

function renderCategoriesView() {
    const files = APP.files.filter(f => !f.trashed);
    // Group by category
    const groups = {};
    files.forEach(f => {
        const cat = getFileCategory(f.name, f.mime);
        if (!groups[cat]) groups[cat] = [];
        groups[cat].push(f);
    });
    const catOrder = ['documents','photos','videos','audio','archives','code','others'];
    let html = '<div class="categories-grid">';
    catOrder.forEach((cat, idx) => {
        const info = getCategoryInfo(cat);
        const catFiles = groups[cat] || [];
        const count = catFiles.length;
        const totalSize = catFiles.reduce((s, f) => s + (f.size || 0), 0);
        html += `<div class="category-card ${info.css} cat-card-anim" style="animation-delay:${idx * 0.06}s" onclick="filterByCategory('${cat}')">
            <div class="cat-icon"><i class="fas ${info.icon}"></i></div>
            <div class="cat-name">${info.name}</div>
            <div class="cat-count">${count} ${APP.lang==='id'?'file':'files'}</div>
            ${count > 0 ? `<div class="cat-size">${formatSize(totalSize)}</div>` : ''}
        </div>`;
    });
    html += '</div>';
    return html;
}

function filterByCategory(cat) {
    // Map category to filterType used by existing filter
    const catToType = {
        documents: 'document',
        photos: 'image',
        videos: 'video',
        audio: 'audio',
        archives: 'archive',
        code: 'code',
        others: 'other'
    };
    APP.filterType = catToType[cat] || 'all';
    APP.currentView = 'grid'; // Switch to grid to show filtered files
    renderFileList();
    showToast(`${getCategoryInfo(cat).name}`, 'info', 1500);
}

// ===== CUSTOM SORT PRESETS =====
function applySortPreset(preset) {
    if (preset === APP.activeSortPreset) {
        // Toggle off
        APP.activeSortPreset = '';
        APP.sortBy = 'date';
        APP.sortOrder = 'desc';
        APP.quickFilter = null;
    } else {
        APP.activeSortPreset = preset;
        switch (preset) {
            case 'terbaru':
                APP.sortBy = 'date';
                APP.sortOrder = 'desc';
                APP.quickFilter = null;
                break;
            case 'terbesar':
                APP.sortBy = 'size';
                APP.sortOrder = 'desc';
                APP.quickFilter = null;
                break;
            case 'az':
                APP.sortBy = 'name';
                APP.sortOrder = 'asc';
                APP.quickFilter = null;
                break;
            case 'favorit':
                APP.sortBy = 'date';
                APP.sortOrder = 'desc';
                APP.quickFilter = 'pinned';
                break;
        }
    }
    localStorage.setItem('rb_sort_preset', APP.activeSortPreset);
    // Update sort selector
    const sortSel = document.querySelector('.toolbar-sort');
    if (sortSel) sortSel.value = APP.sortBy;
    renderFileList();
    updateSortPresetButtons();
}

function updateSortPresetButtons() {
    document.querySelectorAll('.sort-preset-btn').forEach(btn => {
        const p = btn.getAttribute('data-preset');
        btn.classList.toggle('active', p === APP.activeSortPreset);
    });
}

function renderSortPresets() {
    const presets = [
        { key: 'terbaru', label: APP.lang==='id'?'Terbaru':'Newest', icon: 'fa-clock' },
        { key: 'terbesar', label: APP.lang==='id'?'Terbesar':'Largest', icon: 'fa-weight-hanging' },
        { key: 'az', label: 'A-Z', icon: 'fa-arrow-down-a-z' },
        { key: 'favorit', label: APP.lang==='id'?'Favorit':'Favorites', icon: 'fa-star' }
    ];
    return `<div class="sort-preset-wrap">${presets.map(p =>
        `<button class="sort-preset-btn ${APP.activeSortPreset === p.key ? 'active' : ''}" data-preset="${p.key}" onclick="applySortPreset('${p.key}')"><i class="fas ${p.icon}" style="font-size:10px"></i> ${p.label}</button>`
    ).join('')}</div>`;
}

// ===== VIEW MODE CYCLING =====
function cycleViewMode() {
    const views = ['list', 'grid', 'categories'];
    const idx = views.indexOf(APP.currentView);
    APP.currentView = views[(idx + 1) % views.length];
    renderFileList();
}

// ===== PULL-TO-REFRESH (F21 Enhanced) =====
let _ptrActive = false, _ptrStartY = 0, _ptrPulling = false;
const PTR_THRESHOLD = 60;
function setupPullToRefresh() {
    if (APP.viewMode !== 'mobile') return; // Only on mobile
    const container = document.getElementById('file-list-container');
    if (!container || container._ptrInit) return;
    container._ptrInit = true;
    container.addEventListener('touchstart', (e) => {
        if (container.scrollTop > 0) return;
        _ptrStartY = e.touches[0].clientY;
        _ptrPulling = true;
    }, { passive: true });
    container.addEventListener('touchmove', (e) => {
        if (!_ptrPulling || _ptrActive) return;
        const dy = e.touches[0].clientY - _ptrStartY;
        if (dy < 0 || container.scrollTop > 0) { _ptrPulling = false; return; }
        const ptr = document.getElementById('ptr-indicator');
        const arrow = document.getElementById('ptr-arrow');
        const ptrText = document.getElementById('ptr-text');
        if (!ptr) return;
        const isId = APP.lang === 'id';
        const h = Math.min(dy * 0.5, 80);
        ptr.style.height = h + 'px';
        // Rotate arrow based on pull distance
        if (arrow) {
            const rotation = Math.min(dy / PTR_THRESHOLD * 180, 180);
            arrow.style.transform = `rotate(${rotation}deg)`;
        }
        // Update text
        if (ptrText) {
            if (dy >= PTR_THRESHOLD * 2) {
                ptrText.textContent = isId ? 'Lepas untuk memuat ulang' : 'Release to refresh';
            } else {
                ptrText.textContent = isId ? 'Tarik untuk memuat ulang' : 'Pull to refresh';
            }
        }
    }, { passive: true });
    container.addEventListener('touchend', async () => {
        if (!_ptrPulling) return;
        _ptrPulling = false;
        const ptr = document.getElementById('ptr-indicator');
        const arrow = document.getElementById('ptr-arrow');
        const ptrText = document.getElementById('ptr-text');
        const spinner = document.querySelector('.ptr-spinner');
        if (!ptr) return;
        const isId = APP.lang === 'id';
        const h = parseInt(ptr.style.height) || 0;
        if (h >= PTR_THRESHOLD && !_ptrActive) {
            _ptrActive = true;
            haptic('ptr');
            ptr.style.height = '48px';
            if (arrow) { arrow.className = 'fas fa-spinner'; arrow.style.transform = ''; }
            if (spinner) spinner.classList.add('spinning');
            if (ptrText) ptrText.textContent = isId ? 'Memuat ulang...' : 'Refreshing...';
            await refreshUI();
            if (arrow) { arrow.className = 'fas fa-arrow-down'; arrow.style.transform = 'rotate(0deg)'; }
            if (spinner) spinner.classList.remove('spinning');
            // Spring back animation
            ptr.style.transition = 'height .3s cubic-bezier(.25,.46,.45,.94)';
            ptr.style.height = '0';
            setTimeout(() => { ptr.style.transition = 'height .2s ease'; }, 300);
            _ptrActive = false;
            showToast(isId ? 'Diperbarui' : 'Refreshed', 'success', 2000);
        } else {
            ptr.style.transition = 'height .3s cubic-bezier(.25,.46,.45,.94)';
            ptr.style.height = '0';
            if (arrow) arrow.style.transform = 'rotate(0deg)';
            setTimeout(() => { ptr.style.transition = 'height .2s ease'; }, 300);
        }
    }, { passive: true });
}

// ===== FILE DUPLICATE CHECKER =====
function findDuplicates() {
    const files = APP.files.filter(f => !f.trashed);
    const map = {};
    files.forEach(f => {
        const key = f.name + '::' + f.size;
        if (!map[key]) map[key] = [];
        map[key].push(f);
    });
    return Object.entries(map).filter(([, arr]) => arr.length > 1).map(([key, arr]) => {
        arr.sort((a, b) => (b.uploadedAt || 0) - (a.uploadedAt || 0));
        return { key, files: arr, newest: arr[0], duplicates: arr.slice(1), savings: arr.slice(1).reduce((s, f) => s + (f.size || 0), 0) };
    });
}

function openDuplicateChecker() {
    const groups = findDuplicates();
    const isId = APP.lang === 'id';
    const totalSavings = groups.reduce((s, g) => s + g.savings, 0);
    if (groups.length === 0) {
        showToast(isId ? 'Tidak ada file duplikat' : 'No duplicate files found', 'success');
        return;
    }
    openModal(`<div style="padding:24px;max-width:560px">
        <h3 style="font-size:18px;font-weight:600;margin-bottom:4px"><i class="fas fa-clone" style="color:var(--accent)"></i> ${isId ? 'Cek Duplikat' : 'Duplicate Checker'}</h3>
        <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${groups.length} ${isId ? 'grup duplikat ditemukan' : 'duplicate groups found'} · ${isId ? 'Hemat' : 'Save'} ${formatSize(totalSavings)}</p>
        <div style="max-height:400px;overflow-y:auto;display:flex;flex-direction:column;gap:12px">
            ${groups.map((g, gi) => `
                <div style="border:1px solid var(--border);border-radius:10px;overflow:hidden">
                    <div style="padding:10px 12px;background:var(--bg-secondary);display:flex;justify-content:space-between;align-items:center">
                        <span style="font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:200px">${g.newest.name}</span>
                        <span style="font-size:11px;color:var(--text-secondary)">${g.files.length}x · ${isId ? 'hemat' : 'save'} ${formatSize(g.savings)}</span>
                    </div>
                    <div style="padding:8px 12px">
                        <div style="font-size:12px;color:var(--accent);margin-bottom:4px"><i class="fas fa-check-circle"></i> ${isId ? 'Pertahankan (terbaru)' : 'Keep (newest)'}: ${formatSize(g.newest.size)} · ${formatDate(g.newest.uploadedAt)}</div>
                        ${g.duplicates.map(f => `
                            <div style="display:flex;align-items:center;gap:8px;padding:4px 0">
                                <span style="font-size:12px;color:var(--text-secondary);flex:1">${formatSize(f.size)} · ${formatDate(f.uploadedAt)}</span>
                                <button class="btn btn-danger btn-sm" style="font-size:11px;padding:2px 8px" onclick="deleteDuplicateFile('${f.id}',${gi})" aria-label="Delete duplicate"><i class="fas fa-trash"></i></button>
                            </div>
                        `).join('')}
                    </div>
                </div>
            `).join('')}
        </div>
        <div style="margin-top:16px;display:flex;gap:8px;justify-content:flex-end">
            <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
            <button class="btn btn-danger" onclick="deleteAllDuplicates()">${isId ? 'Hapus Semua Duplikat' : 'Delete All Duplicates'}</button>
        </div>
    </div>`);
}

async function deleteDuplicateFile(fileId, groupIdx) {
    await moveToTrash(fileId);
    showToast(APP.lang === 'id' ? 'Duplikat dihapus' : 'Duplicate removed', 'success');
    openDuplicateChecker();
}

async function deleteAllDuplicates() {
    const groups = findDuplicates();
    let count = 0;
    for (const g of groups) {
        for (const f of g.duplicates) {
            await moveToTrash(f.id);
            count++;
        }
    }
    closeModal();
    showToast(`${count} ${APP.lang === 'id' ? 'duplikat dihapus' : 'duplicates removed'}`, 'success');
    await refreshUI();
}

// ===== REAL STORAGE QUOTA =====
let _quotaCache = null, _quotaCacheTime = 0;
async function getStorageQuota() {
    const now = Date.now();
    if (_quotaCache && (now - _quotaCacheTime) < 300000) return _quotaCache;
    try {
        const allFiles = await dbGetAll('files');
        const totalUsed = allFiles.reduce((sum, f) => sum + (f.size || 0), 0);
        const botCount = Math.max(APP.bots.length || 1, 1);
        const totalQuota = botCount * 2 * 1024 * 1024 * 1024;
        _quotaCache = { totalUsed, totalQuota, botCount };
        _quotaCacheTime = now;
        return _quotaCache;
    } catch (e) {
        const totalUsed = APP.files.reduce((sum, f) => sum + (f.size || 0), 0);
        const botCount = Math.max(APP.bots.length || 1, 1);
        const totalQuota = botCount * 2 * 1024 * 1024 * 1024;
        return { totalUsed, totalQuota, botCount };
    }
}

function getStorageLimitBytes() {
    // Use subscription tier limit if available, otherwise fall back to bot-based calculation
    const subLimit = getSubscriptionLimit();
    if (subLimit > 0) return subLimit;
    const botCount = Math.max(APP.bots.length || 1, 1);
    const customLimit = parseInt(localStorage.getItem('rb_storage_limit_gb'));
    return (customLimit > 0 ? customLimit : botCount * 2) * 1024 * 1024 * 1024;
}

// ===== STORAGE QUOTA ENFORCEMENT (F16) =====
function getSubscriptionLimit() {
    const tier = APP.settings.subscription?.tier || 'free';
    const tierData = PRICING_TIERS[tier];
    if (tierData && tierData.storageBytes) return tierData.storageBytes;
    // Default: 5GB for free users
    return 5 * 1024 * 1024 * 1024;
}

function checkStorageQuota(fileSize) {
    const files = APP.files.filter(f => !f.trashed);
    const used = files.reduce((sum, f) => sum + (f.size || 0), 0);
    const limit = getSubscriptionLimit();
    const percentage = limit > 0 ? (used / limit) * 100 : 0;
    const allowed = (used + fileSize) <= limit;
    return { allowed, used, limit, percentage: Math.min(percentage, 100) };
}

function showQuotaExceededModal(quotaInfo) {
    const isId = APP.lang === 'id';
    const tier = APP.settings.subscription?.tier || 'free';
    const pct = quotaInfo.percentage.toFixed(1);
    openModal(`<div style="padding:24px;text-align:center">
        <div class="quota-modal-icon over"><i class="fas fa-hard-drive" style="color:#ef4444;font-size:28px"></i></div>
        <h3 style="font-size:20px;font-weight:700;margin-bottom:8px;color:#ef4444">${isId ? 'Penyimpanan Penuh' : 'Storage Limit Reached'}</h3>
        <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">${isId ? `Anda telah menggunakan ${pct}% dari penyimpanan ${PRICING_TIERS[tier]?.storage || '5 GB'} Anda.` : `You've used ${pct}% of your ${PRICING_TIERS[tier]?.storage || '5 GB'} storage.`}</p>
        <div style="background:var(--bg-secondary);border-radius:10px;padding:12px;margin-bottom:16px">
            <div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:6px">
                <span>${formatSize(quotaInfo.used)} ${isId ? 'terpakai' : 'used'}</span>
                <span>${formatSize(quotaInfo.limit)} ${isId ? 'total' : 'total'}</span>
            </div>
            <div class="quota-bar-track"><div class="quota-bar-fill red" style="width:${Math.min(pct, 100)}%"></div></div>
        </div>
        <div style="display:flex;flex-direction:column;gap:8px">
            <button class="btn btn-primary" style="width:100%;padding:12px;font-size:14px;font-weight:600" onclick="closeModal();openPricingModal('pro')"><i class="fas fa-arrow-up" style="margin-right:6px"></i>${isId ? 'Upgrade ke Pro' : 'Upgrade to Pro'}</button>
            <button class="btn btn-secondary" style="width:100%;padding:10px;font-size:13px" onclick="closeModal();location.hash='#/storage'"><i class="fas fa-chart-pie" style="margin-right:6px"></i>${isId ? 'Bebaskan Ruang' : 'Free Up Space'}</button>
            <button class="btn btn-ghost" style="width:100%" onclick="closeModal()">${isId ? 'Tutup' : 'Close'}</button>
        </div>
    </div>`);
}

function getQuotaBarHtml() {
    const isId = APP.lang === 'id';
    const tier = APP.settings.subscription?.tier || 'free';
    const files = APP.files.filter(f => !f.trashed);
    const used = files.reduce((sum, f) => sum + (f.size || 0), 0);
    const limit = getSubscriptionLimit();
    const pct = limit > 0 ? Math.min((used / limit) * 100, 100) : 0;
    const barColor = pct > 90 ? 'red' : pct > 70 ? 'yellow' : 'green';
    return `<div class="quota-bar-wrap" onclick="location.hash='#/storage'" title="${isId ? 'Klik untuk analisis penyimpanan' : 'Click for storage analytics'}">
        <div class="quota-bar-label">
            <span><i class="fas fa-hard-drive" style="margin-right:4px"></i>${isId ? 'Kuota' : 'Quota'}</span>
            <span class="quota-tier">${PRICING_TIERS[tier]?.storage || '5 GB'}</span>
        </div>
        <div class="quota-bar-track"><div class="quota-bar-fill ${barColor}" style="width:${pct}%"></div></div>
        <div class="quota-bar-stats">
            <span>${formatSize(used)} / ${formatSize(limit)}</span>
            <span style="font-weight:600;color:${pct > 90 ? '#ef4444' : pct > 70 ? '#f59e0b' : 'var(--text-secondary)'}">${pct.toFixed(1)}%</span>
        </div>
    </div>`;
}

function getStorageWarningBanner() {
    const isId = APP.lang === 'id';
    const files = APP.files.filter(f => !f.trashed);
    const used = files.reduce((sum, f) => sum + (f.size || 0), 0);
    const limit = getSubscriptionLimit();
    const pct = limit > 0 ? (used / limit) * 100 : 0;

    if (pct >= 100) {
        return `<div class="storage-warning-banner warning-red">
            <i class="fas fa-exclamation-circle"></i>
            <span>${isId ? 'Penyimpanan penuh! Unggahan diblokir.' : 'Storage full! Uploads blocked.'}</span>
            <button class="btn btn-sm" style="background:rgba(239,68,68,.15);color:#ef4444;border:none;margin-left:8px;font-size:11px;font-weight:600" onclick="openPricingModal('pro')">${isId ? 'Upgrade' : 'Upgrade'}</button>
            <button class="storage-warning-dismiss" onclick="dismissStorageWarning()" aria-label="Dismiss"><i class="fas fa-times"></i></button>
        </div>`;
    } else if (pct >= 95) {
        return `<div class="storage-warning-banner warning-red">
            <i class="fas fa-exclamation-triangle"></i>
            <span>${isId ? 'Hampir kehabisan penyimpanan! Upgrade sekarang.' : 'Almost out of storage! Upgrade now.'}</span>
            <button class="btn btn-sm" style="background:rgba(239,68,68,.15);color:#ef4444;border:none;margin-left:8px;font-size:11px;font-weight:600" onclick="openPricingModal('pro')">${isId ? 'Upgrade' : 'Upgrade'}</button>
            <button class="storage-warning-dismiss" onclick="dismissStorageWarning()" aria-label="Dismiss"><i class="fas fa-times"></i></button>
        </div>`;
    } else if (pct >= 80) {
        return `<div class="storage-warning-banner warning-yellow">
            <i class="fas fa-info-circle"></i>
            <span>${isId ? `Anda telah menggunakan ${pct.toFixed(0)}% penyimpanan Anda` : `You've used ${pct.toFixed(0)}% of your storage`}</span>
            <button class="storage-warning-dismiss" onclick="dismissStorageWarning()" aria-label="Dismiss"><i class="fas fa-times"></i></button>
        </div>`;
    }
    return '';
}

// ===== WEBHOOK INTEGRATION =====
const _webhookRateLimit = {};
function triggerWebhook(event, data) {
    if (!APP.settings.webhookUrl) return;
    const now = Date.now();
    const key = event;
    if (_webhookRateLimit[key] && (now - _webhookRateLimit[key]) < 5000) return;
    _webhookRateLimit[key] = now;
    const payload = { event, timestamp: new Date().toISOString(), data };
    fetch(APP.settings.webhookUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
    }).then(() => showToast(APP.lang==='id'?'Webhook terkirim':'Webhook sent', 'success'))
      .catch(() => showToast(APP.lang==='id'?'Webhook gagal':'Webhook failed', 'error'));
}
async function testWebhook() {
    const url = document.getElementById('admin-webhook-url')?.value || document.getElementById('setting-webhook-url')?.value;
    if (!url) { showToast(APP.lang==='id'?'Masukkan URL webhook':'Enter webhook URL', 'warning'); return; }
    await updateSetting('webhookUrl', url);
    triggerWebhook('test', { message: 'Test webhook from Ridgebox' });
}
async function checkStorageWarning() {
    try {
        const q = await getStorageQuota();
        const pct = q.totalUsed / q.totalQuota;
        if (pct > 0.75) triggerWebhook('storage.warning', { usedBytes: q.totalUsed, totalBytes: q.totalQuota, percentage: Math.round(pct*100) });
    } catch(e) {}
}

