// ===== BOTTOM NAVIGATION BAR (F22) =====
function renderBottomNav() {
    if (APP.viewMode !== 'mobile') {
        const existing = document.getElementById('bottom-nav');
        if (existing) existing.remove();
        return;
    }
    const isId = APP.lang === 'id';
    const recentCount = APP.files.filter(x => !x.trashed && x.lastAccessed).length;
    const sharedCount = APP.shares.length;
    const tabs = [
        { id: 'files', icon: 'fa-folder', label: isId ? 'File' : 'Files', badge: 0 },
        { id: 'recent', icon: 'fa-clock', label: isId ? 'Terkini' : 'Recent', badge: recentCount },
        { id: 'shared', icon: 'fa-share-alt', label: isId ? 'Dibagikan' : 'Shared', badge: sharedCount },
        { id: 'settings', icon: 'fa-cog', label: isId ? 'Pengaturan' : 'Settings', badge: 0 }
    ];

    let navEl = document.getElementById('bottom-nav');
    if (!navEl) {
        navEl = document.createElement('div');
        navEl.id = 'bottom-nav';
        navEl.className = 'bottom-nav';
        document.body.appendChild(navEl);
    }
    navEl.innerHTML = `
        ${tabs.map(tab => {
            const isActive = APP.bottomNavTab === tab.id;
            return `<div class="bottom-nav-tab ${isActive ? 'active' : ''}" onclick="switchBottomTab('${tab.id}')">
                <i class="fas ${tab.icon}"></i>
                <span>${tab.label}</span>
                ${tab.badge > 0 ? `<span class="bottom-nav-badge">${tab.badge > 99 ? '99+' : tab.badge}</span>` : ''}
            </div>`;
        }).join('')}
        <button class="bottom-nav-fab" onclick="triggerUpload()" title="${isId ? 'Unggah File' : 'Upload Files'}">
            <i class="fas fa-plus"></i>
        </button>
    `;
}

function switchBottomTab(tabId) {
    haptic('tap');
    APP.bottomNavTab = tabId;
    renderBottomNav();

    const container = document.getElementById('file-list-container');
    const widgetSection = document.getElementById('dashboard-widgets');
    const isId = APP.lang === 'id';

    if (tabId === 'files') {
        // Show normal file dashboard
        APP.currentFolder = 'all';
        if (widgetSection) widgetSection.style.display = '';
        renderBreadcrumb();
        renderQuickFilter();
        renderTagFilterBar();
        renderFileList();
    } else if (tabId === 'recent') {
        APP.currentFolder = 'recent';
        if (widgetSection) widgetSection.style.display = 'none';
        renderBreadcrumb();
        renderQuickFilter();
        renderTagFilterBar();
        renderFileList();
    } else if (tabId === 'shared') {
        APP.currentFolder = 'shared';
        if (widgetSection) widgetSection.style.display = 'none';
        renderBreadcrumb();
        renderQuickFilter();
        renderTagFilterBar();
        renderFileList();
    } else if (tabId === 'settings') {
        if (widgetSection) widgetSection.style.display = 'none';
        openSettings();
    }

    // Animate content transition
    if (container) {
        container.style.opacity = '0';
        container.style.transform = 'translateY(8px)';
        setTimeout(() => {
            container.style.transition = 'opacity .25s ease, transform .25s ease';
            container.style.opacity = '1';
            container.style.transform = 'translateY(0)';
        }, 50);
    }

    // Update sidebar active state
    const sidebar = document.getElementById('sidebar-panel');
    if (sidebar) sidebar.innerHTML = renderSidebarHTML();
}

// ===== INTEGRATE HAPTIC INTO EXISTING INTERACTIONS (F23) =====
// Patch copyToClipboard with haptic
const _origCopyToClipboard = copyToClipboard;
copyToClipboard = function(text) {
    haptic('copy');
    navigator.clipboard.writeText(text).then(() => {
        showToast(APP.lang === 'id' ? 'Disalin ke clipboard' : 'Copied to clipboard', 'success');
    }).catch(() => {
        const ta = document.createElement('textarea');
        ta.value = text;
        document.body.appendChild(ta);
        ta.select();
        document.execCommand('copy');
        ta.remove();
        showToast(APP.lang === 'id' ? 'Disalin ke clipboard' : 'Copied to clipboard', 'success');
    });
};

// Patch quickDeleteFile to add haptic
const _origQuickDeleteFile = quickDeleteFile;
quickDeleteFile = async function(fileId) {
    haptic('delete');
    const file = APP.files.find(f => f.id === fileId);
    if (!file) { console.warn('quickDelete: file not found', fileId); return; }
    removeFileElement(fileId);
    file.trashed = true;
    file.trashedAt = Date.now();
    try {
        await saveFile(file);
        console.log('quickDelete: saved', fileId, 'trashed=', file.trashed);
    } catch(e) { console.error('quickDelete save error:', e); }
    APP.files = APP.files.filter(f => f.id !== fileId);
    APP.selectedFiles.delete(fileId);
    closeDetailPanel();
    closeContextMenu();
    showUndoToast(t('movedToTrash'), async () => { await restoreFile(fileId); });
    await refreshUI();
};

// Patch updateSetting for haptic toggle
const _origUpdateSetting = updateSetting;
updateSetting = async function(key, value) {
    APP.settings[key] = value;
    if (key === 'hapticFeedback') {
        localStorage.setItem('rb_haptic', value ? '1' : '0');
        haptic('toggle');
    } else {
        haptic('toggle');
        await saveSetting(key, value);
    }
};

