// F24: AI Search - Toggle between regular and AI search
function toggleAISearchMode() {
    APP.aiSearchMode = !APP.aiSearchMode;
    const searchWrap = document.querySelector('.search-premium');
    if (searchWrap) {
        searchWrap.classList.toggle('ai-search-active', APP.aiSearchMode);
        const icon = searchWrap.querySelector('i:first-child');
        if (icon) icon.className = `fas ${APP.aiSearchMode ? 'fa-wand-magic-sparkles' : 'fa-search'}`;
        const input = searchWrap.querySelector('input');
        if (input) {
            input.placeholder = APP.aiSearchMode ? (APP.lang === 'id' ? 'Cari dengan AI...' : 'AI Search...') : t('search');
            if (APP.aiSearchMode) input.focus();
        }
        const toggleBtn = searchWrap.querySelector('.ai-search-toggle');
        if (toggleBtn) toggleBtn.classList.toggle('active', APP.aiSearchMode);
    }
    haptic('tap');
}

// F24: AI Search - Execute AI search query
async function executeAISearch(query) {
    if (!query || !query.trim()) return;
    const isId = APP.lang === 'id';
    const searchWrap = document.querySelector('.search-premium');

    // Show loading shimmer in file list
    const container = document.getElementById('file-list-container');
    if (container) {
        container.innerHTML = `
            <div style="padding:20px">
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:16px">
                    <span class="ai-search-badge"><i class="fas fa-wand-magic-sparkles"></i> AI Search</span>
                    <span style="font-size:13px;color:var(--text-secondary)">${isId ? 'Mencari...' : 'Searching...'}</span>
                </div>
                ${[1,2,3].map(() => '<div class="ai-search-shimmer" style="margin-bottom:8px"></div>').join('')}
            </div>`;
    }

    try {
        // Build file metadata for AI
        const filesMetadata = APP.files.filter(f => !f.trashed).map(f => ({
            id: f.id,
            name: f.name,
            size: f.size,
            type: getFileType(f.name, f.mime),
            folder: APP.folders.find(fo => fo.id === f.folderId)?.name || 'Root',
            uploadedAt: f.uploadedAt ? new Date(f.uploadedAt).toISOString() : '',
            tags: f.aiTags || [],
            category: f.aiCategory || ''
        }));

        const resp = await fetch('/api/ai/search', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ query: query.trim(), files: filesMetadata })
        });
        const data = await resp.json();

        if (data.ok) {
            const matchedFiles = (data.fileIds || []).map(id => APP.files.find(f => f.id === id)).filter(Boolean).filter(f => !f.trashed);
            const explanation = data.explanation || '';

            if (container) {
                if (matchedFiles.length === 0) {
                    container.innerHTML = `
                        <div style="padding:40px 20px;text-align:center">
                            <div class="ai-search-badge" style="margin-bottom:12px;font-size:11px;padding:4px 12px"><i class="fas fa-wand-magic-sparkles"></i> AI Search</div>
                            <div style="font-size:40px;margin-bottom:12px;opacity:.3"><i class="fas fa-search"></i></div>
                            <p style="font-size:14px;font-weight:500;margin-bottom:4px">${isId ? 'Tidak ditemukan' : 'No results found'}</p>
                            <p style="font-size:12px;color:var(--text-secondary)">"${query}"</p>
                        </div>`;
                } else {
                    let html = `
                        <div style="padding:12px 20px 4px">
                            <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
                                <span class="ai-search-badge"><i class="fas fa-wand-magic-sparkles"></i> AI Search</span>
                                <span style="font-size:12px;color:var(--text-secondary)">${matchedFiles.length} ${isId ? 'hasil' : 'results'}</span>
                            </div>
                            ${explanation ? `<div class="ai-search-explanation"><i class="fas fa-lightbulb"></i>${explanation}</div>` : ''}
                        </div>`;
                    // Render matched files using the normal file list rendering
                    matchedFiles.forEach((f, i) => {
                        const type = getFileType(f.name, f.mime);
                        const icon = getFileIcon(type);
                        html += `<div class="ai-search-result-item" onclick="openDetailPanel('${f.id}')" style="animation-delay:${i * 0.03}s">
                            <i class="fas ${icon.icon}" style="color:${icon.color};width:20px;text-align:center"></i>
                            <div style="flex:1;min-width:0">
                                <div style="font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${f.name}</div>
                                <div style="font-size:11px;color:var(--text-secondary)">${formatSize(f.size)} · ${formatDate(f.uploadedAt)}${f.aiCategory ? ' · <span style="color:#10b981">' + f.aiCategory + '</span>' : ''}</div>
                            </div>
                        </div>`;
                    });
                    container.innerHTML = html;
                }
            }
        } else {
            showToast(isId ? 'Pencarian AI gagal' : 'AI search failed', 'error');
        }
    } catch (e) {
        console.error('AI Search error:', e);
        showToast(isId ? 'Pencarian AI gagal' : 'AI search failed', 'error');
        renderFileList(); // Revert to normal list
    }
}

// F25: Auto-Categorize - Categorize a single file using AI
async function aiCategorizeFile(fileMeta) {
    if (!fileMeta || fileMeta.aiCategory) return; // Skip if already categorized
    try {
        const resp = await fetch('/api/ai/categorize', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ fileName: fileMeta.name, fileType: fileMeta.mime, fileSize: fileMeta.size })
        });
        const data = await resp.json();
        if (data.ok) {
            const file = APP.files.find(f => f.id === fileMeta.id);
            if (file) {
                file.aiCategory = data.category;
                file.aiTags = data.tags;
                file.aiFolder = data.suggestedFolder;
                await saveFile(file);
                const isId = APP.lang === 'id';
                // Show subtle toast
                showToast(`🤖 AI: ${data.category} → ${data.suggestedFolder}`, 'info', 3000);
                renderQuickFilter();
            }
        }
    } catch (e) {
        console.warn('AI categorize failed:', e);
    }
}

// F25: Categorize all uncategorized files
async function aiCategorizeAllFiles() {
    const isId = APP.lang === 'id';
    const uncategorized = APP.files.filter(f => !f.trashed && !f.aiCategory);
    if (uncategorized.length === 0) {
        showToast(isId ? 'Semua file sudah dikategorikan' : 'All files already categorized', 'info');
        return;
    }
    showToast(isId ? `Mengkategorikan ${uncategorized.length} file...` : `Categorizing ${uncategorized.length} files...`, 'info');
    let count = 0;
    for (const file of uncategorized) {
        try {
            const resp = await fetch('/api/ai/categorize', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ fileName: file.name, fileType: file.mime, fileSize: file.size })
            });
            const data = await resp.json();
            if (data.ok) {
                file.aiCategory = data.category;
                file.aiTags = data.tags;
                file.aiFolder = data.suggestedFolder;
                await saveFile(file);
                count++;
            }
            // Small delay to avoid rate limiting
            await new Promise(r => setTimeout(r, 300));
        } catch (e) { console.warn('Categorize error:', e); }
    }
    showToast(isId ? `${count} file berhasil dikategorikan` : `${count} files categorized`, 'success');
    renderQuickFilter();
    renderFileList();
}

// F25: Set AI category filter
function setAICategoryFilter(cat) {
    APP.aiCategoryFilter = APP.aiCategoryFilter === cat ? null : cat;
    renderQuickFilter();
    renderFileList();
}

// F26: Smart Duplicate Detection
function findDuplicateFiles() {
    const isId = APP.lang === 'id';
    const activeFiles = APP.files.filter(f => !f.trashed);

    // 1. Exact duplicates (same fileHash)
    const hashGroups = {};
    activeFiles.forEach(f => {
        if (f.fileHash) {
            if (!hashGroups[f.fileHash]) hashGroups[f.fileHash] = [];
            hashGroups[f.fileHash].push(f);
        }
    });
    const exactGroups = Object.values(hashGroups).filter(g => g.length > 1);

    // 2. Similar files (similar name + same size + same type)
    function levenshtein(a, b) {
        const m = a.length, n = b.length;
        const dp = Array.from({ length: m + 1 }, () => Array(n + 1).fill(0));
        for (let i = 0; i <= m; i++) dp[i][0] = i;
        for (let j = 0; j <= n; j++) dp[0][j] = j;
        for (let i = 1; i <= m; i++) {
            for (let j = 1; j <= n; j++) {
                dp[i][j] = a[i - 1] === b[j - 1]
                    ? dp[i - 1][j - 1]
                    : 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
            }
        }
        return dp[m][n];
    }

    const similarGroups = [];
    const checked = new Set();
    for (let i = 0; i < activeFiles.length; i++) {
        if (checked.has(i)) continue;
        const group = [activeFiles[i]];
        for (let j = i + 1; j < activeFiles.length; j++) {
            if (checked.has(j)) continue;
            const fi = activeFiles[i], fj = activeFiles[j];
            const sameSize = fi.size === fj.size;
            const sameType = getFileType(fi.name, fi.mime) === getFileType(fj.name, fj.mime);
            if (sameSize && sameType && fi.name && fj.name) {
                const dist = levenshtein(fi.name.toLowerCase(), fj.name.toLowerCase());
                if (dist < 3 && dist > 0) {
                    group.push(fj);
                    checked.add(j);
                }
            }
        }
        if (group.length > 1) {
            similarGroups.push(group);
            checked.add(i);
        }
    }

    openDuplicateModal(exactGroups, similarGroups);
}

// F26: Open Duplicate Results Modal
function openDuplicateModal(exactGroups, similarGroups) {
    const isId = APP.lang === 'id';
    const totalGroups = exactGroups.length + similarGroups.length;
    const totalSavings = [...exactGroups, ...similarGroups].reduce((sum, group) => {
        return sum + (group.length - 1) * group[0].size;
    }, 0);

    if (totalGroups === 0) {
        openModal(`<div style="padding:24px;text-align:center">
            <div style="font-size:48px;margin-bottom:12px;opacity:.2"><i class="fas fa-clone"></i></div>
            <h3 style="font-size:16px;font-weight:600;margin-bottom:8px">${isId ? 'Tidak Ada Duplikat' : 'No Duplicates Found'}</h3>
            <p style="font-size:13px;color:var(--text-secondary)">${isId ? 'Semua file unik!' : 'All files are unique!'}</p>
            <button class="btn btn-primary" style="margin-top:16px" onclick="closeModal()">OK</button>
        </div>`);
        return;
    }

    function renderGroup(group, groupIdx, isExact) {
        const icon = getFileIcon(getFileType(group[0].name, group[0].mime));
        const savings = (group.length - 1) * group[0].size;
        return `<div class="dup-group" id="dup-group-${groupIdx}">
            <div class="dup-group-header">
                <div style="display:flex;align-items:center;gap:6px">
                    <i class="fas ${icon.icon}" style="color:${icon.color}"></i>
                    <span style="overflow:hidden;text-overflow:ellipsis;white-space:nowrap;max-width:200px">${group[0].name}</span>
                    <span class="dup-savings-badge"><i class="fas fa-arrow-down" style="font-size:9px"></i> ${formatSize(savings)}</span>
                </div>
                <div style="display:flex;gap:4px">
                    <button class="dup-action-btn" onclick="keepDuplicateNewest('${group.map(f=>f.id).join(',')}','${groupIdx}')">${isId ? 'Terbaru' : 'Keep Newest'}</button>
                    <button class="dup-action-btn" onclick="keepDuplicateOldest('${group.map(f=>f.id).join(',')}','${groupIdx}')">${isId ? 'Terlama' : 'Keep Oldest'}</button>
                </div>
            </div>
            ${group.map((f, i) => `<div class="dup-file-row">
                <input type="checkbox" class="dup-check-${groupIdx}" aria-label="Select duplicate file" data-file-id="${f.id}" ${i === 0 ? 'checked' : ''} style="accent-color:var(--accent)">
                <i class="fas ${icon.icon}" style="color:${icon.color};font-size:11px"></i>
                <span style="flex:1;font-size:12px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${f.name}</span>
                <span style="font-size:11px;color:var(--text-secondary)">${formatSize(f.size)}</span>
                <span style="font-size:11px;color:var(--text-secondary)">${formatDate(f.uploadedAt)}</span>
            </div>`).join('')}
            <div style="margin-top:8px;display:flex;gap:6px;justify-content:flex-end">
                <button class="dup-action-btn danger" onclick="deleteSelectedDuplicates('${groupIdx}')">${isId ? 'Hapus Terpilih' : 'Delete Selected'}</button>
            </div>
        </div>`;
    }

    openModal(`<div style="padding:24px;max-width:560px">
        <h3 style="font-size:18px;font-weight:600;margin-bottom:4px"><i class="fas fa-clone" style="color:var(--accent)"></i> ${isId ? 'Deteksi Duplikat' : 'Duplicate Detection'}</h3>
        <p style="font-size:13px;color:var(--text-secondary);margin-bottom:16px">
            <span class="dup-savings-badge">${totalGroups} ${isId ? 'grup duplikat' : 'duplicate groups'} (${isId ? 'hemat' : 'save'} ${formatSize(totalSavings)})</span>
        </p>

        <!-- Tabs -->
        <div style="display:flex;gap:8px;margin-bottom:16px">
            <button class="dup-tab active" id="dup-tab-exact" onclick="switchDupTab('exact')">${isId ? 'Duplikat Eksak' : 'Exact Duplicates'} (${exactGroups.length})</button>
            <button class="dup-tab" id="dup-tab-similar" onclick="switchDupTab('similar')">${isId ? 'File Serupa' : 'Similar Files'} (${similarGroups.length})</button>
        </div>

        <!-- Exact duplicates -->
        <div id="dup-content-exact" style="max-height:400px;overflow-y:auto">
            ${exactGroups.length === 0 ? `<p style="text-align:center;color:var(--text-secondary);padding:20px">${isId ? 'Tidak ada duplikat eksak' : 'No exact duplicates found'}</p>` : exactGroups.map((g, i) => renderGroup(g, 'e' + i, true)).join('')}
        </div>

        <!-- Similar files -->
        <div id="dup-content-similar" style="display:none;max-height:400px;overflow-y:auto">
            ${similarGroups.length === 0 ? `<p style="text-align:center;color:var(--text-secondary);padding:20px">${isId ? 'Tidak ada file serupa' : 'No similar files found'}</p>` : similarGroups.map((g, i) => renderGroup(g, 's' + i, false)).join('')}
        </div>

        <div style="display:flex;justify-content:flex-end;margin-top:16px">
            <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
        </div>
    </div>`);
}

// F26: Switch duplicate tab
function switchDupTab(tab) {
    document.getElementById('dup-tab-exact')?.classList.toggle('active', tab === 'exact');
    document.getElementById('dup-tab-similar')?.classList.toggle('active', tab === 'similar');
    const exactContent = document.getElementById('dup-content-exact');
    const similarContent = document.getElementById('dup-content-similar');
    if (exactContent) exactContent.style.display = tab === 'exact' ? 'block' : 'none';
    if (similarContent) similarContent.style.display = tab === 'similar' ? 'block' : 'none';
}

// F26: Keep newest duplicate, delete rest
async function keepDuplicateNewest(fileIdsStr, groupIdx) {
    const ids = fileIdsStr.split(',');
    const sorted = ids.map(id => APP.files.find(f => f.id === id)).filter(Boolean).sort((a, b) => (b.uploadedAt || 0) - (a.uploadedAt || 0));
    // Keep the newest (first), delete the rest
    for (let i = 1; i < sorted.length; i++) {
        await moveToTrash(sorted[i].id);
    }
    const group = document.getElementById('dup-group-' + groupIdx);
    if (group) group.style.opacity = '0.3';
    showToast(APP.lang === 'id' ? 'Duplikat dihapus, terbaru disimpan' : 'Duplicates removed, newest kept', 'success');
}

// F26: Keep oldest duplicate, delete rest
async function keepDuplicateOldest(fileIdsStr, groupIdx) {
    const ids = fileIdsStr.split(',');
    const sorted = ids.map(id => APP.files.find(f => f.id === id)).filter(Boolean).sort((a, b) => (a.uploadedAt || 0) - (b.uploadedAt || 0));
    for (let i = 1; i < sorted.length; i++) {
        await moveToTrash(sorted[i].id);
    }
    const group = document.getElementById('dup-group-' + groupIdx);
    if (group) group.style.opacity = '0.3';
    showToast(APP.lang === 'id' ? 'Duplikat dihapus, terlama disimpan' : 'Duplicates removed, oldest kept', 'success');
}

// F26: Delete selected duplicates in a group
async function deleteSelectedDuplicates(groupIdx) {
    const checks = document.querySelectorAll('.dup-check-' + groupIdx);
    const toDelete = [];
    checks.forEach(ch => {
        if (!ch.checked) toDelete.push(ch.dataset.fileId);
    });
    if (toDelete.length === 0) {
        showToast(APP.lang === 'id' ? 'Pilih file yang akan dihapus' : 'Select files to delete', 'warning');
        return;
    }
    for (const id of toDelete) {
        await moveToTrash(id);
    }
    const group = document.getElementById('dup-group-' + groupIdx);
    if (group) group.style.opacity = '0.3';
    showToast(`${toDelete.length} ${APP.lang === 'id' ? 'file dipindahkan ke sampah' : 'files moved to trash'}`, 'success');
}

// F27: OCR - Extract text from image/PDF
async function executeOCR(fileId) {
    const isId = APP.lang === 'id';
    const file = APP.files.find(f => f.id === fileId);
    if (!file) return;

    // Check if already extracted
    if (file.ocrText !== undefined) {
        openOCRModal(file.ocrText, file.ocrConfidence || 'medium', fileId);
        return;
    }

    // Show loading state
    const panel = document.getElementById('detail-panel');
    if (panel) {
        const existingBtn = panel.querySelector('[onclick*="executeOCR"]');
        if (existingBtn) {
            existingBtn.outerHTML = `<div style="display:flex;align-items:center;gap:6px;padding:6px 12px;border-radius:8px;border:1px solid var(--border);background:var(--bg-secondary);color:var(--text-secondary);font-size:12px;margin-bottom:10px"><i class="fas fa-spinner fa-spin"></i> ${isId ? 'Mengekstrak teks...' : 'Extracting text...'}</div>`;
        }
    }

    try {
        const downloadUrl = `/api/download?path=${encodeURIComponent(file.filePath)}&bot_index=${file.botIndex}`;
        const resp = await fetch('/api/ai/ocr', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ fileUrl: downloadUrl })
        });
        const data = await resp.json();

        if (data.ok) {
            file.ocrText = data.text || '';
            file.ocrConfidence = data.confidence || 'medium';
            await saveFile(file);

            if (data.text) {
                openOCRModal(data.text, data.confidence, fileId);
                showToast(isId ? 'Teks berhasil diekstrak!' : 'Text extracted successfully!', 'success');
            } else {
                openOCRModal('', data.confidence, fileId);
                showToast(isId ? 'Tidak ada teks ditemukan' : 'No text found', 'info');
            }
        } else {
            showToast(isId ? 'OCR gagal: ' + (data.error || '') : 'OCR failed: ' + (data.error || ''), 'error');
        }
    } catch (e) {
        console.error('OCR error:', e);
        showToast(isId ? 'OCR gagal' : 'OCR failed', 'error');
    }
}

// F27: Open OCR Results Modal
function openOCRModal(text, confidence, fileId) {
    const isId = APP.lang === 'id';
    const hasText = text && text.trim().length > 0;
    const confLabel = confidence === 'high' ? (isId ? 'Tinggi' : 'High') : confidence === 'medium' ? (isId ? 'Sedang' : 'Medium') : confidence === 'low' ? (isId ? 'Rendah' : 'Low') : (isId ? 'Tidak ada' : 'None');

    openModal(`<div style="padding:24px;max-width:560px">
        <h3 style="font-size:18px;font-weight:600;margin-bottom:4px;display:flex;align-items:center;gap:8px">
            <i class="fas fa-file-lines" style="color:var(--accent)"></i>
            ${isId ? 'Teks Diekstrak' : 'Extracted Text'}
            ${hasText ? `<span class="ocr-status-badge extracted"><i class="fas fa-check"></i>${isId ? 'Diekstrak' : 'Extracted'}</span>` : `<span class="ocr-status-badge none"><i class="fas fa-times"></i>${isId ? 'Tanpa Teks' : 'No Text'}</span>`}
        </h3>
        ${hasText ? `<p class="ocr-confidence">${isId ? 'Kepercayaan' : 'Confidence'}: ${confLabel}</p>` : ''}

        ${hasText ? `
        <!-- Search within extracted text -->
        <div class="ocr-search-bar">
            <i class="fas fa-search"></i>
            <input type="text" placeholder="${isId ? 'Cari dalam teks...' : 'Search within text...'}" oninput="searchOCRText(this.value)">
        </div>

        <!-- Text display area -->
        <div class="ocr-text-area" id="ocr-text-display">${text}</div>

        <!-- Actions -->
        <div style="display:flex;gap:8px;margin-top:12px">
            <button class="btn btn-primary btn-sm" onclick="copyOCRText()"><i class="fas fa-copy"></i> ${isId ? 'Salin Teks' : 'Copy Text'}</button>
            <button class="btn btn-secondary btn-sm" onclick="downloadOCRText('${fileId}')"><i class="fas fa-download"></i> ${isId ? 'Unduh .txt' : 'Download .txt'}</button>
        </div>
        ` : `
        <div style="text-align:center;padding:30px 0;color:var(--text-secondary)">
            <div style="font-size:40px;opacity:.2;margin-bottom:8px"><i class="fas fa-file-lines"></i></div>
            <p>${isId ? 'Tidak ada teks yang dapat diekstrak dari file ini' : 'No text could be extracted from this file'}</p>
        </div>
        `}

        <div style="display:flex;justify-content:flex-end;margin-top:16px">
            <button class="btn btn-secondary" onclick="closeModal()">${t('close')}</button>
        </div>
    </div>`);
}

// F27: Search within OCR text
function searchOCRText(query) {
    const display = document.getElementById('ocr-text-display');
    if (!display) return;
    const file = APP.files.find(f => f.ocrText !== undefined && display.dataset.fileId !== undefined);
    const originalText = display.textContent || display.innerText || '';
    if (!query || !query.trim()) {
        display.innerHTML = originalText;
        return;
    }
    const q = query.toLowerCase();
    const idx = originalText.toLowerCase().indexOf(q);
    if (idx >= 0) {
        const before = originalText.substring(0, idx);
        const match = originalText.substring(idx, idx + query.length);
        const after = originalText.substring(idx + query.length);
        display.innerHTML = before + '<mark style="background:rgba(139,92,246,.25);color:inherit;border-radius:2px;padding:0 1px">' + match + '</mark>' + after;
    }
}

// F27: Copy OCR text to clipboard
function copyOCRText() {
    const display = document.getElementById('ocr-text-display');
    if (!display) return;
    const text = display.textContent || display.innerText;
    navigator.clipboard.writeText(text).then(() => {
        showToast(APP.lang === 'id' ? 'Teks disalin!' : 'Text copied!', 'success');
    }).catch(() => {
        showToast(APP.lang === 'id' ? 'Gagal menyalin' : 'Copy failed', 'error');
    });
}

// F27: Download OCR text as .txt
function downloadOCRText(fileId) {
    const file = APP.files.find(f => f.id === fileId);
    if (!file || !file.ocrText) return;
    const blob = new Blob([file.ocrText], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = (file.name.replace(/\.[^.]+$/, '') || 'extracted') + '_text.txt';
    a.click();
    URL.revokeObjectURL(url);
}

